window.OBJECTIVES = [{"id":"1.1","domain":"1.0 General Security Concepts","label":"Security Controls"},{"id":"1.2","domain":"1.0 General Security Concepts","label":"Fundamental Security Concepts (CIA, AAA, Zero Trust)"},{"id":"1.3","domain":"1.0 General Security Concepts","label":"Change Management"},{"id":"1.4","domain":"1.0 General Security Concepts","label":"Cryptographic Solutions"},{"id":"2.1","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Threat Actors & Motivations"},{"id":"2.2","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Threat Vectors & Attack Surfaces"},{"id":"2.3","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Vulnerability Types"},{"id":"2.4","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Indicators of Malicious Activity"},{"id":"2.5","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Mitigation Techniques"},{"id":"3.1","domain":"3.0 Security Architecture","label":"Architecture Models"},{"id":"3.2","domain":"3.0 Security Architecture","label":"Enterprise Infrastructure Security"},{"id":"3.3","domain":"3.0 Security Architecture","label":"Data Protection Concepts"},{"id":"3.4","domain":"3.0 Security Architecture","label":"Resilience & Recovery"},{"id":"4.1","domain":"4.0 Security Operations","label":"Securing Computing Resources & Hardening"},{"id":"4.2","domain":"4.0 Security Operations","label":"Asset Management"},{"id":"4.3","domain":"4.0 Security Operations","label":"Vulnerability Management"},{"id":"4.4","domain":"4.0 Security Operations","label":"Security Monitoring & Alerting"},{"id":"4.5","domain":"4.0 Security Operations","label":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)"},{"id":"4.6","domain":"4.0 Security Operations","label":"Identity & Access Management (IAM)"},{"id":"4.7","domain":"4.0 Security Operations","label":"Automation & Orchestration"},{"id":"4.8","domain":"4.0 Security Operations","label":"Incident Response"},{"id":"4.9","domain":"4.0 Security Operations","label":"Digital Forensics & Investigation Data Sources"},{"id":"5.1","domain":"5.0 Security Program Management & Oversight","label":"Security Governance"},{"id":"5.2","domain":"5.0 Security Program Management & Oversight","label":"Risk Management"},{"id":"5.3","domain":"5.0 Security Program Management & Oversight","label":"Third-Party Risk Management"},{"id":"5.4","domain":"5.0 Security Program Management & Oversight","label":"Security Compliance"},{"id":"5.5","domain":"5.0 Security Program Management & Oversight","label":"Audits & Assessments"},{"id":"5.6","domain":"5.0 Security Program Management & Oversight","label":"Security Awareness Training"}];
window.QUESTION_BANK = [{"id":1,"question":"A hospital IT department is implementing a security control that automatically blocks USB storage devices from connecting to workstations to prevent malware infections and data theft.","options":["Detective control","Corrective control","Preventive control","Compensating control"],"correctIndex":2,"explanation":"1. The core action is blocking the connection before it occurs. 2. Because it stops the threat from ever entering the system, it is categorized as preventive. 3. Detective or corrective controls would only address the issue after the USB was already connected.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":2,"question":"A financial company hires a third-party auditor to review firewall logs and identify suspicious activity after a security incident.","options":["Detective control","Preventive control","Directive control","Deterrent control"],"correctIndex":0,"explanation":"1. The auditor is reviewing logs of events that have already taken place[cite: 9]. 2. Identifying suspicious activity post-incident is a classic detective function[cite: 11]. 3. Unlike preventive controls, this does not stop the incident but ensures it is discovered and understood.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":3,"question":"An organization places warning signs around its data center stating that all activities are monitored and recorded.","options":["Corrective control","Deterrent control","Operational control","Preventive control"],"correctIndex":1,"explanation":"1. Warning signs are intended to discourage potential attackers by making them aware of consequences[cite: 15]. 2. This psychological discouragement defines a deterrent control[cite: 18]. 3. It does not physically block access (preventive) or fix a problem (corrective), but seeks to prevent the attempt entirely.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":4,"question":"A systems administrator restores corrupted files from a backup after a ransomware attack encrypted production servers.","options":["Preventive control","Detective control","Directive control","Corrective control"],"correctIndex":3,"explanation":"1. The organization is reacting to damage that has already been done by ransomware[cite: 21]. 2. Restoring from backups is a corrective action because it returns the system to a functional state[cite: 26]. 3. This control focuses on recovery rather than prevention or mere detection.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":5,"question":"A security analyst notices that customer data was altered without authorization during transmission between two servers.","options":["Availability","Confidentiality","Integrity","Non-repudiation"],"correctIndex":2,"explanation":"1. The scenario describes data being 'altered,' which refers to the consistency and accuracy of information[cite: 28]. 2. The 'I' in the CIA triad stands for Integrity, which ensures data remains unchanged by unauthorized parties[cite: 32]. 3. Confidentiality would be the concern if the data were merely seen, while Availability concerns access to the data.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"100 questions Sec + v3.html"},{"id":6,"question":"A law firm requires employees to digitally sign all contracts so the sender cannot later deny submitting the document.","options":["Authentication","Authorization","Accounting","Non-repudiation"],"correctIndex":3,"explanation":"1. Digital signatures provide a way to prove who sent a message[cite: 34]. 2. Non-repudiation ensures that a party cannot deny the authenticity of their signature or the sending of a document[cite: 39]. 3. This principle is vital for legal contracts to ensure accountability for all signatories.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"100 questions Sec + v3.html"},{"id":7,"question":"61. A security team creates a hardened baseline image for all company laptops before deployment. What is the PRIMARY purpose of the baseline? [cite: 306-307]","options":["Reduce backup size","Ensure consistent security configurations","Eliminate all malware","Increase processor performance"],"correctIndex":1,"explanation":"1. A security baseline defines a minimum set of security requirements and configurations. 2. Applying this image to all laptops ensures that every device starts with a known, secure configuration. 3. This consistency simplifies management and reduces the chance of configuration drift.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"61-80 Secv1.html"},{"id":8,"question":"62. An employee loses a company-issued smartphone containing confidential email. Which feature BEST protects company data? [cite: 307-308]","options":["Screen timeout","Mobile hotspot restriction","Remote wipe capability","Bluetooth pairing"],"correctIndex":2,"explanation":"1. Remote wipe is a mobile device management (MDM) feature that allows administrators to erase all data from a lost or stolen device. 2. This is the most effective way to prevent unauthorized access to confidential emails when the physical device is no longer in the owner's possession. 3. It ensures that even if the screen lock is bypassed, the sensitive data is no longer on the storage.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"61-80 Secv1.html"},{"id":9,"question":"63. A company configures wireless networks to require AES encryption and strong authentication for all users. Which wireless security standard BEST meets this requirement? [cite: 309-310]","options":["WEP","WPA","WPA3","Open authentication"],"correctIndex":2,"explanation":"1. WPA3 is the latest wireless security standard designed to provide enhanced protection for modern networks. 2. It mandates the use of AES-based encryption (GCMP) and offers stronger authentication through Simultaneous Authentication of Equals (SAE). 3. Unlike WEP or WPA, WPA3 addresses many of the cryptographic weaknesses found in earlier protocols.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"61-80 Secv1.html"},{"id":10,"question":"64. An organization executes suspicious applications inside an isolated environment to observe behavior without affecting production systems. Which technology is being used? [cite: 310-311]","options":["Honeypot","Sandboxing","Container orchestration","Tokenization"],"correctIndex":1,"explanation":"1. Sandboxing is a security mechanism for separating running programs to prevent system failures and software vulnerabilities from spreading. 2. It creates a tightly controlled environment where suspicious code can be executed without risk to the host operating system or network. 3. Analysts use this to observe malware behavior safely and determine its intended function.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"61-80 Secv1.html"},{"id":11,"question":"65. A company tracks all laptops using asset tags and inventory management software. Which operational function is being performed? [cite: 311-312]","options":["Vulnerability scanning","Asset management","Threat hunting","Penetration testing"],"correctIndex":1,"explanation":"1. Asset management is the process of tracking physical hardware and software licenses throughout their lifecycle. 2. Using asset tags and inventory software allows an organization to know exactly what devices are on the network and who is responsible for them. 3. This is a foundational security practice because you cannot protect what you do not know you have.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"61-80 Secv1.html"},{"id":12,"question":"66. A vulnerability scanner identifies outdated software versions on several servers. What should administrators do NEXT? [cite: 312-313]","options":["Ignore the findings","Replace the firewalls","Remediate the vulnerabilities","Disable logging"],"correctIndex":2,"explanation":"1. Once vulnerabilities are identified by a scanner, the next logical step in the lifecycle is remediation. 2. Remediation involves applying patches, changing configurations, or implementing compensating controls to fix the security gap. 3. Delaying this step leaves the organization exposed to potential exploitation of known weaknesses.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"61-80 Secv1.html"},{"id":13,"question":"67. A security analyst receives alerts whenever unusual outbound traffic volumes leave the corporate network. Which type of tool is MOST likely generating these alerts? [cite: 313-315]","options":["DHCP server","Load balancer","Intrusion detection system (IDS)","Proxy cache"],"correctIndex":2,"explanation":"1. An Intrusion Detection System (IDS) monitors network traffic for suspicious patterns and policy violations. 2. Unusual outbound traffic volumes can indicate data exfiltration or a botnet infection, triggering an alert. 3. While a firewall blocks traffic, the IDS focuses on visibility and alerting the security team to potential breaches.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"61-80 Secv1.html"},{"id":14,"question":"68. A company blocks access to known malicious domains before users can connect to them. Which enterprise security control is being used? [cite: 315-316]","options":["NAC","EDR","DNS filtering","Tokenization"],"correctIndex":2,"explanation":"1. DNS filtering prevents users from accessing specific IP addresses or domains by blocking them at the DNS level. 2. By preventing the resolution of known malicious domains, the organization stops the connection before it can ever be established. 3. This is a highly effective way to block phishing sites and malware command-and-control (C2) servers.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"61-80 Secv1.html"},{"id":15,"question":"69. A network only allows devices that meet company security requirements to connect to internal resources. Which technology is being implemented? [cite: 316-317]","options":["IDS","Network access control (NAC)","SIEM","DLP"],"correctIndex":1,"explanation":"1. Network Access Control (NAC) is a security solution that enforces policy-based access to network resources. 2. It evaluates the security posture of a device (e.g., antivirus status, patch level) before allowing it to connect to the internal network. 3. This ensures that only 'healthy' and authorized devices can access sensitive corporate data.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"61-80 Secv1.html"},{"id":16,"question":"70. A security platform monitors endpoints, correlates activity across systems, and automates threat response actions. Which solution BEST fits this description? [cite: 317-318]","options":["VPN concentrator","NAC","XDR","Proxy server"],"correctIndex":2,"explanation":"1. Extended Detection and Response (XDR) provides a holistic view of security by integrating data from endpoints, networks, and cloud environments. 2. It correlates alerts from multiple sources to detect complex, multi-stage attacks that siloed tools might miss. 3. XDR also includes automated response capabilities to contain threats quickly across the entire infrastructure.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"61-80 Secv1.html"},{"id":17,"question":"71. A company deploys multifactor authentication for remote employees logging into cloud applications. What is the PRIMARY security benefit? [cite: 318-319]","options":["Increased network speed","Reduced backup size","Reduced risk of credential compromise","Elimination of phishing attacks"],"correctIndex":2,"explanation":"1. Multi-factor authentication (MFA) requires users to provide two or more verification factors to gain access. 2. Even if a password is stolen through phishing or a breach, the attacker cannot log in without the second factor (e.g., a phone app or token). 3. This significantly reduces the success rate of credential-based attacks.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"61-80 Secv1.html"},{"id":18,"question":"72. A user authenticates once and gains access to several approved applications without re-entering credentials. Which identity solution is being used? [cite: 319-320]","options":["Federation","Single sign-on (SSO)","Tokenization","Privileged escalation"],"correctIndex":1,"explanation":"1. Single Sign-On (SSO) allows a user to log in once and gain access to a variety of interconnected systems. 2. It improves user experience and security by reducing the number of passwords a user must remember and manage. 3. From an admin perspective, it centralizes access control and simplifies the deprovisioning process.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"61-80 Secv1.html"},{"id":19,"question":"73. A company grants temporary elevated privileges to administrators only when critical maintenance tasks are performed. Which security tool is MOST likely being used? [cite: 320-322]","options":["IDS","DLP","Privileged access management (PAM)","SIEM"],"correctIndex":2,"explanation":"1. Privileged Access Management (PAM) consists of technologies to exercise control over elevated access. 2. It allows for 'just-in-time' privilege elevation, granting high-level rights only when a specific task needs to be performed. 3. This prevents persistent administrative access, which is a major target for attackers.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"61-80 Secv1.html"},{"id":20,"question":"74. A security operations team uses scripts to automatically isolate infected endpoints after malware is detected. Which concept is being demonstrated? [cite: 322-323]","options":["Risk acceptance","Automation and orchestration","Data classification","High availability"],"correctIndex":1,"explanation":"1. Security Orchestration, Automation, and Response (SOAR) uses playbooks to execute repetitive security tasks without human intervention. 2. Automatically isolating an infected endpoint as soon as malware is detected minimizes the 'dwell time' of the threat. 3. This rapid response helps prevent lateral movement and limits the overall damage of an incident.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"61-80 Secv1.html"},{"id":21,"question":"75. After detecting suspicious activity, a company follows a documented process to identify, contain, eradicate, and recover from the attack. Which process is being executed? [cite: 323-324]","options":["Business continuity planning","Incident response","Change management","Disaster recovery testing"],"correctIndex":1,"explanation":"1. Incident response is a structured process used by organizations to handle security breaches and cyberattacks. 2. The standard phases include preparation, identification, containment, eradication, recovery, and lessons learned. 3. Following a documented plan ensures that the response is consistent, efficient, and thorough.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"61-80 Secv1.html"},{"id":22,"question":"76. A security analyst reviews firewall, server, and authentication logs to determine how an attacker gained access. Which investigation activity is occurring? [cite: 324-325]","options":["Vulnerability remediation","Risk transference","Digital forensics analysis","Configuration baselining"],"correctIndex":2,"explanation":"1. Digital forensics analysis involves the collection and examination of digital evidence after a security event. 2. Reviewing logs and system artifacts helps investigators reconstruct the timeline of an attack and identify the root cause. 3. This detailed analysis is vital for understanding how the breach occurred and preventing future recurrences.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"61-80 Secv1.html"},{"id":23,"question":"77. A company conducts proactive searches through logs and endpoint data to identify hidden threats that automated tools may have missed. Which activity is this? [cite: 325-327]","options":["Penetration testing","Threat hunting","Asset tagging","Load balancing"],"correctIndex":1,"explanation":"1. Threat hunting is a proactive security exercise where analysts manually search through data for indicators of compromise (IoCs). 2. It assumes that attackers may have already bypassed automated defenses and are hiding within the network. 3. By actively looking for anomalies, hunting teams can discover sophisticated 'living off the land' attacks.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"61-80 Secv1.html"},{"id":24,"question":"78. An organization configures DLP rules to prevent employees from emailing customer credit card numbers outside the company. Which objective is MOST directly supported? [cite: 327-328]","options":["Availability","Authentication","Preventing data exfiltration","Network redundancy"],"correctIndex":2,"explanation":"1. Data Loss Prevention (DLP) tools are designed to identify and block the unauthorized transfer of sensitive information. 2. Detecting credit card numbers in outbound emails allows the system to stop the message before the data leaves the organization. 3. This directly supports the confidentiality of customer data and helps maintain regulatory compliance.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"61-80 Secv1.html"},{"id":25,"question":"79. A system administrator removes inactive user accounts after employees leave the company. Which IAM activity is being performed? [cite: 328-329]","options":["Federation","Deprovisioning","Accounting","Threat hunting"],"correctIndex":1,"explanation":"1. Deprovisioning is the process of removing or disabling user access to systems and data when it is no longer required. 2. Regularly removing inactive accounts from former employees is a critical security hygiene practice. 3. It prevents 'orphan accounts' from being exploited by attackers to gain unauthorized entry to the network.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"61-80 Secv1.html"},{"id":26,"question":"80. A security team validates that vulnerabilities were successfully fixed after patches were installed. Which step of vulnerability management is occurring? [cite: 329-330]","options":["Identification","Reporting","Prioritization","Validation"],"correctIndex":3,"explanation":"1. Validation is the final step in the vulnerability management cycle where administrators confirm that a fix was successful. 2. Re-scanning systems after patching ensures that the vulnerability is truly gone and no new issues were introduced. 3. Without validation, an organization might mistakenly believe they are protected when the patch failed to install correctly.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"61-80 Secv1.html"},{"id":27,"question":"A company creates a written document that defines acceptable employee behavior when using corporate systems. What type of governance document is this? [cite: 330-332]","options":["Standard","Procedure","Policy","Guideline"],"correctIndex":2,"explanation":"1. A policy is a high-level document that outlines an organization's requirements and goals regarding security. 2. It sets the foundation for acceptable use by defining what is and isn't allowed. 3. Policies are generally mandatory and form the top tier of the governance hierarchy.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"81-100 Secv1.html"},{"id":28,"question":"A security team documents detailed step-by-step instructions for configuring firewalls. What type of governance document is this? [cite: 332-333]","options":["Policy","Guideline","Standard","Procedure"],"correctIndex":3,"explanation":"1. Procedures provide the 'how-to' for specific tasks through sequential steps. 2. They ensure consistency by providing a repeatable process for technical actions. 3. While policies say what to do, procedures provide the exact map to get it done.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"81-100 Secv1.html"},{"id":29,"question":"A company requires all passwords to contain at least 14 characters and include special symbols. What type of governance element is this? [cite: 333-334]","options":["Procedure","Standard","Risk register","Guideline"],"correctIndex":1,"explanation":"1. Standards define specific mandatory requirements or benchmarks for technology and configurations. 2. Password complexity requirements are a classic example of a security standard. 3. Standards ensure that security levels are uniform across all systems in the organization.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"81-100 Secv1.html"},{"id":30,"question":"A business identifies a risk but decides the cost of mitigation is higher than the potential damage. Which risk strategy is being applied? [cite: 334-335]","options":["Risk transfer","Risk avoidance","Risk acceptance","Risk mitigation"],"correctIndex":2,"explanation":"1. Risk acceptance is a conscious decision to acknowledge a risk without taking action to reduce it. 2. This is typically done when the cost-benefit analysis shows that fixing the risk is too expensive. 3. It implies that the organization is willing to absorb the impact if the threat occurs.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"81-100 Secv1.html"},{"id":31,"question":"A company purchases cyber insurance to reduce the financial impact of future security incidents. Which risk management strategy is being used? [cite: 335-336]","options":["Risk acceptance","Risk transfer","Risk avoidance","Risk escalation"],"correctIndex":1,"explanation":"1. Risk transfer moves the financial burden of a risk to a third party. 2. Insurance is the most common method of transferring risk, as the insurer pays for losses. 3. It doesn't eliminate the risk itself but mitigates the negative economic consequences.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"81-100 Secv1.html"},{"id":32,"question":"A security manager calculates the potential financial impact of a ransomware attack on business operations. Which process is being performed? [cite: 336-337]","options":["Penetration testing","Business impact analysis (BIA)","Threat hunting","Vulnerability scanning"],"correctIndex":1,"explanation":"1. A BIA evaluates the potential consequences of disrupting critical business functions. 2. It calculates financial and operational impacts to help prioritize recovery efforts. 3. This process identifies recovery time objectives (RTOs) and recovery point objectives (RPOs).","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":33,"question":"An organization maintains a document listing identified risks, likelihood, impact, and mitigation plans. What is this document called? [cite: 338-339]","options":["Security baseline","Configuration guide","Risk register","Audit report"],"correctIndex":2,"explanation":"1. A risk register is a central repository for all identified risks facing an organization. 2. It tracks the status of risks and the owners responsible for managing them. 3. This document is a living artifact used for ongoing risk monitoring and reporting.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":34,"question":"Before hiring a cloud provider, a company reviews security practices, compliance certifications, and service agreements. Which process is occurring? [cite: 339-340]","options":["Threat hunting","Vendor assessment","Digital forensics","Patch validation"],"correctIndex":1,"explanation":"1. Vendor assessments ensure third parties meet an organization's security standards. 2. This process involves verifying that the provider has proper controls in place. 3. It is critical for managing supply chain risk and protecting shared data.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"81-100 Secv1.html"},{"id":35,"question":"A penetration testing agreement clearly defines what systems can be tested and what activities are prohibited. What section of the agreement is this? [cite: 340-341]","options":["Recovery objective","Rules of engagement","Separation of duties","Asset inventory"],"correctIndex":1,"explanation":"1. Rules of Engagement (RoE) define the parameters and constraints of a security test. 2. They protect the organization from unintended downtime during testing. 3. RoEs ensure that both the tester and the client have a clear understanding of the project's scope.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":36,"question":"A healthcare provider must comply with regulations protecting patient privacy and medical records. What security area is MOST directly involved? [cite: 341-342]","options":["Asset management","Compliance and privacy","Platform diversity","Sandboxing"],"correctIndex":1,"explanation":"1. Compliance involves adhering to laws, regulations, and industry standards like HIPAA. 2. Privacy focuses on the legal right of individuals to control their personal information. 3. Healthcare providers are heavily regulated to ensure sensitive patient data remains confidential.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"81-100 Secv1.html"},{"id":37,"question":"An external auditor independently reviews company controls to confirm regulatory compliance. Which process is occurring? [cite: 342-344]","options":["Threat intelligence","Risk acceptance","External audit","Threat hunting"],"correctIndex":2,"explanation":"1. An external audit is an objective review performed by a third party outside the organization. 2. It provides an unbiased validation that security controls are functioning as intended. 3. These audits are often required by law or for specific industry certifications.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":38,"question":"A company performs a simulated cyberattack to evaluate the effectiveness of its defenses. Which assessment method is being used? [cite: 344-345]","options":["Vulnerability scanning","Penetration testing","Configuration management","Asset tracking"],"correctIndex":1,"explanation":"1. Penetration testing is an active attempt to exploit vulnerabilities to see if a breach is possible. 2. It goes beyond scanning by simulating the actual methods used by attackers. 3. The results help organizations understand the real-world impact of their security gaps.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":39,"question":"A manager signs a document formally confirming that implemented security controls meet compliance requirements. What is this process called? [cite: 345-346]","options":["Tokenization","Attestation","Threat modeling","Change approval"],"correctIndex":1,"explanation":"1. Attestation is a formal statement by a person in authority that a control is operating correctly. 2. It provides evidence for auditors that management is taking responsibility for compliance. 3. This process is a key part of financial and security reporting frameworks.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":40,"question":"Employees receive regular simulated phishing emails followed by training when they click suspicious links. What is the PRIMARY goal? [cite: 346-347]","options":["Improve encryption strength","Increase server uptime","Security awareness training","Reduce backup costs"],"correctIndex":2,"explanation":"1. Security awareness programs aim to reduce human-related risks by educating staff. 2. Phishing simulations teach employees to recognize and report social engineering attempts. 3. Improving the human firewall is often more effective than technical controls alone.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":41,"question":"A security team notices a user logging in from two different countries within ten minutes. What should the organization encourage employees to do? [cite: 347-349]","options":["Ignore the activity","Delete system logs","Report anomalous behavior","Disable MFA"],"correctIndex":2,"explanation":"1. This scenario describes 'impossible travel,' a strong indicator of account compromise. 2. Reporting anomalous behavior allows the security team to investigate and contain potential breaches quickly. 3. Vigilance by both employees and automated systems is essential for early threat detection.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"81-100 Secv1.html"},{"id":42,"question":"An organization separates financial transaction approval responsibilities between two employees to reduce fraud risk. Which principle is applied? [cite: 350-351]","options":["Least privilege","Separation of duties","Zero trust","Sandboxing"],"correctIndex":1,"explanation":"1. Separation of duties ensures that no single person has enough power to complete a critical task alone. 2. This control requires collusion for fraud to occur, making malicious activity much harder. 3. It is a fundamental administrative control for maintaining integrity and accountability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"81-100 Secv1.html"},{"id":43,"question":"A company enforces mandatory vacations for employees handling financial systems to help identify fraudulent activities. Which risk management concept is this? [cite: 351-352]","options":["High availability","Job rotation","Operational oversight control","Threat intelligence"],"correctIndex":1,"explanation":"1. Mandatory vacations are a security control where employees must take time off, allowing others to step in. 2. While away, any ongoing fraudulent schemes may be uncovered when the substitute takes over. 3. This is often categorized alongside job rotation as a personnel security control.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":44,"question":"A security administrator conducts regular reviews to ensure employees only retain access necessary for their current roles. What process is being performed? [cite: 352-353]","options":["Data masking","Access review and recertification","Threat hunting","Load balancing"],"correctIndex":1,"explanation":"1. Access reviews prevent 'privilege creep,' where users accumulate rights they no longer need. 2. Recertification requires managers to periodically confirm that their employees' access is still appropriate. 3. This maintains the principle of least privilege throughout the employee lifecycle.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"81-100 Secv1.html"},{"id":45,"question":"A company develops disaster recovery plans and performs tabletop exercises to evaluate response during emergencies. What is the PRIMARY purpose? [cite: 353-354]","options":["Increase processor speed","Test preparedness and response effectiveness","Reduce software licensing costs","Improve wireless coverage"],"correctIndex":1,"explanation":"1. Tabletop exercises are discussion-based sessions that walk through a simulated disaster scenario. 2. They allow key personnel to practice their roles and identify flaws in the recovery plan. 3. This preparedness ensures a faster, more effective response when a real crisis occurs.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"81-100 Secv1.html"},{"id":46,"question":"An organization monitors regulatory changes and updates internal policies to maintain legal compliance. Which activity is MOST directly being performed? [cite: 355]","options":["Threat hunting","Asset disposal","Governance and compliance monitoring","Sandboxing"],"correctIndex":2,"explanation":"1. Governance and compliance monitoring is the ongoing process of staying aligned with legal requirements. 2. As laws like GDPR or CCPA evolve, internal policies must be updated to avoid fines and liability. 3. This proactive approach ensures the organization remains legally protected and operationally compliant.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"81-100 Secv1.html"},{"id":47,"question":"A healthcare org is migrating a claims app to SaaS. The BIA shows severe impact if the provider is down, but leadership refuses additional budget this quarter. What should security do NEXT to keep governance intact?","options":["Document the residual risk and present it for formal acceptance by leadership","Purchase a secondary SaaS subscription immediately using the emergency response fund","Inform the cloud provider that they must maintain 100% uptime per healthcare laws","Delay the migration indefinitely until the budget for redundancy is approved"],"correctIndex":0,"explanation":"When a security gap is identified but cannot be mitigated due to budget or business constraints, it must be formally documented in the risk register. This ensures that leadership is aware of the potential impact and takes accountability for the risk. This process maintains governance by keeping an audit trail of informed decision-making.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Overall 81-100 v1.html"},{"id":48,"question":"A vulnerability scan identifies an end-of-life (EOL) operating system on a critical legacy server that runs an essential proprietary application. What is the BEST risk mitigation strategy?","options":["Decommission the server immediately to prevent exploitation","Isolate the server on a dedicated VLAN with strict firewall rules","Install a third-party antivirus tool to block all known exploits","Submit a bug report to the OS vendor requesting an emergency patch"],"correctIndex":1,"explanation":"End-of-life systems no longer receive security updates, making them permanently vulnerable to new exploits. If the system cannot be replaced, network isolation through a VLAN or 'sandboxing' restricts its communication to only what is necessary. This prevents lateral movement and reduces the server's exposure to the rest of the network.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Overall 81-100 v1.html"},{"id":49,"question":"An administrator wants to ensure that only approved software can run on company laptops. Which technology provides the STRONGEST protection against unauthorized binaries?","options":["Application Allowlisting","Heuristic Antivirus","File Integrity Monitoring (FIM)","Standard User Permissions"],"correctIndex":0,"explanation":"Application allowlisting (or blocklisting) explicitly defines which executables are permitted to run on a system. Unlike antivirus, which looks for known bad files, allowlisting prevents anything not specifically authorized from executing. This is highly effective against zero-day malware and unauthorized 'shadow IT' applications.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall 81-100 v1.html"},{"id":50,"question":"While reviewing system logs, a security analyst notices that a web server is making high volumes of DNS queries for random subdomains of a known malicious domain. What is this indicative of?","options":["DNS Sinkholing","DNS Beaconing/Exfiltration","BGP Route Hijacking","Domain Sharding"],"correctIndex":1,"explanation":"DNS beaconing is a common command-and-control (C2) technique where malware 'calls home' to a server by making DNS requests. Attackers can also encode stolen data into the subdomain portion of the query to exfiltrate it past firewalls. Monitoring for unusual DNS volume or patterns is a key part of incident detection.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall 81-100 v1.html"},{"id":51,"question":"Which of the following is the primary purpose of a 'Purge' sanitization method on a magnetic hard drive?","options":["Removing data such that it cannot be recovered even by laboratory techniques","Formatting the drive using a high-level operating system command","Deleting the file allocation table while leaving the raw data intact","Resetting the drive to factory default settings without overwriting sectors"],"correctIndex":0,"explanation":"Purging is a media sanitization level that protects against robust laboratory attacks. It typically involves techniques like degaussing or multiple-pass overwriting to ensure no residual data can be reconstructed. This is more intensive than 'Clear,' which only protects against standard software recovery tools.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall 81-100 v1.html"},{"id":52,"question":"A security engineer is configuring a new server. They disable the print spooler service, remove unused sample code, and close all ports except 443. Which process is being performed?","options":["Vulnerability Assessment","System Hardening","Penetration Testing","Patch Management"],"correctIndex":1,"explanation":"System hardening is the process of reducing the attack surface by removing unnecessary software, services, and users. By closing unused ports and disabling non-essential features, the engineer limits the entry points available to an attacker. This is a proactive security measure recommended for every enterprise deployment.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Overall 81-100 v1.html"},{"id":53,"question":"Which cloud service model provides the customer with the MOST control over the operating system and middleware?","options":["Software as a Service (SaaS)","Platform as a Service (PaaS)","Infrastructure as a Service (IaaS)","Function as a Service (FaaS)"],"correctIndex":2,"explanation":"In the Infrastructure as a Service (IaaS) model, the provider only manages the hardware and virtualization layer. The customer is responsible for installing, patching, and securing the operating system and everything above it. This offers maximum flexibility but also the highest security management burden for the user.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Overall 81-100 v1.html"},{"id":54,"question":"A vulnerability scanner reports a 'False Positive' on a web server. How should the security team respond?","options":["Ignore the report and disable the scanner for that specific server","Verify the vulnerability manually or via secondary tools","Immediately apply the recommended patch to ensure compliance","Delete the vulnerability scan history to clear the audit trail"],"correctIndex":1,"explanation":"False positives occur when a scanner incorrectly identifies a vulnerability that does not actually exist. The team must manually investigate to confirm the finding before dedicating resources to remediation. Accurate verification prevents unnecessary downtime and ensures the team focuses on real risks.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Overall 81-100 v1.html"},{"id":55,"question":"An organization wants to detect unauthorized changes to critical system files in real-time. Which tool is BEST suited for this?","options":["File Integrity Monitoring (FIM)","Network Intrusion Detection System (NIDS)","Log Aggregator","Vulnerability Scanner"],"correctIndex":0,"explanation":"File Integrity Monitoring (FIM) tools compute hashes of system files and alert administrators if those hashes change. This is critical for detecting rootkits or unauthorized modifications by malicious insiders. FIM is often a requirement for compliance standards like PCI DSS.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall 81-100 v1.html"},{"id":56,"question":"What is the primary benefit of using a CASB (Cloud Access Security Broker)?","options":["It provides physical security for cloud data centers","It enforces security policies between on-premises users and cloud providers","It replaces the need for a corporate firewall and VPN","It automates the deployment of virtual machines in the cloud"],"correctIndex":1,"explanation":"A CASB acts as a security enforcement point between cloud users and cloud applications. It provides visibility into 'Shadow IT' and enforces policies like data loss prevention (DLP) and encryption. This helps organizations maintain a consistent security posture across multiple cloud environments.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall 81-100 v1.html"},{"id":57,"question":"Which attack involves taking advantage of the trust a user's browser has in a website?","options":["XSRF (CSRF)","SQLi","XSS","Buffer Overflow"],"correctIndex":0,"explanation":"XSRF (Cross-Site Request Forgery) exploits the trust a site has in a user's browser to execute unwanted actions. You arrive at this answer by focusing on the 'trust a user's browser has in a website' key phrase. It forces an authenticated user to submit a request that the web application perceives as legitimate.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":58,"question":"An attacker uses a computer to repeatedly ping a server until it crashes. What type of attack is this?","options":["DoS","DDoS","MITM","Spoofing"],"correctIndex":0,"explanation":"A Denial of Service (DoS) attack aims to make a service unavailable by overwhelming it with requests from a single source. In this scenario, a single computer is used to crash a server via pings, matching the DoS definition. This differs from a DDoS, which utilizes multiple distributed systems to achieve the same result.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":59,"question":"Which of the following is a 'Supply Chain Attack'?","options":["Compromising a software vendor","Guessing a user's password","Sending a phishing email","Stealing a laptop"],"correctIndex":0,"explanation":"A Supply Chain attack targets the third-party vendors and software providers that an organization trusts. By injecting malicious code into a vendor's update, the attacker gains access to all of that vendor's customers simultaneously. This is a high-impact threat because it bypasses traditional perimeter defenses by riding on trusted software.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":60,"question":"What is 'Typosquatting'?","options":["Registering domains with slight misspellings","Stealing data from a keyboard buffer","Watching someone type a password","Breaking a physical keyboard"],"correctIndex":0,"explanation":"Typosquatting relies on users making small typing errors when manually entering a web address into a browser. Attackers register these misspelled domains to lead users to malicious clones of popular sites for credential harvesting. It is a common social engineering tactic that exploits human error in navigation.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":61,"question":"Which threat actor is usually motivated by political or social causes?","options":["Script Kiddie","APT","Hacktivist","Insider Threat"],"correctIndex":2,"explanation":"Hacktivists are threat actors motivated by social, political, or religious ideologies rather than financial gain. Their primary goal is usually to draw attention to a specific cause or protest a government or corporation. This distinguishes them from organized crime groups who are typically driven by monetary profit.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Overall Sec 41-80v1.html"},{"id":62,"question":"Which network device uses ACLs to filter traffic based on IP addresses and ports?","options":["Switch","Router","Firewall","Hub"],"correctIndex":2,"explanation":"Firewalls use Access Control Lists (ACLs) to filter incoming and outgoing traffic based on source/destination IP addresses and port numbers. They act as the primary barrier between different network zones to enforce specific security policies. You arrive at this answer because the question specifically mentions filtering via IPs and ports.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":63,"question":"A company wants to encrypt all traffic between two offices over the internet. What should they use?","options":["VLAN","Site-to-Site VPN","Remote Access VPN","Honeypot"],"correctIndex":1,"explanation":"A Site-to-Site VPN creates a secure, encrypted tunnel between two physical office locations over the public internet. This allows users in different offices to access shared resources as if they were on the same local network. It is the industry-standard solution for connecting branch offices securely.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":64,"question":"Which protocol is used to secure web traffic?","options":["HTTP","FTP","HTTPS (TLS)","SNMP"],"correctIndex":2,"explanation":"HTTPS uses TLS (Transport Layer Security) to encrypt communication between a web browser and a server. It ensures that data remains confidential while also providing server authentication through digital certificates. This is the fundamental protocol for secure web browsing and e-commerce today.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":65,"question":"What is the purpose of a 'DMZ'?","options":["To store internal databases","To provide a buffer for public-facing services","To encrypt internal emails","To manage user passwords"],"correctIndex":1,"explanation":"A DMZ (Demilitarized Zone) is a subnetwork that sits between the internal private network and the public internet. It hosts public-facing services like web or mail servers to prevent external users from accessing the internal network directly. This adds a critical layer of defense-in-depth for organizational assets.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":66,"question":"Which technology allows multiple isolated networks to exist on a single physical switch?","options":["VPN","VLAN","NAT","DHCP"],"correctIndex":1,"explanation":"A Virtual Local Area Network (VLAN) segments a single physical switch into multiple isolated logical networks. It improves security by restricting broadcast domains and controlling traffic flow between different departments. This allows for flexible network management without requiring additional physical hardware.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Overall Sec 41-80v1.html"},{"id":67,"question":"Which cloud service model provides the consumer with the most control over the OS?","options":["SaaS","PaaS","IaaS","XaaS"],"correctIndex":2,"explanation":"Infrastructure as a Service (IaaS) provides virtualized computing resources like servers, storage, and networking over the internet. In this model, the customer has the most control because they are responsible for managing the operating system and applications. You arrive at this answer by identifying the high level of OS-level control granted to the user.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Overall Sec 41-80v1.html"},{"id":68,"question":"A security admin wants to prevent unauthorized devices from connecting to a switch port. What should they implement?","options":["Port Security (MAC Filtering)","Loop Protection","VLAN Tagging","Spanning Tree"],"correctIndex":0,"explanation":"Port Security (specifically MAC Filtering) limits which devices can connect to a physical switch port based on their unique hardware address. It prevents unauthorized hardware from being plugged into the network in empty cubicles or public areas. This is a vital Layer 2 security control for managing physical office access.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall Sec 41-80v1.html"},{"id":69,"question":"Which protocol is used to securely manage network devices?","options":["Telnet","SSH","FTP","SNMPv1"],"correctIndex":1,"explanation":"Secure Shell (SSH) provides an encrypted channel for managing network devices and servers remotely. It was designed as a secure replacement for Telnet, which sent login credentials and data in cleartext. You arrive at this answer because it is the global standard for 'securely managing' infrastructure.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":70,"question":"What does 'Load Balancing' primarily provide?","options":["Confidentiality","Availability","Integrity","Non-repudiation"],"correctIndex":1,"explanation":"Load balancing distributes incoming network traffic across multiple servers to ensure that no single server becomes overwhelmed. This directly supports the goal of Availability by providing redundancy and preventing service downtime during traffic spikes. You arrive at this answer by linking traffic distribution to system uptime.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall Sec 41-80v1.html"},{"id":71,"question":"A company moving to the cloud wants a dedicated, private connection to the provider. What is this called?","options":["Public Cloud","Community Cloud","Direct Connect / ExpressRoute","Hybrid Cloud"],"correctIndex":2,"explanation":"Cloud providers offer dedicated, private network connections (like AWS Direct Connect or Azure ExpressRoute) that bypass the public internet entirely. These provide more consistent performance, lower latency, and improved security for enterprise workloads. This is the preferred method for hybrid cloud environments requiring high-speed data transfer.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":72,"question":"Which of the following is used to store and manage digital certificates?","options":["SIEM","PKI","IDS","UTM"],"correctIndex":1,"explanation":"Public Key Infrastructure (PKI) is the framework of hardware, software, and policies used to manage and distribute digital certificates. It enables the secure exchange of data by providing identity verification via a trusted third party. You arrive at this answer by associating the management of certificates with its governing architecture.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":73,"question":"Which standard is used for network-based authentication (Port-based)?","options":["802.11","802.1X","802.3","802.1Q"],"correctIndex":1,"explanation":"802.1X is an IEEE standard for port-based network access control (PNAC) on wired and wireless networks. It requires devices to authenticate with a central server (like RADIUS) before they are granted access to the physical network. This ensures that only authorized users and devices can connect to the organization's ports.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall Sec 41-80v1.html"},{"id":74,"question":"Which of the following is an 'Air Gap'?","options":["A network with no physical/wireless connection","A high-speed fiber connection","A type of firewall","A ventilated server room"],"correctIndex":0,"explanation":"An Air Gap is a security measure that ensures a network is physically isolated from all other networks, including the internet. It is used for highly sensitive systems where the risk of remote intrusion or data exfiltration must be minimized to zero. You arrive at this answer because the description mentions a network with no physical or wireless connections.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":75,"question":"Which technology translates private IP addresses to a public IP address?","options":["DNS","NAT","DHCP","ARP"],"correctIndex":1,"explanation":"Network Address Translation (NAT) allows multiple devices on a private network to share a single public IP address for internet access. It hides the internal network structure from the outside world while conserving the limited pool of IPv4 addresses. This translation typically occurs at the perimeter router or firewall level.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":76,"question":"What is a 'CASB'?","options":["A home firewall","A security tool between cloud users and apps","A secure cable","A biometric scanner"],"correctIndex":1,"explanation":"A Cloud Access Security Broker (CASB) is a tool that enforces security policies between cloud service users and cloud applications. It provides visibility into cloud usage, data protection (DLP), and threat prevention for SaaS platforms. You arrive at this answer because it sits specifically between the 'cloud user' and the 'cloud application.'","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":77,"question":"Which of the following is a stateless inspection?","options":["Monitoring the entire conversation","Checking each packet individually","Blocking based on geography","Inspecting encrypted packets"],"correctIndex":1,"explanation":"Stateless inspection (or packet filtering) examines each packet individually without considering the context of the entire connection. It is faster than stateful inspection but less secure because it doesn't track the 'state' or flow of sessions. You arrive at this answer because the description specifies checking 'each packet individually.'","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":78,"question":"A company uses a single sign-on (SSO) solution. Which protocol might they be using?","options":["SAML","WPA3","TKIP","SNMP"],"correctIndex":0,"explanation":"Security Assertion Markup Language (SAML) is an XML-based standard used for exchanging authentication and authorization data. It is the primary protocol used to enable Single Sign-On (SSO) across different web applications and domains. This allows a user to log in once and access multiple services seamlessly.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall Sec 41-80v1.html"},{"id":79,"question":"Which of the following is a symmetric encryption algorithm?","options":["RSA","ECC","AES","Diffie-Hellman"],"correctIndex":2,"explanation":"Advanced Encryption Standard (AES) is a symmetric block cipher used worldwide to secure sensitive data. Symmetric encryption uses the same key for both encryption and decryption, making it significantly faster for large amounts of data. You arrive at this answer by identifying it as a common 'symmetric' algorithm compared to asymmetric ones like RSA.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":80,"question":"What is the purpose of 'Hashing'?","options":["To encrypt data for storage","To provide integrity via a unique fixed value","To hide data in an image","To speed up the network"],"correctIndex":1,"explanation":"Hashing takes an input of any size and produces a unique, fixed-length string of characters (a digest). Because even a tiny change in the input results in a completely different hash, it is used to verify data integrity. You arrive at this answer by focusing on the goal of creating a 'unique fixed-length value' for verification.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":81,"question":"Which protocol provides secure file transfers?","options":["TFTP","SFTP","FTP","Telnet"],"correctIndex":1,"explanation":"SSH File Transfer Protocol (SFTP) uses the Secure Shell (SSH) protocol to provide a secure, encrypted tunnel for moving files. It is superior to standard FTP, which transmits data and passwords in cleartext. You arrive at this answer by seeking the protocol that provides 'secure file transfers' via encryption.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":82,"question":"What is a 'Honeypot'?","options":["A password vault","A decoy system to study attackers","A type of malware","A high-speed server"],"correctIndex":1,"explanation":"A Honeypot is a decoy system designed to look like a high-value target to lure in attackers. It allows security teams to study the attacker's methods and divert them from real production systems. You arrive at this answer because it is described as a 'decoy system' for study and distraction purposes.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall Sec 41-80v1.html"},{"id":83,"question":"Which concept involves keeping the same encryption key for only a short period?","options":["Key Stretching","Ephemeral Keys","Key Escrow","Key Revocation"],"correctIndex":1,"explanation":"Ephemeral keys are temporary cryptographic keys generated for a single session or transaction and then discarded. By frequently changing keys, an organization ensures that even if one key is compromised, past and future sessions remain secure. This concept is a core component of achieving Perfect Forward Secrecy (PFS).","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":84,"question":"Which type of hypervisor runs directly on the hardware?","options":["Type 1 (Bare Metal)","Type 2 (Hosted)","Type 3 (Cloud)","Container"],"correctIndex":0,"explanation":"A Type 1 hypervisor (Bare Metal) runs directly on the host's hardware to manage guest operating systems. It is more efficient and secure than Type 2 hypervisors, which must run on top of a host operating system. You arrive at this answer because the scenario specifies running 'directly on the hardware.'","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":85,"question":"A mobile device is lost. The admin wants to delete all data on it remotely. What is this called?","options":["Remote Wipe","Geofencing","Sideloading","Jailbreaking"],"correctIndex":0,"explanation":"Remote Wipe is a security feature that allows an administrator to erase all data on a mobile device from a distance. It is a critical control for protecting corporate data when a phone or tablet is lost or stolen. You arrive at this answer because the goal is to 'delete all data' on a lost device.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":86,"question":"Which technology provides a centralized way to manage and automate network security?","options":["SDN (Software Defined Networking)","VLAN","Hub","Repeater"],"correctIndex":0,"explanation":"Software-Defined Networking (SDN) decouples the network control plane from the forwarding plane (data plane). This allows for centralized management and programmable automation of network traffic and security policies. You arrive at this answer because it describes a 'centralized way to manage and automate' network logic.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Overall Sec 41-80v1.html"},{"id":87,"question":"Which tool is used to aggregate and correlate logs from multiple sources?","options":["IDS","SIEM","DLP","UPS"],"correctIndex":1,"explanation":"Security Information and Event Management (SIEM) tools collect and analyze log data from throughout the enterprise. They correlate disparate events to identify potential security threats that might be missed by individual systems. You arrive at this answer because the tool's primary role is to 'aggregate and correlate logs.'","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":88,"question":"What is the first step in the Incident Response process?","options":["Eradication","Preparation","Containment","Recovery"],"correctIndex":1,"explanation":"Preparation is the foundational stage of the incident response lifecycle where policies, teams, and tools are established. It ensures that the organization is trained and equipped to handle an attack before it actually occurs. You arrive at this answer because it is universally recognized as the 'first step' in the IR process.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Overall Sec 41-80v1.html"},{"id":89,"question":"During an investigation, the legal team wants to ensure that the evidence has not been tampered with. What is required?","options":["Data Masking","Chain of Custody","Hot Site","Qualitative Analysis"],"correctIndex":1,"explanation":"Chain of Custody is a chronological record that tracks the collection, handling, and storage of evidence during an investigation. It ensures that evidence remains untampered and admissible in a court of law. You arrive at this answer because the legal team wants to verify 'evidence has not been tampered with.'","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Overall Sec 41-80v1.html"},{"id":90,"question":"Which of the following is an 'Indicator of Compromise' (IoC)?","options":["High network latency","Unknown IP communication at 3 AM","A forgotten password","A Windows update"],"correctIndex":1,"explanation":"An Indicator of Compromise (IoC) is a piece of forensic data that suggests a system has been breached. Unexpected outbound traffic to an unknown IP at an odd hour is a classic sign of an active threat or exfiltration. You arrive at this answer by identifying which event represents a specific 'sign' of a security incident.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":91,"question":"What is the purpose of 'Sandboxing'?","options":["To play games","To run suspicious programs in isolation","To encrypt data at rest","To increase database speed"],"correctIndex":1,"explanation":"Sandboxing creates a safe, isolated environment where suspicious files or code can be executed without risking the host system. It is commonly used by malware analysts and security tools to observe malicious behavior in real-time. You arrive at this answer because the goal is to 'run suspicious programs in an isolated environment.'","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":92,"question":"Which of the following is 'Volatile Data'?","options":["Hard drive contents","RAM","USB Stick","DVD-ROM"],"correctIndex":1,"explanation":"Volatile data is information that is lost when power is removed from a computer system. RAM (Random Access Memory) is the most common example of volatile storage used in digital forensics. You arrive at this answer by identifying which storage medium requires power to maintain its contents.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Overall Sec 41-80v1.html"},{"id":93,"question":"A company wants to simulate a real-world attack to test their defenses. Which team performs the attack?","options":["Blue Team","Red Team","White Team","Purple Team"],"correctIndex":1,"explanation":"The Red Team acts as the adversary in a security exercise, using real-world attack techniques to test an organization's defenses. Their goal is to identify weaknesses by thinking and acting like a malicious threat actor. You arrive at this answer because the Red Team is explicitly the group that 'performs the attack.'","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Overall Sec 41-80v1.html"},{"id":94,"question":"What does 'DLP' stand for?","options":["Data Loss Prevention","Digital Log Processor","Dynamic Link Protocol","Data Layer Protection"],"correctIndex":0,"explanation":"Data Loss Prevention (DLP) consists of tools and policies designed to ensure that sensitive information does not leave the corporate network. It scans data in motion, in use, and at rest to prevent unauthorized exfiltration. You arrive at this answer by recognizing the standard industry acronym for 'Data Loss Prevention.'","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall Sec 41-80v1.html"},{"id":95,"question":"Which command-line tool can be used to view active network connections?","options":["ipconfig","netstat","ping","tracert"],"correctIndex":1,"explanation":"The 'netstat' (network statistics) command-line tool displays all active network connections and listening ports on a local machine. It is a vital tool for troubleshooting and identifying unauthorized or suspicious network activity. You arrive at this answer because the objective is to 'view active network connections.'","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":96,"question":"What is the main goal of 'Containment' in incident response?","options":["To fix the vulnerability","To stop the incident from spreading","To identify the attacker","To restore the system"],"correctIndex":1,"explanation":"Containment is the IR phase focused on limiting the scope and impact of a security incident to prevent further damage. By isolating infected systems, the security team prevents the threat from spreading deeper into the network. You arrive at this answer because the primary goal is to 'stop the incident from spreading.'","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Overall Sec 41-80v1.html"},{"id":97,"question":"A security administrator is implementing a system where access is granted based on the user's role within the organization. Which access control model is being used?","options":["DAC","MAC","RBAC","ABAC"],"correctIndex":2,"explanation":"RBAC (Role-Based Access Control) assigns permissions to specific job functions rather than individual users. To arrive at this answer, look for the keyword 'role' which defines the access structure. This model simplifies management because users automatically inherit permissions when assigned to a role.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":98,"question":"Which of the following security goals ensures that data has not been modified by unauthorized entities?","options":["Confidentiality","Integrity","Availability","Non-repudiation"],"correctIndex":1,"explanation":"Integrity is the core security pillar focused on preventing unauthorized data alteration. You can identify this by the focus on data being 'modified' or changed. Tools like hashing and digital signatures are commonly used to verify that integrity remains intact.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":99,"question":"An organization wants to verify that a message was sent by a specific user and that the content was not altered. What should the user apply to the message?","options":["Encryption with a public key","A digital signature","A salted hash","Steganography"],"correctIndex":1,"explanation":"A digital signature provides both integrity and non-repudiation, verifying the sender's identity. To arrive at this answer, notice the requirement for both identity verification and content validation. By signing with a private key, the sender ensures only their public key can decrypt the hash.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":100,"question":"Which concept assumes that no user or device is trusted by default, even if they are inside the network perimeter?","options":["Defense in Depth","Zero Trust","Honeynet","Air Gap"],"correctIndex":1,"explanation":"Zero Trust architecture removes the concept of an implicit 'trusted' internal network. You can arrive at this answer by focusing on the 'no trust by default' phrase in the scenario. Every access request must be continuously authenticated and authorized regardless of location.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall quiz Secv1.html"},{"id":101,"question":"A technician is tasked with ensuring that a critical server remains online even if a single power supply fails. Which concept does this represent?","options":["Scalability","Redundancy","Elasticity","Non-persistence"],"correctIndex":1,"explanation":"Redundancy involves duplicating critical components to ensure system operation continues during a failure. The phrase 'remains online even if a component fails' is the key indicator for this concept. This ensures high availability by eliminating single points of failure.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall quiz Secv1.html"},{"id":102,"question":"Which of the following is a physical security control?","options":["Firewall","ACL","Faraday cage","Encryption"],"correctIndex":2,"explanation":"A Faraday cage is a physical enclosure used to block electromagnetic fields from entering or leaving an area. To arrive at this answer, identify which option represents a tangible, physical barrier rather than software. It is primarily used to prevent electronic eavesdropping or signal interference.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall quiz Secv1.html"},{"id":103,"question":"A company requires employees to use a password and a hardware token to log in. What type of authentication is this?","options":["Single-factor","Mutual","Multi-factor","Federation"],"correctIndex":2,"explanation":"Multi-factor authentication (MFA) requires two or more distinct categories of credentials. In this case, a password is 'something you know' and a token is 'something you have.' Combining these two different factors satisfies the multi-factor requirement.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":104,"question":"Which term describes the probability of a threat actor exploiting a vulnerability?","options":["Asset","Risk","Impact","Mitigation"],"correctIndex":1,"explanation":"Risk is mathematically defined as the likelihood (probability) of a threat occurring multiplied by the impact. You arrive at this answer by connecting the potential for exploitation with the term 'probability.' Understanding risk helps organizations prioritize which vulnerabilities to patch first.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Overall quiz Secv1.html"},{"id":105,"question":"Which policy defines how long data should be kept and when it should be destroyed?","options":["Acceptable Use Policy (AUP)","Data Retention Policy","Incident Response Policy","Separation of Duties"],"correctIndex":1,"explanation":"A Data Retention Policy sets the timeline for how long data must be stored for legal or business reasons. The keywords 'how long' and 'destroyed' directly point to data lifecycle management. This policy helps reduce liability and storage costs by purging unnecessary data.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall quiz Secv1.html"},{"id":106,"question":"A user cannot deny having sent an email because the email was digitally signed. Which concept is this?","options":["Integrity","Availability","Non-repudiation","Obfuscation"],"correctIndex":2,"explanation":"Non-repudiation ensures that a party in a communication cannot deny the authenticity of their signature or message. You arrive at this answer because the scenario explicitly mentions the user 'cannot deny' the action. This is achieved through the use of asymmetric cryptography.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":107,"question":"Which of the following is considered a corrective control?","options":["CCTV","Guard","Restoring from backups","Security policy"],"correctIndex":2,"explanation":"Corrective controls are used to restore a system to a normal state after an incident has occurred. Restoring from backups is the classic example of fixing the damage caused by a threat. You arrive at this answer by identifying which action occurs 'after' the incident to remediate it.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall quiz Secv1.html"},{"id":108,"question":"What is the primary purpose of a 'Gap Analysis'?","options":["To find the root cause of an incident","To compare current security levels against desired standards","To encrypt data at rest","To scan for network vulnerabilities"],"correctIndex":1,"explanation":"A Gap Analysis identifies the 'gap' between the current security posture and the required compliance or industry standard. You arrive at this answer by focusing on the comparison of 'current' versus 'desired.' This process creates a roadmap for security improvements and budgeting.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":109,"question":"Which role is responsible for the technical environment where data resides?","options":["Data Owner","Data Custodian","Data Controller","Data Processor"],"correctIndex":1,"explanation":"The Data Custodian is responsible for the technical implementation of security controls and data maintenance. To arrive at this answer, look for the 'technical environment' keyword, which distinguishes it from the management role of the Owner. They handle backups, encryption settings, and storage access.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall quiz Secv1.html"},{"id":110,"question":"A security admin uses a 'Mantrap' at the entrance of a data center. What is the primary purpose?","options":["To prevent tailgating","To detect fire","To monitor traffic","To block EMI"],"correctIndex":0,"explanation":"A mantrap is a physical access control consisting of two interlocking doors to ensure only one person enters at a time. The primary goal is to prevent 'tailgating' or 'piggybacking' into a secure area. You arrive at this answer by recognizing the physical design of the entryway system.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":111,"question":"Which of the following describes 'security through obscurity'?","options":["Changing the default port of a service","Using AES-256 encryption","Implementing MFA","Hardening a Linux kernel"],"correctIndex":0,"explanation":"Security through obscurity relies on hiding information or configuration details to prevent discovery by attackers. Changing a default port is a classic example, as it doesn't actually secure the service, just makes it harder to find. You arrive at this answer by identifying a tactic that hides rather than fixes a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":112,"question":"An attacker sends an email to a CEO pretending to be the legal department to steal credentials. What is this called?","options":["Phishing","Whaling","Vishing","Smishing"],"correctIndex":1,"explanation":"Whaling is a highly targeted form of phishing aimed at high-profile individuals like CEOs or executives. You arrive at this answer because the target specified is a 'CEO.' This attack typically uses more sophisticated social engineering than standard phishing.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall quiz Secv1.html"},{"id":113,"question":"Which type of malware encrypts a user's files and demands payment?","options":["Spyware","Rootkit","Ransomware","Logic Bomb"],"correctIndex":2,"explanation":"Ransomware is malicious software designed to block access to a computer system or files until a sum of money is paid. The keyword 'encrypts' and 'demands payment' is the definitive characteristic of this malware. It primarily targets the availability of data.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":114,"question":"A user notices their computer is slow, and the CPU usage is high even when idle. A technician finds a process running that is mining cryptocurrency. What is this?","options":["Adware","Cryptojacking","Trojan","Worm"],"correctIndex":1,"explanation":"Cryptojacking is the unauthorized use of a person's computing power to mine cryptocurrency. To arrive at this answer, connect the symptoms of 'high CPU usage' with the activity of 'mining.' It often occurs through malicious scripts in a browser or infected software.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":115,"question":"An attacker redirects a website's traffic to a fake site by poisoning the DNS cache. What is this?","options":["Pharming","Typosquatting","Spim","Shoulder Surfing"],"correctIndex":0,"explanation":"Pharming involves redirecting victims to a malicious website by corrupting DNS resolution or host files. You arrive at this answer by noting the 'poisoning the DNS cache' method mentioned. Unlike phishing, the user may type the correct URL and still be redirected.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":116,"question":"Which attack involves an attacker capturing a session token and using it to impersonate a user?","options":["SQL Injection","Session Hijacking","Cross-site Scripting","Replay Attack"],"correctIndex":1,"explanation":"Session Hijacking occurs when an attacker steals a valid session ID to gain unauthorized access to a web server. The 'capturing a session token' phrase is the key indicator for this attack. Once the token is stolen, the attacker can bypass authentication entirely.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Overall quiz Secv1.html"},{"id":117,"question":"An attacker enters a string like ' OR 1=1 -- into a login field. What attack is being attempted?","options":["XSS","SQL Injection","Buffer Overflow","LDAP Injection"],"correctIndex":1,"explanation":"SQL Injection (SQLi) is an attack that inserts malicious SQL code into input fields to manipulate a database. You arrive at this answer by recognizing the SQL syntax 'OR 1=1' used to bypass authentication. This exploit targets vulnerabilities in the application's data layer.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":118,"question":"A vulnerability is discovered in a software package that has no known patch. What is this called?","options":["Zero-day","False positive","Legacy system","Shadow IT"],"correctIndex":0,"explanation":"A Zero-day vulnerability is a security flaw that is unknown to the software vendor and has no available patch. The phrase 'no known patch' is the defining characteristic of this threat. These are highly dangerous because there are zero days of protection available.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Overall quiz Secv1.html"},{"id":119,"question":"Which type of attack uses a list of common words to try and crack a password?","options":["Brute Force","Dictionary Attack","Birthday Attack","Rainbow Table"],"correctIndex":1,"explanation":"A Dictionary Attack uses a predefined list of likely words or previously leaked passwords to guess credentials. You arrive at this answer by identifying the 'list of common words' method. It is more efficient than a pure brute force attack but less effective against complex strings.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":120,"question":"A person walks into an office following an employee who just swiped their badge. What is this called?","options":["Piggybacking","Tailgating","Dumpster diving","Social engineering"],"correctIndex":1,"explanation":"Tailgating is the act of following an authorized person into a secure area without their knowledge or consent. You arrive at this answer because the individual is 'following' someone through a badge-protected door. It is a common physical security breach.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":121,"question":"What is the primary difference between a worm and a virus?","options":["A worm requires human action","A virus is self-replicating","A worm is self-replicating and spreads over the network","A virus only affects mobile devices"],"correctIndex":2,"explanation":"Worms are standalone programs that replicate and spread across networks without needing a host file or human interaction. Viruses, by contrast, require a user to execute an infected file to spread. You arrive at this answer by focusing on the 'network' and 'self-replicating' traits of the worm.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":122,"question":"Which of the following is a physical threat?","options":["Skimming","Bluejacking","Bluesnarfing","Spoofing"],"correctIndex":0,"explanation":"Skimming involves physical devices placed over card readers to steal credit card information during a transaction. You arrive at this answer by identifying which threat requires a physical device interaction. The other options are wireless or software-based attacks.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":123,"question":"An attacker uses an authorized user's Bluetooth connection to steal data. What is this?","options":["Bluejacking","Bluesnarfing","Evil Twin","Rogue Access Point"],"correctIndex":1,"explanation":"Bluesnarfing is the unauthorized access of information from a wireless device through a Bluetooth connection. You arrive at this answer because the goal is to 'steal data' (snarfing) rather than just send messages (jacking). It exploits vulnerabilities in the Bluetooth protocol.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":124,"question":"A technician finds that a program is crashing because it is trying to write more data to a memory buffer than it can hold. What is this?","options":["Integer Overflow","Buffer Overflow","Resource Exhaustion","Race Condition"],"correctIndex":1,"explanation":"A Buffer Overflow occurs when a program writes data beyond the boundaries of its fixed-length block of memory. This leads to system crashes or the execution of malicious code. You arrive at this answer by identifying the 'writing more data than memory can hold' description.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":125,"question":"Which of the following is a passive reconnaissance technique?","options":["Port scanning with Nmap","Banner grabbing","Searching Whois records","Vulnerability scanning"],"correctIndex":2,"explanation":"Passive reconnaissance involves gathering information about a target without directly interacting with their systems. Searching Whois records is passive because you are querying a public database, not the target's server. To arrive at this answer, distinguish between direct interaction and indirect data gathering.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Overall quiz Secv1.html"},{"id":126,"question":"An attacker sets up a fake Wi-Fi hotspot with the same name as a legitimate one. What is this?","options":["War Driving","Evil Twin","Bluejacking","Dissociative Attack"],"correctIndex":1,"explanation":"An Evil Twin is a fraudulent Wi-Fi access point that appears to be legitimate by using the same SSID. Users connect to it thinking it is the official network, allowing the attacker to intercept traffic. You arrive at this answer by identifying the 'fake hotspot with the same name' scenario.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":127,"question":"What is the purpose of a 'Logic Bomb'?","options":["To steal passwords","To execute malicious code when a specific condition is met","To provide remote access","To replicate across the network"],"correctIndex":1,"explanation":"A Logic Bomb is a string of code intentionally inserted into software that triggers a malicious action when certain conditions are met. You arrive at this answer by focusing on the 'specific condition' (like a date or user action). It is often planted by disgruntled employees as an insider threat.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Overall quiz Secv1.html"},{"id":128,"question":"A pen tester is given no information about the target network. What type of test is this?","options":["White Box","Grey Box","Black Box","Known Environment"],"correctIndex":2,"explanation":"Black Box testing simulates an outside attacker who has no prior knowledge of the internal systems or architecture. You arrive at this answer because the tester is given 'no information.' This forces the tester to perform their own reconnaissance and discovery.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":129,"question":"Which of the following is a non-credentialed vulnerability scan?","options":["Scanning as an administrator","Scanning from the perspective of an outsider without login rights","Reviewing code for logic errors","Checking file permissions manually"],"correctIndex":1,"explanation":"Non-credentialed scans attempt to find vulnerabilities without having login access to the target system. This simulates what an unauthenticated hacker would see from the outside. You arrive at this answer by identifying the 'outsider without login rights' perspective.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Overall quiz Secv1.html"},{"id":130,"question":"An attacker exploits a flaw where two threads are competing for the same resource. What is this?","options":["Buffer Overflow","Race Condition","DLL Injection","Memory Leak"],"correctIndex":1,"explanation":"A Race Condition occurs when the output of a process depends on the sequence or timing of uncontrollable events. You arrive at this answer by focusing on the 'two threads competing for the same resource' description. This timing flaw can be exploited to gain unauthorized privileges or bypass security checks.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":131,"question":"Which of the following describes 'Vishing'?","options":["Phishing over SMS","Phishing over Voice/Phone","Phishing over Social Media","Phishing over Email"],"correctIndex":1,"explanation":"Vishing (Voice Phishing) is a social engineering attack conducted over the phone or via VoIP. To arrive at this answer, look for the 'Voice' or 'Phone' keywords. Attackers often use caller ID spoofing to appear as a trusted organization like a bank.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":132,"question":"An attacker uses a precomputed table of hashes to crack passwords. What is this table called?","options":["Hash Map","Rainbow Table","Logic Table","Salt Table"],"correctIndex":1,"explanation":"A Rainbow Table is a precomputed database of plaintext passwords and their corresponding hash values. You arrive at this answer by identifying the 'precomputed table of hashes' method. Salting passwords makes these tables ineffective because it changes the hash outcome.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":133,"question":"What is 'Shadow IT'?","options":["IT departments working at night","Unauthorized hardware or software","A backup IT site","Stealthy malware"],"correctIndex":1,"explanation":"Shadow IT refers to information technology systems and solutions used within an organization without explicit departmental approval. You arrive at this answer by looking for 'unauthorized' use of tech by employees. This creates security risks because these devices are not managed or patched by the security team.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":134,"question":"Which of the following is a 'Man-in-the-Middle' attack?","options":["SQL Injection","ARP Poisoning","Brute Force","Salted Hashing"],"correctIndex":1,"explanation":"ARP Poisoning is a method where an attacker sends faked ARP messages to a LAN to link their MAC address with the IP of a legitimate server. This allows the attacker to intercept, modify, or block data meant for that server. You arrive at this answer by recognizing it as a primary way to sit 'in the middle' of traffic.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":135,"question":"What does a 'Rootkit' primarily aim to do?","options":["Steal credit card info","Maintain persistent, hidden access","Display unwanted ads","Encrypt the hard drive"],"correctIndex":1,"explanation":"A Rootkit is a collection of software designed to provide privileged (root) access to a computer while hiding its presence. You arrive at this answer because the primary goal is 'hidden' and 'persistent' access. They often subvert the OS kernel to remain invisible to standard antivirus tools.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":136,"question":"A user receives a text message saying their bank account is locked and to click a link. What is this?","options":["Phishing","Smishing","Vishing","Whaling"],"correctIndex":1,"explanation":"Smishing is a form of phishing that uses SMS (Short Message Service) or text messaging as the attack vector. You arrive at this answer because the scenario specifies a 'text message.' It targets mobile users who may be less likely to verify links than they are on a computer.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":137,"question":"Which security principle ensures that information is accessible only to authorized individuals?","options":["Confidentiality","Integrity","Availability","Non-repudiation"],"correctIndex":0,"explanation":"Confidentiality prevents unauthorized access to sensitive information.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":138,"question":"Which concept ensures that data has not been altered, tampered with, or modified?","options":["Integrity","Confidentiality","Availability","Authentication"],"correctIndex":0,"explanation":"Integrity ensures data remains accurate and unchanged unless modified by authorized users.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":139,"question":"Ensuring systems and data are accessible when needed is known as:","options":["Availability","Integrity","Confidentiality","Authorization"],"correctIndex":0,"explanation":"Availability ensures that systems and data remain usable and accessible.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":140,"question":"Which security goal prevents individuals from denying their actions?","options":["Non-repudiation","Confidentiality","Integrity","Availability"],"correctIndex":0,"explanation":"Non-repudiation ensures actions can be proven and cannot be denied later.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":141,"question":"What is the process of verifying a user’s identity?","options":["Authentication","Authorization","Accounting","Auditing"],"correctIndex":0,"explanation":"Authentication verifies that a user is who they claim to be.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":142,"question":"Which AAA component determines what a user is allowed to do?","options":["Authorization","Authentication","Accounting","Auditing"],"correctIndex":0,"explanation":"Authorization defines permissions and access rights after authentication.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":143,"question":"Which security control type includes firewalls and IDS/IPS?","options":["Technical controls","Managerial controls","Operational controls","Physical controls"],"correctIndex":0,"explanation":"Technical controls use technology to enforce security.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":144,"question":"Security guards, fences, and cameras are examples of:","options":["Physical controls","Technical controls","Managerial controls","Operational controls"],"correctIndex":0,"explanation":"Physical controls protect the physical environment and infrastructure.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":145,"question":"Policies, risk assessments, and security planning are examples of:","options":["Managerial controls","Technical controls","Physical controls","Corrective controls"],"correctIndex":0,"explanation":"Managerial controls focus on governance and risk management.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":146,"question":"Which control type attempts to stop an attack before it succeeds?","options":["Preventive","Detective","Corrective","Compensating"],"correctIndex":0,"explanation":"Preventive controls aim to block threats before they occur.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":147,"question":"Which control type identifies that an attack is occurring?","options":["Detective","Preventive","Corrective","Deterrent"],"correctIndex":0,"explanation":"Detective controls discover and alert on malicious activity.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":148,"question":"Which control type restores systems after an incident?","options":["Corrective","Preventive","Detective","Deterrent"],"correctIndex":0,"explanation":"Corrective controls help return systems to normal operation.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":149,"question":"What is the term for reducing risk to an acceptable level?","options":["Risk mitigation","Risk acceptance","Risk avoidance","Risk transference"],"correctIndex":0,"explanation":"Mitigation reduces the likelihood or impact of a risk.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":150,"question":"Cyber insurance is an example of which risk response?","options":["Risk transference","Risk mitigation","Risk acceptance","Risk avoidance"],"correctIndex":0,"explanation":"Transference shifts risk to a third party, such as an insurer.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":151,"question":"Which term describes the potential for loss or damage?","options":["Risk","Threat","Vulnerability","Impact"],"correctIndex":0,"explanation":"Risk is the likelihood that a threat will exploit a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":152,"question":"A weakness that can be exploited by a threat actor is known as a:","options":["Vulnerability","Risk","Threat","Impact"],"correctIndex":0,"explanation":"A vulnerability is a flaw or weakness that can be exploited.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":153,"question":"An individual or event that can exploit a vulnerability is called a:","options":["Threat","Risk","Impact","Control"],"correctIndex":0,"explanation":"A threat is any potential danger that can exploit a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":154,"question":"Which concept ensures that users only have the permissions they need to perform their job?","options":["Least privilege","Separation of duties","Defense in depth","Zero trust"],"correctIndex":0,"explanation":"Least privilege limits access to only what is necessary.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":155,"question":"Splitting critical tasks between multiple people is known as:","options":["Separation of duties","Least privilege","Job rotation","Mandatory vacations"],"correctIndex":0,"explanation":"Separation of duties prevents fraud and misuse by dividing responsibilities.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":156,"question":"Which principle uses multiple layers of security controls?","options":["Defense in depth","Zero trust","Least privilege","Separation of duties"],"correctIndex":0,"explanation":"Defense in depth uses layered security to reduce risk.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":157,"question":"Which model assumes no user or device is trusted by default?","options":["Zero trust","Defense in depth","Least privilege","Mandatory access control"],"correctIndex":0,"explanation":"Zero trust requires continuous verification of all users and devices.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":158,"question":"Which access control model uses labels such as 'Top Secret' and 'Confidential'?","options":["Mandatory Access Control (MAC)","Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)","Attribute-Based Access Control (ABAC)"],"correctIndex":0,"explanation":"MAC uses security labels and strict centralized control.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":159,"question":"Which access control model assigns permissions based on job functions?","options":["RBAC","MAC","DAC","ABAC"],"correctIndex":0,"explanation":"Role-Based Access Control assigns permissions based on roles.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":160,"question":"Which access control model allows resource owners to determine access?","options":["DAC","MAC","RBAC","ABAC"],"correctIndex":0,"explanation":"DAC gives owners control over who can access their resources.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":161,"question":"Which access control model uses policies based on attributes such as location or device type?","options":["ABAC","RBAC","MAC","DAC"],"correctIndex":0,"explanation":"ABAC uses attributes to dynamically determine access.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":162,"question":"Which term describes the likelihood that a threat will exploit a vulnerability?","options":["Risk","Impact","Threat","Exposure"],"correctIndex":0,"explanation":"Risk is the probability of a threat exploiting a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":163,"question":"Which concept ensures that logs and audit trails accurately reflect user actions?","options":["Accountability","Authentication","Authorization","Integrity"],"correctIndex":0,"explanation":"Accountability ties actions to specific users through logging.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":164,"question":"Which security concept ensures that systems continue operating even during failures?","options":["Fault tolerance","Integrity","Non-repudiation","Authentication"],"correctIndex":0,"explanation":"Fault tolerance uses redundancy to maintain availability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":165,"question":"Which term describes the total harm or damage caused by a security incident?","options":["Impact","Risk","Threat","Exposure"],"correctIndex":0,"explanation":"Impact measures the severity of a security incident.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":166,"question":"Which concept involves verifying both the identity and integrity of a device before granting access?","options":["Device authentication","Zero trust","Least privilege","MAC"],"correctIndex":0,"explanation":"Device authentication ensures the device is trusted and uncompromised.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":167,"question":"Which cryptographic property ensures that data has not been altered between sender and receiver?","options":["Confidentiality","Integrity","Availability","Obfuscation"],"correctIndex":1,"explanation":"Integrity ensures that data remains unmodified; hashing and digital signatures are common mechanisms.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":168,"question":"Which of the following is a symmetric block cipher commonly used for VPNs and full-disk encryption?","options":["RSA","ECC","AES","Diffie-Hellman"],"correctIndex":2,"explanation":"AES is a symmetric block cipher widely used for VPNs, disk encryption, and many other secure applications.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":169,"question":"A company wants to securely exchange a symmetric key over an insecure channel. Which algorithm is BEST suited?","options":["AES","Diffie-Hellman","SHA-256","MD5"],"correctIndex":1,"explanation":"Diffie-Hellman is designed for secure key exchange over an insecure channel.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":170,"question":"Which of the following is primarily used to provide non-repudiation?","options":["Symmetric encryption","Hashing","Digital signatures","Steganography"],"correctIndex":2,"explanation":"Digital signatures provide integrity, authentication, and non-repudiation by binding a signer to the message.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":171,"question":"Which hashing algorithm is considered broken and should NOT be used for security purposes?","options":["SHA-256","SHA-3","MD5","BLAKE2"],"correctIndex":2,"explanation":"MD5 is vulnerable to collisions and is no longer considered secure for cryptographic use.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":172,"question":"Which concept describes adding random data to a password before hashing to defend against rainbow table attacks?","options":["Key stretching","Salting","Peppering","Key escrow"],"correctIndex":1,"explanation":"Salting adds unique random data to each password before hashing, making precomputed tables ineffective.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":173,"question":"Which of the following BEST describes perfect forward secrecy (PFS)?","options":["Using the same key for encryption and decryption","Ensuring that compromise of a long-term key does not compromise past session keys","Using a longer key length than required","Encrypting data at rest and in transit"],"correctIndex":1,"explanation":"PFS ensures that even if a long-term key is compromised, past session keys remain secure.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":174,"question":"Which protocol is commonly used to provide secure email with digital signatures and encryption?","options":["S/MIME","SNMPv3","SRTP","FTPS"],"correctIndex":0,"explanation":"S/MIME provides secure email with encryption and digital signatures using X.509 certificates.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":175,"question":"Which of the following is an example of asymmetric encryption?","options":["AES-256","3DES","RSA","ChaCha20"],"correctIndex":2,"explanation":"RSA is a widely used asymmetric (public key) cryptographic algorithm.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":176,"question":"A security engineer needs to verify that a downloaded file has not been tampered with. Which is the BEST method?","options":["Compare the file size","Check the file's digital signature or hash","Open the file and visually inspect it","Re-download the file from another mirror"],"correctIndex":1,"explanation":"Verifying a cryptographic hash or digital signature ensures the file's integrity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":177,"question":"Which of the following is a key stretching algorithm commonly used for password hashing?","options":["PBKDF2","RSA","Diffie-Hellman","SHA-1"],"correctIndex":0,"explanation":"PBKDF2 is a key stretching algorithm that applies a hash function many times to slow down brute-force attacks.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":178,"question":"Which cryptographic concept ensures that the same plaintext will not always produce the same ciphertext?","options":["Initialization vector (IV)","Key escrow","Key wrapping","Certificate pinning"],"correctIndex":0,"explanation":"An IV introduces randomness so that identical plaintexts encrypt to different ciphertexts.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":179,"question":"Which of the following BEST describes a digital certificate?","options":["A symmetric key used for bulk encryption","A signed binding between a public key and an identity","A random number used for key generation","A hardware token used for MFA"],"correctIndex":1,"explanation":"A digital certificate binds a public key to an identity and is signed by a CA.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":180,"question":"Which access control model uses labels such as 'Secret' and 'Top Secret' and enforces access based on clearance?","options":["Discretionary Access Control (DAC)","Mandatory Access Control (MAC)","Role-Based Access Control (RBAC)","Rule-Based Access Control"],"correctIndex":1,"explanation":"MAC uses labels and clearances, with access decisions enforced by a central authority.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":181,"question":"In Role-Based Access Control (RBAC), permissions are primarily assigned to:","options":["Users directly","Roles","Objects","Networks"],"correctIndex":1,"explanation":"In RBAC, permissions are assigned to roles, and users are assigned to those roles.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":182,"question":"Which of the following is an example of something you HAVE in multifactor authentication?","options":["Password","PIN","Smart card","Fingerprint"],"correctIndex":2,"explanation":"A smart card is a physical token and represents 'something you have'.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":183,"question":"Which protocol is commonly used for centralized authentication, authorization, and accounting for network devices?","options":["RADIUS","DNSSEC","SFTP","NTP"],"correctIndex":0,"explanation":"RADIUS provides centralized AAA services for network access and devices.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 2.html"},{"id":184,"question":"Which protocol is often used for secure, ticket-based authentication in Windows domains?","options":["TACACS+","Kerberos","LDAP","SAML"],"correctIndex":1,"explanation":"Kerberos uses tickets and symmetric cryptography for secure authentication in domains.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":185,"question":"Which of the following BEST describes single sign-on (SSO)?","options":["Using multiple passwords for different systems","Using one set of credentials to access multiple systems","Using a hardware token for every login","Using a local account instead of a domain account"],"correctIndex":1,"explanation":"SSO allows a user to authenticate once and gain access to multiple systems or applications.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":186,"question":"Which standard is commonly used to provide federated identity and SSO between organizations using XML-based assertions?","options":["SAML","OAuth 2.0","OpenID Connect","RADIUS"],"correctIndex":0,"explanation":"SAML uses XML-based assertions for federated identity and SSO between identity and service providers.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 2.html"},{"id":187,"question":"Which of the following is MOST associated with authorization of API calls and delegated access?","options":["SAML","OAuth 2.0","Kerberos","CHAP"],"correctIndex":1,"explanation":"OAuth 2.0 is commonly used for delegated authorization, especially for APIs.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":188,"question":"Which identity concept describes a centralized directory that stores user accounts and attributes?","options":["RADIUS","LDAP directory","TACACS+ server","NTP server"],"correctIndex":1,"explanation":"LDAP directories (like Active Directory) store user accounts, groups, and attributes centrally.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":189,"question":"A security team wants to enforce that users only have the minimum permissions necessary to perform their jobs. This is an example of:","options":["Separation of duties","Job rotation","Least privilege","Mandatory vacations"],"correctIndex":2,"explanation":"Least privilege ensures users have only the access they need and no more.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":190,"question":"Which of the following BEST describes separation of duties?","options":["Requiring two people to approve all changes","Ensuring that critical tasks are divided among multiple people","Rotating employees through different roles","Requiring strong passwords"],"correctIndex":1,"explanation":"Separation of duties divides critical tasks so no single person can complete them alone, reducing fraud risk.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":191,"question":"Which authentication factor category does a retina scan fall under?","options":["Something you know","Something you have","Something you are","Somewhere you are"],"correctIndex":2,"explanation":"Biometric identifiers like retina scans are 'something you are'.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":192,"question":"Which of the following is a common risk of using shared accounts?","options":["Improved accountability","Simplified auditing","Lack of non-repudiation","Stronger authentication"],"correctIndex":2,"explanation":"Shared accounts make it difficult to attribute actions to a specific individual, reducing accountability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 2.html"},{"id":193,"question":"Which cryptographic attack attempts to find two different inputs that produce the same hash value?","options":["Brute-force attack","Collision attack","Birthday attack","Replay attack"],"correctIndex":1,"explanation":"A collision attack aims to find two distinct inputs with the same hash output.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":194,"question":"Which of the following is MOST appropriate for encrypting large amounts of data on a storage device?","options":["RSA","ECC","AES","DSA"],"correctIndex":2,"explanation":"AES, a symmetric cipher, is efficient and commonly used for bulk data encryption such as full-disk encryption.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":195,"question":"Which identity and access management concept ensures that user access is reviewed and adjusted when roles change?","options":["Onboarding","Offboarding","Access recertification (account review)","Password rotation"],"correctIndex":2,"explanation":"Access recertification periodically reviews user access to ensure it still aligns with job responsibilities.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":196,"question":"Which of the following BEST describes just-in-time (JIT) access?","options":["Permanent elevated privileges for administrators","Granting elevated access only when needed and for a limited time","Using shared admin accounts","Using static passwords for service accounts"],"correctIndex":1,"explanation":"JIT access provides temporary, time-bound elevated privileges only when required, reducing risk.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":197,"question":"Which architectural approach most effectively limits lateral movement by enforcing granular communication rules between internal workloads?","options":["Microsegmentation using workload-level policy enforcement boundaries","Static VLAN assignments based solely on switch port groupings","Perimeter filtering that relies on a single external firewall layer","Flat network routing that forwards internal traffic without restrictions"],"correctIndex":0,"explanation":"Microsegmentation enforces fine-grained controls between workloads, reducing lateral movement opportunities.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 3.html"},{"id":198,"question":"In a three-tier application design, which component should be placed in the most restrictive network zone to minimize exposure?","options":["Database tier containing sensitive structured application data","Presentation tier responsible for handling external client requests","Load balancing tier distributing inbound session traffic","DNS resolution tier providing general name lookup services"],"correctIndex":0,"explanation":"The database tier contains sensitive data and requires the strongest isolation.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":199,"question":"Which design pattern describes placing public-facing systems in a controlled zone between internal and external networks?","options":["DMZ architecture using screened subnets between firewall layers","Single-segment architecture with unified internal routing","Mesh topology allowing unrestricted peer-to-peer connectivity","Legacy perimeter model relying solely on NAT for protection"],"correctIndex":0,"explanation":"A DMZ isolates public systems to reduce risk to internal networks.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 3.html"},{"id":200,"question":"Which traffic pattern is characterized by communication between internal systems rather than inbound or outbound flows?","options":["East-west traffic moving laterally between internal workloads","North-south traffic moving between clients and external services","Transit traffic routed between remote branch locations","Overlay traffic encapsulated for tunneling across WAN links"],"correctIndex":0,"explanation":"East-west traffic refers to lateral internal communication.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":201,"question":"Which control is most appropriate for enforcing policy boundaries between internal network segments?","options":["Internal firewalls applying granular inter-segment filtering rules","Layer 2 switches forwarding frames based on MAC learning","Hubs broadcasting all frames to every connected interface","Repeaters regenerating signals without traffic inspection"],"correctIndex":0,"explanation":"Internal firewalls enforce segmentation and policy boundaries.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 3.html"},{"id":202,"question":"Which design choice best supports high availability for critical perimeter security devices?","options":["Redundant firewall pairs configured for synchronized failover","Single high-capacity firewall with enhanced throughput settings","Distributed endpoint firewalls replacing network-level filtering","Perimeter filtering performed only at upstream ISP routers"],"correctIndex":0,"explanation":"Redundant firewall pairs ensure continuity during device failure.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":203,"question":"Which architectural principle ensures that a single component failure does not disrupt overall service availability?","options":["Fault-tolerant design using redundant and resilient components","Minimalist design using a single consolidated service instance","Prototype design relying on experimental hardware modules","Legacy design using monolithic centralized infrastructure"],"correctIndex":0,"explanation":"Fault tolerance ensures continued operation despite component failures.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":204,"question":"Which architectural model emphasizes continuous verification and localized enforcement rather than implicit internal trust?","options":["Zero trust architecture with distributed access validation","Perimeter-centric architecture relying on external firewalls","Implicit trust architecture assuming internal traffic is safe","Best-effort architecture using broad shared access policies"],"correctIndex":0,"explanation":"Zero trust removes implicit trust and enforces continuous verification.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":205,"question":"Which system is used to centralize administrative access into sensitive management networks?","options":["Jump server providing controlled entry to management segments","Caching proxy accelerating outbound web browsing requests","Wireless controller managing guest network associations","Public web server hosting external customer applications"],"correctIndex":0,"explanation":"Jump servers centralize and secure administrative access.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":206,"question":"Which design element is most important when building a secure management network for infrastructure devices?","options":["Out-of-band management network isolated from user traffic paths","Shared VLAN carrying both user and administrative traffic","Public internet path used for remote administrative sessions","Guest wireless network temporarily used for device management"],"correctIndex":0,"explanation":"OOB networks isolate management traffic for security and reliability.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":207,"question":"Which component accepts client requests and forwards them to internal application servers while masking backend details?","options":["Reverse proxy providing controlled access to internal services","NAT gateway translating outbound private address traffic","Layer 2 switch forwarding frames based on learned MAC tables","Routing appliance advertising default routes to internal hosts"],"correctIndex":0,"explanation":"Reverse proxies protect backend servers and manage client requests.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 3.html"},{"id":208,"question":"Which deployment model distributes application components across multiple geographically separated sites for resilience?","options":["Active-active multi-site architecture with synchronized workloads","Single-site architecture with centralized monolithic services","Branch-only architecture with isolated local deployments","Ad hoc architecture using unmanaged local installations"],"correctIndex":0,"explanation":"Active-active multi-site deployments improve resilience and availability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":209,"question":"Which principle is applied when service accounts are restricted to only the permissions required for their specific tasks?","options":["Least privilege applied to system and service accounts","Implicit trust applied to authenticated internal accounts","Open access applied to shared administrative credentials","Full control applied to all authenticated user identities"],"correctIndex":0,"explanation":"Least privilege limits permissions to reduce risk of compromise.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 3.html"},{"id":210,"question":"Which concept describes applying fine-grained security controls between individual workloads in a virtualized environment?","options":["Microsegmentation using workload-specific policy boundaries","Static VLAN segmentation based on physical switch ports","Perimeter filtering using a single external firewall layer","Legacy segmentation relying on broad trust zones internally"],"correctIndex":0,"explanation":"Microsegmentation enforces granular controls between workloads.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 3.html"},{"id":211,"question":"Which method best supports secure remote administration over untrusted networks?","options":["VPN tunnels using strong authentication and encrypted sessions","Telnet access permitted from any external network location","HTTP-based management exposed on public interfaces","Open wireless networks used for administrative connectivity"],"correctIndex":0,"explanation":"VPNs protect administrative traffic with encryption and authentication.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":212,"question":"Which component enforces application-layer security policies by inspecting and filtering HTTP traffic?","options":["Web application firewall analyzing inbound and outbound requests","Layer 2 switch forwarding frames based on MAC addresses","Network hub repeating traffic to all connected devices","Patch panel providing passive cable termination points"],"correctIndex":0,"explanation":"WAFs enforce application-layer protections.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 3.html"},{"id":213,"question":"Which principle is demonstrated by using multiple independent security controls to protect the same asset?","options":["Defense in depth using layered and overlapping safeguards","Single-layer protection relying on one primary control","Implicit trust assuming internal traffic is inherently safe","Best-effort security using loosely defined control placement"],"correctIndex":0,"explanation":"Defense in depth ensures redundancy across security layers.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 3.html"},{"id":214,"question":"Which solution evaluates device posture before granting network access?","options":["Network access control validating compliance before connection","Log aggregation system storing long-term audit records","Identity provider managing cloud authentication workflows","Email encryption gateway securing internal message flows"],"correctIndex":0,"explanation":"NAC evaluates device posture and compliance.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":215,"question":"Which design choice best supports isolation between tenants in a cloud environment?","options":["Separate virtual networks and security groups per tenant","Shared flat network segment for all tenant workloads","Unrestricted routing between tenant environments","Single administrative account shared across all tenants"],"correctIndex":0,"explanation":"Tenant isolation requires separate virtual networks and policies.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":216,"question":"Which component distributes client requests across multiple backend servers to improve availability?","options":["Load balancer directing traffic using defined distribution logic","Network tap passively copying traffic for monitoring tools","Patch panel connecting cables between racks and switches","Console server providing serial access to infrastructure devices"],"correctIndex":0,"explanation":"Load balancers distribute traffic to improve performance and uptime.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":217,"question":"Which principle is applied when development, testing, and production environments are separated?","options":["Environment separation reducing risk of unintended production impact","Unified environment simplifying deployment and configuration","Shared environment maximizing resource utilization only","Ad hoc environment supporting rapid experimental changes"],"correctIndex":0,"explanation":"Environment separation prevents development activities from affecting production.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":218,"question":"Which system is intentionally hardened and exposed to untrusted networks to provide controlled access?","options":["Bastion host designed to withstand targeted external attacks","Unmanaged workstation used for general internet browsing","Legacy server running outdated operating system versions","Guest kiosk used for temporary visitor access"],"correctIndex":0,"explanation":"Bastion hosts are hardened for exposure to untrusted networks.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":219,"question":"Which design choice best supports secure logging and monitoring across distributed infrastructure?","options":["Centralized log aggregation with secure forwarding mechanisms","Local log storage only with no centralized collection","Manual review of logs stored on individual devices","Unencrypted log transmission across public network paths"],"correctIndex":0,"explanation":"Centralized logging enables correlation and secure retention.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":220,"question":"Which architecture uses small, independently deployable services that communicate through APIs?","options":["Microservices architecture with loosely coupled components","Monolithic architecture using a single large application","Mainframe architecture with centralized batch processing","Client-server architecture using thick desktop clients"],"correctIndex":0,"explanation":"Microservices improve scalability and resilience.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":221,"question":"Which principle is applied when unnecessary services and open ports are removed from an internet-facing server?","options":["Attack surface reduction through service minimization","Implicit trust through broad internal service exposure","Open access through unrestricted service publication","Best-effort security using default service configurations"],"correctIndex":0,"explanation":"Reducing exposed services minimizes the number of potential attack vectors.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"Sec + Day 3.html"},{"id":222,"question":"Which option best describes the role of a CASB in a cloud-centric architecture?","options":["Broker enforcing security policies between users and cloud services","Device providing physical connectivity between racks and switches","Appliance used solely for encrypting local storage volumes","Server dedicated to running on-premises directory services"],"correctIndex":0,"explanation":"CASBs enforce policy and visibility between users and cloud applications.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":223,"question":"Which design choice best supports secure integration between on-premises infrastructure and public cloud resources?","options":["Using dedicated VPN or private connectivity with strong authentication","Allowing unrestricted public internet access to internal services","Using open wireless networks to bridge cloud and on-premises","Relying on unsecured legacy protocols for all connectivity"],"correctIndex":0,"explanation":"VPN or private links secure hybrid connectivity.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + Day 3.html"},{"id":224,"question":"Which architecture component is primarily responsible for isolating broadcast domains within a switched network?","options":["Router or Layer 3 switch performing inter-VLAN routing functions","Hub broadcasting all inbound frames to every connected interface","Patch panel providing passive cable termination for copper links","Network tap duplicating traffic streams for monitoring systems"],"correctIndex":0,"explanation":"Routers and Layer 3 switches isolate broadcast domains by routing between VLANs.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":225,"question":"Which design principle is applied when critical security functions are distributed across separate dedicated components rather than consolidated into a single device?","options":["Separation of duties across distinct and independently controlled systems","Centralized control using one unified multi-purpose appliance","Implicit trust model allowing broad administrative privileges","Best-effort security relying on default hardware configurations"],"correctIndex":0,"explanation":"Separating duties across components reduces risk and avoids a single point of failure.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":226,"question":"Which option best describes the purpose of a secure enclave within an enterprise architecture?","options":["Isolated environment designed to protect highly sensitive workloads","Shared environment used for general-purpose user applications","Legacy environment used for unsupported operating systems","Guest environment used for temporary visitor access only"],"correctIndex":0,"explanation":"A secure enclave provides enhanced isolation and controls for highly sensitive data and workloads.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":227,"question":"A security team needs a recurring method to identify missing patches and insecure configurations across all managed servers. Which approach best supports this requirement?","options":["Use credentialed vulnerability scans to validate configuration states across all managed systems.","Rely on periodic log reviews to identify configuration drift across production workloads.","Deploy agentless discovery tools that highlight network‑visible weaknesses during routine sweeps.","Analyze firewall rule changes to detect potential exposure created by misaligned access paths."],"correctIndex":0,"explanation":"Credentialed scans provide deeper visibility into host‑level settings and patch status.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 4.html"},{"id":228,"question":"A company wants to safely verify whether identified weaknesses can actually be exploited in a controlled environment. Which approach best meets this objective?","options":["Conduct targeted penetration testing to confirm whether identified weaknesses are practically exploitable.","Review historical incident reports to determine whether similar vulnerabilities were exploited previously.","Use passive monitoring tools to observe abnormal behavior without interacting with the system.","Rely on automated patch deployment to mitigate weaknesses before validation occurs."],"correctIndex":0,"explanation":"Penetration testing validates whether a vulnerability can be exploited under real conditions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 4.html"},{"id":229,"question":"A critical remote code execution flaw is discovered on a public web server. Which factor most increases the urgency of addressing this vulnerability?","options":["The system is directly internet‑facing and accessible to unauthenticated external attackers.","The server hosts non‑sensitive content that rarely changes during normal operations.","The vulnerability requires multiple chained conditions before exploitation is possible.","The system is monitored by a SIEM that alerts on suspicious inbound traffic."],"correctIndex":0,"explanation":"Internet‑facing systems are at significantly higher risk because attackers can reach them directly.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 4.html"},{"id":230,"question":"A security analyst is reviewing a vulnerability scoring report and wants to understand how easily an attacker could exploit a weakness. Which focus best supports this analysis?","options":["Evaluate exploitability metrics such as attack vector, complexity, and required privileges.","Prioritize vulnerabilities based solely on the age of the published advisory.","Review system uptime statistics to determine how frequently services restart.","Analyze user login frequency to estimate potential exposure to credential misuse."],"correctIndex":0,"explanation":"Exploitability metrics indicate how easily an attacker can leverage a vulnerability.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":231,"question":"A vulnerability with a high severity score is found on an isolated lab system with no production connectivity. Which concept best explains why remediation may be deprioritized?","options":["The system’s limited exposure reduces the likelihood of meaningful exploitation attempts.","The vulnerability is unlikely to generate alerts within centralized monitoring tools.","The system’s hardware lifecycle is nearing end‑of‑support within the next year.","The vulnerability affects only optional features not enabled on the system."],"correctIndex":0,"explanation":"Risk is influenced by exposure; isolated systems present far less opportunity for exploitation.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":232,"question":"After a vulnerability scan completes, several new findings are identified on production systems. Which step should occur next in a formal vulnerability management process?","options":["Prioritize the findings based on severity, asset value, and operational impact.","Immediately deploy patches to all affected systems without further evaluation.","Archive the scan results for long‑term compliance reporting requirements.","Disable network access to all systems showing new vulnerabilities."],"correctIndex":0,"explanation":"Triage ensures vulnerabilities are addressed in an order aligned with business risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"Sec + Day 4.html"},{"id":233,"question":"A security engineer notices that some vulnerabilities are not being detected on systems that are known to be unpatched. Which scanning characteristic is most likely contributing to these false negatives?","options":["The scans are running without authentication, limiting visibility into host‑level details.","The scans are scheduled too frequently, causing incomplete data collection cycles.","The scanner is configured to ignore informational findings during routine assessments.","The network uses redundant routing paths that obscure endpoint identification."],"correctIndex":0,"explanation":"Unauthenticated scans often miss vulnerabilities that require deeper system access to detect.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":234,"question":"A team wants to ensure that newly deployed virtual machines consistently follow a hardened baseline before entering production. Which approach best supports this objective?","options":["Use standardized system images that enforce consistent baseline configurations across deployments.","Allow administrators to manually configure each system according to documented guidelines.","Enable automatic updates to apply patches immediately after system installation.","Perform quarterly audits to verify whether deployed systems match expected configurations."],"correctIndex":0,"explanation":"Standardized images ensure new systems start with a consistent, hardened configuration.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":235,"question":"An application relies heavily on third-party libraries. The security team wants to reduce the risk of vulnerabilities introduced through these components. Which approach is most appropriate?","options":["Track and update third‑party components using a structured dependency management process.","Disable all optional features within the application to reduce its overall attack surface.","Increase logging verbosity to detect abnormal behavior caused by outdated libraries.","Restrict outbound network access to prevent libraries from communicating externally."],"correctIndex":0,"explanation":"Dependency management ensures third‑party components remain updated and free of known vulnerabilities.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"Sec + Day 4.html"},{"id":236,"question":"A medium-severity vulnerability is identified on a mission-critical database that stores regulated data. Which consideration could justify treating this as a higher-priority issue?","options":["The system stores sensitive regulated data that increases the impact of potential compromise.","The vulnerability affects a feature that is rarely used during normal operations.","The system is hosted on hardware nearing its scheduled replacement cycle.","The database is backed up daily using encrypted storage mechanisms."],"correctIndex":0,"explanation":"Data sensitivity increases the potential impact, raising the priority of remediation.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":237,"question":"A workstation fleet is being reviewed to reduce the overall attack surface. Which approach most directly supports this goal?","options":["Restrict which applications can run by enforcing approved software execution policies.","Increase system logging levels to capture more detailed operational activity.","Extend patch deployment windows to reduce disruption during business hours.","Enable remote desktop access for administrators to streamline maintenance tasks."],"correctIndex":0,"explanation":"Application control reduces the attack surface by limiting unauthorized software execution.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"Sec + Day 4.html"},{"id":238,"question":"A security architect wants to prevent unauthorized code from running during system startup on corporate laptops. Which approach best addresses this requirement?","options":["Enable secure boot mechanisms that validate trusted components during system initialization.","Require multi‑factor authentication before users can access the operating system.","Encrypt the system drive to protect data stored on the device.","Disable unused hardware ports to limit opportunities for physical tampering."],"correctIndex":0,"explanation":"Secure boot ensures only trusted components load during system startup.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":239,"question":"A security program wants to define how quickly vulnerabilities must be remediated based on severity. Which type of guidance should describe these expectations?","options":["Document remediation timelines within formal vulnerability management policy requirements.","Store remediation expectations in archived audit reports for future reference.","Communicate remediation expectations informally during team meetings and briefings.","Include remediation expectations within optional training materials for administrators."],"correctIndex":0,"explanation":"Policies define required remediation timelines and establish organizational expectations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 4.html"},{"id":240,"question":"Different administrators are interpreting vulnerability scan results in inconsistent ways, leading to uneven remediation. Which approach best improves consistency?","options":["Adopt standardized criteria for interpreting vulnerability severity and required actions.","Allow each team to determine its own remediation priorities based on workload.","Increase scan frequency to ensure more up‑to‑date vulnerability information.","Disable low‑severity findings to reduce the number of items requiring review."],"correctIndex":0,"explanation":"Standardized interpretation ensures consistent remediation decisions across teams.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":241,"question":"Users sometimes access corporate resources from unmanaged or shared devices. The organization wants to limit the risk of credential theft on those endpoints. Which approach is most appropriate?","options":["Provide isolated virtual desktop environments that prevent sensitive activity on untrusted devices.","Require users to rotate passwords more frequently when using shared devices.","Disable all remote access capabilities to prevent connections from unmanaged systems.","Allow browser‑based access only when users acknowledge additional security warnings."],"correctIndex":0,"explanation":"Virtual desktops isolate corporate activity from untrusted or unmanaged endpoints.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + Day 4.html"},{"id":242,"question":"A known vulnerability exists on a production server. The organization wants to reduce the likelihood that this weakness will be exploited. Which approach is most effective?","options":["Apply the appropriate patch to eliminate the underlying vulnerability on the system.","Increase monitoring frequency to detect suspicious activity targeting the system.","Restrict user login hours to reduce opportunities for unauthorized access attempts.","Disable non‑essential services to reduce the number of running processes."],"correctIndex":0,"explanation":"Patching directly removes the vulnerability, reducing the likelihood of exploitation.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":243,"question":"A vulnerability report indicates that a service is using deprecated cipher suites. Which approach best addresses this issue?","options":["Update the service configuration to use modern, supported cryptographic algorithms.","Increase key rotation frequency to compensate for weaker encryption strength.","Enable additional logging to capture details about encrypted session activity.","Restrict access to the service to reduce exposure to external users."],"correctIndex":0,"explanation":"Replacing deprecated cipher suites ensures secure, modern cryptographic protection.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":244,"question":"Several servers with the same intended role show different security settings and patch levels. Which issue is most likely occurring?","options":["Configuration drift is causing systems to deviate from their expected baseline state.","The servers are using incompatible hardware that prevents consistent patching.","The systems are receiving excessive updates that exceed vendor recommendations.","The servers are assigned to different network segments with varying access rules."],"correctIndex":0,"explanation":"Configuration drift occurs when systems diverge from their intended baseline.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":245,"question":"A compromised user account should have limited ability to affect other computing resources. Which approach best supports this objective?","options":["Enforce least‑privilege access controls to limit what each account can perform.","Require users to authenticate more frequently during normal business operations.","Enable verbose logging to capture detailed user activity across all systems.","Increase password complexity requirements for all user accounts."],"correctIndex":0,"explanation":"Least‑privilege access limits the impact of a compromised account.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":246,"question":"After remediation work is completed for a critical vulnerability, the security team wants to confirm that the issue is no longer present. Which approach is most appropriate?","options":["Perform a follow‑up scan to verify that the vulnerability has been resolved.","Review patch notes to confirm that the update addressed the vulnerability.","Monitor system logs for several days to ensure no related alerts appear.","Request user feedback to determine whether system behavior has improved."],"correctIndex":0,"explanation":"Follow‑up scanning confirms whether remediation successfully removed the vulnerability.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":247,"question":"An organization wants to reduce the chance that malware will exploit unpatched software on endpoints. Which approach best supports this goal?","options":["Ensure endpoint applications receive timely updates through a structured patch management process.","Increase antivirus scan frequency to detect malware before it becomes active.","Restrict user access to administrative tools during normal business operations.","Enable detailed event logging to capture suspicious activity across all endpoints."],"correctIndex":0,"explanation":"Regular patching reduces the number of exploitable software vulnerabilities on endpoints.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":248,"question":"Business priorities and threat landscapes change over time. Which approach best ensures that vulnerability management activities remain aligned with these changes?","options":["Conduct periodic reviews to adjust vulnerability priorities based on updated business needs.","Increase the number of vulnerability scans performed each week for better visibility.","Assign remediation tasks to whichever team has the most available resources.","Disable low‑severity findings to reduce the volume of items requiring review."],"correctIndex":0,"explanation":"Regular reviews ensure vulnerability priorities reflect current business and threat conditions.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":249,"question":"A workstation image includes several legacy services that are not required for business operations. Which approach best reduces potential vulnerabilities from these services?","options":["Remove unnecessary services through a hardened baseline to reduce the attack surface.","Increase system monitoring to detect unusual activity associated with legacy components.","Restrict outbound network access to prevent legacy services from communicating externally.","Schedule quarterly audits to verify whether legacy components remain active."],"correctIndex":0,"explanation":"Hardening eliminates unnecessary services, reducing exposure to avoidable vulnerabilities.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"Sec + Day 4.html"},{"id":250,"question":"Laptops used by employees may be lost or stolen. The organization wants to protect the data stored on these devices. Which approach is most appropriate?","options":["Use full‑disk encryption to protect stored data if the device is lost or stolen.","Require users to change their passwords more frequently when traveling.","Disable USB ports to prevent unauthorized data transfers from the device.","Enable remote desktop access to reduce the need for local data storage."],"correctIndex":0,"explanation":"Full‑disk encryption protects data even if the physical device is compromised.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":251,"question":"Major infrastructure changes have recently been deployed. The security team wants to identify any new weaknesses introduced by these changes. Which approach is most suitable?","options":["Perform targeted vulnerability scans following major changes to detect newly introduced issues.","Delay scanning until the next scheduled assessment cycle to avoid operational disruption.","Rely on user reports to identify any unexpected behavior after the changes.","Increase firewall logging to capture unusual traffic patterns after deployment."],"correctIndex":0,"explanation":"Post‑change scanning identifies vulnerabilities introduced during infrastructure updates.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 4.html"},{"id":252,"question":"The security team wants to make it harder for attackers to exploit memory corruption vulnerabilities in applications. Which approach best supports this goal?","options":["Enable exploit‑mitigation features such as ASLR and DEP to reduce attack success.","Increase application logging to detect abnormal memory usage patterns.","Restrict user permissions to prevent unauthorized access to application files.","Require code reviews for all future software updates to improve quality."],"correctIndex":0,"explanation":"Exploit‑mitigation features make memory‑based attacks significantly harder to execute.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":253,"question":"A security team wants to ensure that only approved, hardened operating system builds are used for new servers. Which approach best enforces this requirement?","options":["Provision new servers using standardized, hardened images maintained by the security team.","Allow administrators to configure new servers manually using documented guidelines.","Require post‑deployment audits to verify whether servers meet baseline expectations.","Enable automatic updates to ensure servers receive patches immediately after deployment."],"correctIndex":0,"explanation":"Standardized hardened images ensure consistent, secure server deployments.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":254,"question":"A newly disclosed vulnerability is being actively exploited in environments similar to the organization’s infrastructure. Which factor most strongly indicates that this issue requires emergency remediation?","options":["Active exploitation in similar environments significantly increases the likelihood of attack.","The vulnerability affects a feature that is rarely used during normal operations.","The vendor has not yet released a patch for the vulnerability.","The vulnerability was published recently and has limited public documentation."],"correctIndex":0,"explanation":"Active exploitation indicates attackers are already targeting this vulnerability.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":255,"question":"After an initial compromise, the organization wants to limit the ability of malware to move laterally between systems. Which approach best supports this objective?","options":["Segment internal networks to restrict unauthorized movement between systems.","Increase password complexity requirements for all user accounts.","Enable verbose logging to capture detailed information about system interactions.","Require multi‑factor authentication for all internal administrative actions."],"correctIndex":0,"explanation":"Segmentation limits how far malware can spread after an initial compromise.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 4.html"},{"id":256,"question":"Leadership wants vulnerability management activities to be repeatable, measurable, and suitable for long-term improvement. Which approach best supports this requirement?","options":["Establish governance processes that define metrics, reporting, and continuous improvement goals.","Increase scan frequency to gather more data for long‑term analysis.","Assign remediation tasks to teams based on available staffing levels.","Store vulnerability reports indefinitely to maintain historical reference material."],"correctIndex":0,"explanation":"Governance establishes structure, metrics, and consistency for long‑term program maturity.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":257,"question":"Which monitoring platform aggregates logs and correlates alerts across enterprise security systems?","options":["Centralized SIEM analytics correlating multi source telemetry through behavioral detection engines","Endpoint configuration platform enforcing local device compliance through isolated host policies","Layer three routing device forwarding packets using static route configuration tables","Patch deployment service distributing vendor software updates through scheduled workflows"],"correctIndex":0,"explanation":"SIEM platforms aggregate and correlate logs.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":258,"question":"Which alerting technique reduces repetitive duplicate security notifications?","options":["Alert suppression consolidating recurring detections into grouped security notification events","Traffic mirroring duplicating packets toward dedicated analysis monitoring interfaces","Network segmentation dividing infrastructure through logical virtual LAN enforcement","Firmware lifecycle automation replacing outdated embedded device operating systems"],"correctIndex":0,"explanation":"Alert suppression reduces alert fatigue.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + Day 5.html"},{"id":259,"question":"Which monitoring solution analyzes endpoint behavior to detect suspicious runtime activity?","options":["Endpoint detection analytics monitoring processes through behavioral anomaly detection telemetry","Perimeter firewall inspection filtering inbound packets through static rule evaluation policies","Secure proxy service relaying outbound web traffic through content filtering mechanisms","System imaging platform deploying standardized workstation builds through automated scripts"],"correctIndex":0,"explanation":"EDR tools analyze endpoint behavior.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 5.html"},{"id":260,"question":"Which log source records authentication successes and failures from identity providers?","options":["Directory service audit logs documenting login attempts and authorization validation events","Wireless controller metrics tracking device roaming behavior across enterprise access points","Switch forwarding tables listing learned MAC addresses across physical network interfaces","Printer job queues recording completed printing activity across departmental resources"],"correctIndex":0,"explanation":"Directory logs record authentication activity.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 5.html"},{"id":261,"question":"Which monitoring practice validates alerts by correlating multiple telemetry sources?","options":["Event correlation comparing security data across diverse monitoring platforms for validation","Port scanning enumerating open services through sequential probing of network hosts","Configuration auditing verifying system baselines against regulatory compliance standards","Backup restoration testing validating disaster recovery procedures through scheduled simulations"],"correctIndex":0,"explanation":"Event correlation confirms suspicious activity.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + Day 5.html"},{"id":262,"question":"Which alert severity classification requires immediate containment response actions?","options":["Critical severity classification indicating confirmed malicious activity requiring urgent mitigation","Informational severity classification documenting normal operational system status messages","Low severity classification describing minor deviations unlikely to affect enterprise operations","Medium severity classification indicating suspicious activity requiring standard investigation"],"correctIndex":0,"explanation":"Critical alerts require immediate action.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 5.html"},{"id":263,"question":"Which monitoring method establishes normal activity baselines to identify anomalies?","options":["Behavioral analytics comparing current metrics against historical baseline performance thresholds","Signature inspection matching network packets against predefined threat detection rules","Manual log review analyzing archived events through periodic analyst investigation","Compliance scanning validating device configurations against industry benchmark templates"],"correctIndex":0,"explanation":"Behavioral analytics detect deviations from baselines.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":264,"question":"Which tool inspects packet captures to identify suspicious protocol anomalies?","options":["Network protocol analyzer dissecting captured traffic using deep packet inspection techniques","Endpoint configuration manager deploying standardized security baselines across enterprise devices","Federated identity service providing cross domain authentication through trust relationships","Database optimization engine restructuring queries to improve application performance"],"correctIndex":0,"explanation":"Protocol analyzers examine packet captures.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Sec + Day 5.html"},{"id":265,"question":"Which monitoring output occurs when detection rule conditions are met?","options":["Automated alert notification generated after predefined detection thresholds are exceeded","Maintenance schedule report documenting upcoming planned service downtime periods","Asset inventory export listing approved enterprise hardware and licensed software resources","Capacity forecast analysis predicting future storage utilization across production systems"],"correctIndex":0,"explanation":"Alerts are generated when rules trigger.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":266,"question":"Which alert tuning practice reduces false positives while maintaining detection coverage?","options":["Detection rule refinement adjusting thresholds using validated historical incident telemetry","Network expansion extending monitoring visibility into newly deployed organizational subnets","Backup retention modification altering archival storage lifecycle management policies","Encryption enforcement applying cryptographic protections across enterprise application traffic"],"correctIndex":0,"explanation":"Rule tuning reduces false positives.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 5.html"},{"id":267,"question":"Which monitoring platform identifies abnormal outbound traffic suggesting data exfiltration?","options":["Network traffic analysis engine evaluating outbound flows using behavioral anomaly detection models","Operating system hardening toolkit disabling unnecessary services across endpoint builds","Cloud orchestration system provisioning virtual machines during workload scaling operations","Wireless management controller optimizing signal distribution across office floor deployments"],"correctIndex":0,"explanation":"NTA tools detect abnormal outbound traffic.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + Day 5.html"},{"id":268,"question":"Which prioritization method ranks alerts based on potential organizational risk impact?","options":["Risk based prioritization scoring incidents using asset value and threat likelihood calculations","Chronological sorting arranging alerts based solely on timestamp order of occurrence","Alphabetical categorization organizing events through standardized naming conventions","Geographic grouping clustering alerts based on physical infrastructure deployment locations"],"correctIndex":0,"explanation":"Risk-based prioritization evaluates impact and likelihood.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + Day 5.html"},{"id":269,"question":"Which monitoring solution analyzes DNS queries to detect suspicious domains?","options":["DNS telemetry monitoring platform capturing query logs for anomaly detection analysis","Switch configuration utility modifying VLAN assignments across enterprise network infrastructure","Certificate authority server issuing digital certificates for encrypted communication channels","File compression utility reducing archive sizes for efficient long term storage management"],"correctIndex":0,"explanation":"DNS monitoring detects malicious domains.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 5.html"},{"id":270,"question":"Which detection approach compares file hashes against known malicious signatures?","options":["Signature based detection verifying file fingerprints against curated threat intelligence databases","Behavioral anomaly detection comparing runtime user activity against established usage baselines","Manual threat hunting analyzing historical telemetry through investigator driven research methods","Compliance monitoring validating configurations against published regulatory frameworks"],"correctIndex":0,"explanation":"Signature detection uses known malicious hashes.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 5.html"},{"id":271,"question":"Which monitoring capability detects abnormal privilege escalation attempts?","options":["User behavior analytics monitoring privilege changes through contextual access pattern analysis","Bandwidth optimization appliance compressing traffic streams to improve network performance","Disk defragmentation utility reorganizing storage sectors to improve read write efficiency","Time synchronization service aligning device clocks using centralized network protocols"],"correctIndex":0,"explanation":"UBA identifies abnormal privilege changes.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 5.html"},{"id":272,"question":"Which log source best detects unauthorized firewall configuration changes?","options":["Firewall administrative audit logs documenting rule modifications and configuration updates","Wireless interference reports measuring channel congestion across access point deployments","Printer usage metrics summarizing departmental printing activity across shared resources","Operating system boot records documenting workstation startup times across enterprise fleets"],"correctIndex":0,"explanation":"Firewall admin logs record configuration changes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 5.html"},{"id":273,"question":"Which alert suggests a brute force login attack against authentication services?","options":["Repeated failed authentication attempts exceeding predefined account lockout thresholds","Authorized software installation logs generated during scheduled enterprise deployment windows","Scheduled system restarts performed following approved patch management cycles","Routine vulnerability scans identifying outdated packages across managed production servers"],"correctIndex":0,"explanation":"Multiple login failures indicate brute force attacks.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":274,"question":"Which monitoring strategy detects lateral movement across internal networks?","options":["East west traffic monitoring analyzing internal communication patterns for abnormal behavior","North south filtering inspecting inbound internet traffic through perimeter gateway devices","Peripheral hardware inventory tracking authorized USB device usage across endpoints","Electrical consumption monitoring measuring power utilization across data center equipment"],"correctIndex":0,"explanation":"East-west monitoring identifies lateral movement.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":275,"question":"Which alert pattern indicates malware beaconing to command infrastructure?","options":["Consistent periodic outbound connections to a single external destination at regular intervals","Large enterprise software update downloads during approved scheduled maintenance windows","Short DNS query bursts generated during typical authenticated web browsing activities","Routine database synchronization uploads executed during automated nightly backup processes"],"correctIndex":0,"explanation":"Regular outbound communication indicates beaconing.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 5.html"},{"id":276,"question":"Which monitoring platform correlates vulnerability scan results with active threat alerts?","options":["Integrated security analytics platform combining vulnerability findings with real time event correlation","Desktop imaging system deploying standardized operating systems across enterprise endpoints","Load balancing appliance distributing incoming web traffic across redundant application servers","Virtual desktop infrastructure hosting remote sessions through centralized hypervisor clusters"],"correctIndex":0,"explanation":"Integrated analytics correlate vulnerabilities with alerts.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 5.html"},{"id":277,"question":"Which monitoring metric may indicate a denial of service attack?","options":["Sudden spike in inbound connections exceeding historical baseline network traffic patterns","Gradual increase in employee login frequency during normal operational business hours","Stable CPU utilization observed during predictable scheduled batch processing operations","Incremental storage growth caused by routine automated database backup archival"],"correctIndex":0,"explanation":"Traffic spikes suggest DoS attacks.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 5.html"},{"id":278,"question":"Which monitoring solution analyzes web application logs for injection attempts?","options":["Web application firewall analytics inspecting HTTP request payloads for malicious input patterns","Layer two switch monitoring system recording MAC address learning events across network ports","System temperature monitoring utility tracking hardware thermal performance across servers","Help desk ticketing system categorizing user support requests using standardized templates"],"correctIndex":0,"explanation":"WAF analytics detect injection attacks.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 5.html"},{"id":279,"question":"Which alert indicates possible data staging prior to exfiltration?","options":["Large sensitive files aggregated into temporary directories outside normal workflow patterns","Routine archive compression jobs executed during scheduled enterprise backup automation","Patch repository synchronization downloading update packages during maintenance windows","Operating system cache files expanding temporarily during high performance application execution"],"correctIndex":0,"explanation":"Unexpected file staging can indicate exfiltration preparation.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 5.html"},{"id":280,"question":"Which monitoring process proactively searches historical logs for hidden threats?","options":["Threat hunting analysis reviewing archived telemetry through hypothesis driven investigative methods","Routine log rotation archiving historical records to conserve available disk storage capacity","Configuration baseline enforcement applying standardized hardening policies across endpoints","Infrastructure provisioning automation deploying servers through predefined template scripts"],"correctIndex":0,"explanation":"Threat hunting proactively searches for hidden threats.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 5.html"},{"id":281,"question":"Which alert suggests insider threat behavior involving abnormal file access?","options":["User accessing large volumes of sensitive files outside established working hour patterns","Employee updating contact information through authorized human resource management portals","Administrator deploying approved system updates during scheduled maintenance operations","Department staff printing quarterly business reports during normal reporting cycle periods"],"correctIndex":0,"explanation":"Abnormal file access can indicate insider threats.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":282,"question":"Which monitoring technique detects impossible travel login scenarios?","options":["Geolocation anomaly detection comparing login timestamps against realistic travel duration thresholds","Password expiration enforcement requiring credential rotation through scheduled authentication policies","Certificate validation verifying encrypted sessions using trusted public key infrastructures","Disk quota monitoring limiting storage allocation across departmental shared file repositories"],"correctIndex":0,"explanation":"Impossible travel detection flags suspicious logins.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 5.html"},{"id":283,"question":"Which monitoring tool detects malicious scripts executed inside web browsers?","options":["Endpoint browser telemetry monitoring script execution using runtime behavioral anomaly detection","Network address translation gateway converting private addresses for outbound internet connectivity","Cloud billing dashboard summarizing monthly infrastructure resource consumption reports","System uptime tracker reporting availability metrics for business critical application services"],"correctIndex":0,"explanation":"Browser monitoring detects malicious scripts.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 5.html"},{"id":284,"question":"Which alert indicates unauthorized persistence mechanisms after reboot?","options":["Unapproved startup registry entries created outside authorized enterprise application deployment tools","Temporary diagnostic log files generated during scheduled system performance benchmarking","Driver updates installed automatically through vendor supported hardware update utilities","Group policy refresh operations applied across domain joined workstations during synchronization"],"correctIndex":0,"explanation":"Unauthorized startup entries indicate persistence.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 5.html"},{"id":285,"question":"Which monitoring approach correlates badge access logs with workstation login events?","options":["Context aware authentication analytics comparing physical entry records against digital login timestamps","Network throughput monitoring measuring bandwidth consumption across enterprise departments","Asset lifecycle management tracking procurement stages of new hardware inventory requests","Printer queue optimization distributing print jobs across multiple shared network print servers"],"correctIndex":0,"explanation":"Correlating physical and logical access improves detection.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":286,"question":"Which monitoring control analyzes cloud API activity for suspicious administrative behavior?","options":["Cloud activity monitoring platform evaluating API calls using anomaly detection and behavior baselines","Local disk monitoring utility tracking storage fragmentation levels across endpoint devices","Wireless signal survey tool mapping coverage strength across corporate office floor layouts","Environmental monitoring sensor measuring humidity levels inside data center facilities"],"correctIndex":0,"explanation":"Cloud monitoring detects suspicious API actions.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":287,"question":"1. Which incident response phase primarily focuses on limiting spread while investigation continues?","options":["Containment by isolating impacted hosts quickly","Preparation by updating runbooks and training staff","Recovery by returning services to production safely","Lessons learned by documenting process gaps clearly"],"correctIndex":0,"explanation":"Containment is intended to stop or limit damage and prevent further spread while analysis proceeds.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":288,"question":"2. A sudden spike in outbound traffic to unfamiliar IPs most strongly suggests which indicator?","options":["Normal telemetry uploading to trusted vendor endpoints","Data exfiltration or command-and-control callbacks","Routine patch distribution using content delivery nodes","Standard directory replication across internal servers"],"correctIndex":1,"explanation":"Unusual outbound connections—especially to unknown or rare destinations—commonly indicate C2 activity or exfiltration.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":289,"question":"3. Which activity is MOST associated with the lessons learned phase?","options":["Holding a post-incident review and updating playbooks","Restoring production services after removing malware","Capturing volatile memory before powering down hosts","Blocking suspicious domains at the secure web gateway"],"correctIndex":0,"explanation":"Lessons learned includes after-action reviews, documentation, and process improvements.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":290,"question":"4. Multiple failed logins followed by a successful login from the same source is a classic sign of:","options":["Credential stuffing or brute-force password attempts","Normal authentication retries during network latency","Scheduled account provisioning by identity services","Routine security scanning by approved assessment tools"],"correctIndex":0,"explanation":"Repeated failures followed by success can indicate password guessing or use of leaked credentials.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 6.html"},{"id":291,"question":"5. Which action best fits the eradication phase of incident response?","options":["Removing malware artifacts and patching the root flaw","Isolating affected network segments to stop propagation","Drafting the communications plan for stakeholders","Capturing baseline metrics for future event detection"],"correctIndex":0,"explanation":"Eradication removes the threat and addresses root causes (e.g., patching vulnerabilities, removing persistence).","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":292,"question":"6. Unexpected registry modifications that reappear after reboot most commonly indicate:","options":["Malware persistence using autorun or startup entries","Standard user profile synchronization across endpoints","Routine OS tuning applied by enterprise hardening tools","Normal application updates adjusting configuration keys"],"correctIndex":0,"explanation":"Persistence mechanisms often modify registry run keys or similar startup settings to survive reboots.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":293,"question":"7. The primary objective of the recovery phase is to:","options":["Return systems to operation with validated clean state","Identify the initial infection vector with certainty","Create IOCs and distribute them to threat feeds","Collect volatile memory and packet captures immediately"],"correctIndex":0,"explanation":"Recovery focuses on safely restoring services (often with monitoring and validation) after eradication.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Sec + Day 6.html"},{"id":294,"question":"8. Which item is an example of an Indicator of Compromise (IOC)?","options":["A known malicious file hash observed on an endpoint","A quarterly awareness training completion percentage","A documented acceptable use policy with revisions","A configuration baseline stored in a change system"],"correctIndex":0,"explanation":"IOCs include hashes, domains, IPs, registry keys, filenames, and other artifacts tied to malicious activity.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":295,"question":"9. Which solution is MOST commonly used to aggregate and correlate logs for incident analysis?","options":["Security Information and Event Management platform","Network Time Protocol synchronization service","Dynamic Host Configuration Protocol address manager","Simple Network Management Protocol polling engine"],"correctIndex":0,"explanation":"SIEMs centralize log ingestion and correlation to identify suspicious patterns across sources.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":296,"question":"10. Sustained high CPU usage caused by an unfamiliar process on many endpoints is a strong indicator of:","options":["Unauthorized cryptocurrency mining or resource hijacking","Normal endpoint compliance scanning during off-hours","Routine OS indexing and search optimization services","Approved software distribution pushing large updates"],"correctIndex":0,"explanation":"Cryptominers and some malware families cause notable CPU usage, especially when widespread.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 6.html"},{"id":297,"question":"11. A user reports that files were renamed and now have unfamiliar extensions, plus a ransom note appears. This indicates:","options":["Ransomware encrypting data and demanding payment","Standard disk compression performed by maintenance jobs","Normal file format conversion by productivity software","Authorized data archival and lifecycle management policy"],"correctIndex":0,"explanation":"Renamed/encrypted files and ransom notes are hallmark ransomware indicators.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 6.html"},{"id":298,"question":"12. Which artifact is MOST helpful for proving evidence integrity during a forensic process?","options":["Cryptographic hash values recorded for the evidence","A screenshot of the file directory showing timestamps","A printed copy of system information from the host","A list of installed applications exported to a text file"],"correctIndex":0,"explanation":"Hashes (e.g., SHA-256) help verify evidence has not changed during handling and analysis.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 6.html"},{"id":299,"question":"13. In incident response, chain of custody primarily ensures:","options":["Documentation of evidence handling from start to finish","Automatic restoration of systems using trusted backups","Immediate blocking of malicious domains at the firewall","Encryption of logs before forwarding to a central system"],"correctIndex":0,"explanation":"Chain of custody documents who handled evidence, when, and how, supporting legal defensibility.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 6.html"},{"id":300,"question":"14. Which is the BEST example of lateral movement activity in logs?","options":["One workstation authenticating to many hosts rapidly","A single server applying patches to its own services","A user opening a local file from their documents folder","A printer requesting DHCP renewal after a lease expires"],"correctIndex":0,"explanation":"Lateral movement often appears as unusual authentication patterns from a compromised host to many internal systems.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":301,"question":"15. An endpoint begins beaconing every 60 seconds to a rare domain using HTTPS. This most likely indicates:","options":["Command-and-control communications using regular beacons","Standard certificate revocation checks by web browsers","Normal OS time synchronization with an external service","Routine content retrieval from a well-known CDN provider"],"correctIndex":0,"explanation":"Periodic, regular connections to rare infrastructure are typical C2 beacon behavior.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":302,"question":"16. A user receives an email requesting urgent payment and the sender domain is slightly misspelled. This is most likely:","options":["Business email compromise or targeted phishing attempt","Routine invoice processing from a vendor mail gateway","An automated password expiration reminder from identity","A harmless marketing message sent from a mailing list"],"correctIndex":0,"explanation":"Lookalike domains and urgency cues are common in phishing/BEC attempts.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 6.html"},{"id":303,"question":"17. Which action is MOST appropriate FIRST when malware is suspected on a critical server?","options":["Isolate the server to contain impact while preserving data","Immediately wipe the system drive to remove the malware","Publicly notify customers before initial triage is complete","Disable all logging to prevent the attacker from noticing"],"correctIndex":0,"explanation":"Containment is typically the first operational step—limit spread while maintaining evidence for analysis.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":304,"question":"18. Which indicator most strongly suggests DNS tunneling?","options":["Many long and random-looking DNS queries to one domain","A normal number of DNS queries to common SaaS services","Short DNS queries for internal hostnames during business","DNS replies cached locally reducing outbound query volume"],"correctIndex":0,"explanation":"DNS tunneling often uses long subdomains, high query volume, and unusual patterns to carry data.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 6.html"},{"id":305,"question":"19. A security analyst sees a new local admin account created outside change control. This is most likely evidence of:","options":["Privilege escalation or persistence via rogue accounts","Routine group policy refresh applying standard accounts","A normal endpoint enrollment process for device management","Standard password rotation applied by the PAM solution"],"correctIndex":0,"explanation":"Unexpected admin account creation is a strong sign of compromise or policy violation.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 6.html"},{"id":306,"question":"20. Which response best describes the purpose of an incident response playbook?","options":["A step-by-step guide for handling a specific incident type","A list of user passwords stored for emergency access use","A vendor catalog describing security products and pricing","A legal contract defining service uptime requirements only"],"correctIndex":0,"explanation":"Playbooks standardize actions and decision points for consistent handling of common incident scenarios.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":307,"question":"21. Which log source is MOST useful for detecting abnormal privilege use on Windows systems?","options":["Security event logs showing logons and privilege changes","Printer spooler logs showing queued and completed jobs","Application theme logs showing user display preferences","Battery usage logs showing charge and discharge cycles"],"correctIndex":0,"explanation":"Windows Security logs (and related auditing) are key for tracking logons, group changes, and privileged actions.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":308,"question":"22. Which technique best helps reduce false positives during indicator-based detection?","options":["Correlating multiple signals before escalating an alert","Alerting on a single IOC match without additional context","Disabling endpoint telemetry to prevent noisy detections","Blocking all outbound traffic to avoid any beacon traffic"],"correctIndex":0,"explanation":"Correlation (SIEM/EDR context) helps confirm suspicious behavior versus one-off matches.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 6.html"},{"id":309,"question":"23. A host shows repeated authentication attempts using many usernames against one service. This most likely indicates:","options":["Password spraying attempt against a common credential set","Normal SSO token refresh activity across multiple users","Routine HR onboarding automatically validating accounts","Standard VPN reconnection events due to network jitter"],"correctIndex":0,"explanation":"Password spraying tries a few common passwords against many accounts to avoid lockouts.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":310,"question":"24. Which activity is MOST appropriate during the detection and analysis phase?","options":["Confirming the incident, triaging scope, and collecting IOCs","Rebuilding all impacted systems without preserving evidence","Publishing a public statement before internal validation","Removing all logs to prevent further attacker discovery"],"correctIndex":0,"explanation":"Detection/analysis validates the event, determines scope/impact, and gathers details for containment/eradication.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":311,"question":"25. A file integrity monitoring alert shows critical binaries changed without a patch window. This most likely indicates:","options":["Unauthorized modification or tampering with system files","Routine update activity completed during planned downtime","Standard user personalization settings applied at login","Normal backup deduplication rewriting unchanged content"],"correctIndex":0,"explanation":"Unexpected changes to critical files can indicate compromise, rootkits, or malicious tampering.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 6.html"},{"id":312,"question":"26. Which indicator best aligns with a rootkit infection on a host?","options":["Hidden processes or drivers and inconsistent system outputs","A single blocked pop-up window from a web browser tab","An increase in helpdesk tickets during a password reset day","A normal reboot after applying an approved security update"],"correctIndex":0,"explanation":"Rootkits often hide processes/drivers and manipulate system calls, causing inconsistent views between tools.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 6.html"},{"id":313,"question":"27. Which step helps preserve evidence BEST when collecting data from a suspect disk?","options":["Create a forensic image using a write blocker when possible","Open the files directly and copy only the suspicious ones","Run a cleanup utility to remove temporary files beforehand","Defragment the drive to speed up scanning and collection"],"correctIndex":0,"explanation":"Forensic imaging with write blockers helps prevent altering evidence and supports repeatable analysis.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Sec + Day 6.html"},{"id":314,"question":"28. Which communication is MOST appropriate as part of an incident response communications plan?","options":["Defined internal and external notification procedures and roles","A list of employee personal accounts for emergency contact use","A schedule of marketing campaigns for the next quarter year","A catalog of office equipment replacement part identifiers"],"correctIndex":0,"explanation":"A communications plan defines who communicates what, to whom, and when (legal/PR/leadership/technical).","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":315,"question":"29. A user reports their browser homepage and proxy settings changed without permission. This most likely indicates:","options":["Potential browser hijacking or unauthorized configuration change","Routine browser updates applying standard security defaults","Normal DHCP changes updating gateway and DNS information","Approved enterprise management applying user experience settings"],"correctIndex":0,"explanation":"Unexpected proxy/homepage changes can indicate adware, browser hijackers, or malicious configuration changes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":316,"question":"30. Which outcome best reflects successful incident containment?","options":["Further spread is stopped while evidence and operations are managed","All systems are wiped immediately without determining scope first","A public press release is issued before internal validation completes","Logs are disabled to prevent attackers from noticing investigation steps"],"correctIndex":0,"explanation":"Containment aims to stop propagation and limit impact while maintaining the ability to investigate and recover.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":317,"question":"Which activity best demonstrates effective security governance rather than day-to-day security operations?","options":["Approving security policy and risk direction through executive oversight","Adjusting IDS rules to reduce repeated false positive alerts","Rotating service account credentials on a set monthly schedule","Reimaging an infected workstation to remove persistent malware"],"correctIndex":0,"explanation":"Governance is direction and oversight (policy approval, risk appetite). The others are operational tasks.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":318,"question":"A company wants security decisions aligned with business goals and clear accountability. What is MOST appropriate?","options":["Establish a security steering committee with authority and metrics","Let each department select controls without centralized coordination","Assign all approvals to the SOC manager without executive input","Outsource security entirely and remove internal decision oversight"],"correctIndex":0,"explanation":"A steering committee supports governance via alignment, authority, accountability, and escalation paths.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":319,"question":"Which document MOST directly translates high-level security objectives into specific, measurable requirements?","options":["Security standards that define mandatory technical requirements","Acceptable use policy describing expected user behavior","Incident response playbook describing response workflows","Network topology diagram showing paths and device placement"],"correctIndex":0,"explanation":"Policies state intent; standards define measurable requirements such as versions, lengths, and configurations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":320,"question":"A policy states: “Sensitive data must be protected in transit.” Which supporting standard is BEST?","options":["Require TLS 1.2+ with approved cipher suites for sensitive transfers","Encourage employees to avoid sending sensitive data when possible","Require the help desk to verify identity during password resets","Ask developers to document APIs that handle sensitive information"],"correctIndex":0,"explanation":"A standard is specific and testable. TLS version and ciphers are enforceable requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":321,"question":"Which is the BEST example of separation of duties (SoD)?","options":["One person requests payment, another approves, and a third reconciles","Administrators use MFA for all privileged access sessions","Developers complete security training during annual refresher events","Users change passwords every 90 days based on written policy"],"correctIndex":0,"explanation":"SoD splits critical steps across different roles to reduce fraud and mistakes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":322,"question":"A company is adopting a new cloud service. Which governance artifact best sets security expectations for vendors?","options":["Third-party risk requirements and contract security clauses for services","An internal list of employee job titles and reporting structure","A wireless coverage diagram showing access point placement areas","A collection of old incident tickets from prior unrelated systems"],"correctIndex":0,"explanation":"TPRM artifacts and contract clauses define responsibilities, reporting, and security requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":323,"question":"Which metric BEST supports governance by demonstrating executive-level security program effectiveness?","options":["Risk reduction trends for critical services based on periodic assessments","Number of firewall packets dropped during the previous business hour","CPU usage percentage on SIEM collectors averaged across all nodes","Total help desk calls related to printers and peripheral connectivity"],"correctIndex":0,"explanation":"Governance metrics should tie to business risk and critical service outcomes, not low-level telemetry.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":324,"question":"What is the PRIMARY goal of data classification within a security governance program?","options":["Apply handling rules based on sensitivity and business impact of data","Ensure all data uses a single encryption method across the enterprise","Eliminate the need for access controls through uniform permissions","Require all data to remain on-premises without any cloud storage use"],"correctIndex":0,"explanation":"Classification drives appropriate controls (access, retention, encryption, sharing) based on sensitivity.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":325,"question":"A team is asked to implement controls that match the organization’s risk appetite. What should happen FIRST?","options":["Perform a risk assessment to prioritize threats and business impacts","Deploy DLP to all endpoints immediately to prevent any data movement","Block all external attachments to reduce exposure to malware risks","Require biometrics for every user login regardless of role needs"],"correctIndex":0,"explanation":"You select controls after understanding risk and prioritizing based on likelihood/impact and objectives.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":326,"question":"Which scenario BEST represents a formal exception (policy waiver) process?","options":["A time-bound deviation approved with compensating controls and tracking","A developer disables logging permanently to improve application speed","A user shares credentials to meet a deadline and avoid ticket delays","A vendor rejects clauses and the business proceeds without documentation"],"correctIndex":0,"explanation":"Exceptions should be documented, authorized, time-limited, and include compensating controls.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":327,"question":"What is the PRIMARY difference between an internal audit and an external audit?","options":["Internal audits are organizational; external audits require independent review","Internal audits are always financial; external audits are only technical","Internal audits do not require evidence; external audits always require it","Internal audits cannot report results to management or leadership teams"],"correctIndex":0,"explanation":"Independence is key: internal audits are internal assurance, external audits are independent/regulatory.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":328,"question":"During an audit, which item is the BEST example of objective evidence?","options":["System logs showing administrative login attempts over a set time window","A manager stating that access reviews are performed on a regular basis","A policy stating access reviews should be performed quarterly by owners","An employee claiming MFA is enforced everywhere across all environments"],"correctIndex":0,"explanation":"Objective evidence is verifiable (logs, tickets, signed reviews), not statements or intent documents.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":329,"question":"Which assessment BEST validates the effectiveness of security controls over time?","options":["Periodic control testing with documented results and follow-up actions","A one-time asset inventory completed during initial system onboarding","A diagram review that does not validate configuration or implementation","A marketing survey measuring customer sentiment toward company products"],"correctIndex":0,"explanation":"Ongoing effectiveness is demonstrated through repeatable testing, evidence, and remediation tracking.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 7.html"},{"id":330,"question":"A penetration test is MOST likely to answer which question?","options":["Can an attacker exploit weaknesses to achieve a defined objective?","Are employees aware of the exact password policy wording in place?","Has the board formally approved the organization’s data classification policy?","Are vendor invoices approved and reconciled properly by accounting teams?"],"correctIndex":0,"explanation":"Pen tests validate exploitability and attack paths to objectives like privilege escalation or data access.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":331,"question":"Which activity BEST represents a vulnerability assessment rather than a penetration test?","options":["Scanning for known weaknesses and prioritizing fixes based on risk","Using social engineering to obtain credentials and pivot across systems","Chaining exploits to reach sensitive data and prove end-to-end impact","Establishing persistence with covert command-and-control communications"],"correctIndex":0,"explanation":"Vulnerability assessments identify and prioritize weaknesses; penetration tests attempt exploitation.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":332,"question":"Which document BEST defines scope, rules of engagement, and authorization for a penetration test?","options":["A signed SOW/ROE document with explicit written authorization details","An acceptable use policy describing how employees should use systems","A disaster recovery plan describing recovery strategies during outages","A data retention schedule listing required retention periods per record"],"correctIndex":0,"explanation":"A formal SOW/ROE plus authorization defines scope, windows, limitations, and legal permission.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":333,"question":"After an audit identifies a high-risk finding, what is the MOST appropriate next step?","options":["Create a remediation plan with owners, dates, and tracked verification","Delete the report to reduce exposure and avoid discovery in litigation","Wait until the next annual audit cycle before addressing the issue","Terminate employees immediately without validating facts or root cause"],"correctIndex":0,"explanation":"High-risk findings require owned remediation, timelines, tracking, and verification to closure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":334,"question":"Which is the BEST example of a compensating control for an audit finding?","options":["Use a jump host with MFA and session recording until direct access ends","Accept risk informally without documenting approval or compensations","Disable security logs to reduce storage costs and simplify operations","Grant broader privileges to reduce the number of access request tickets"],"correctIndex":0,"explanation":"Compensating controls reduce risk when the primary control cannot be implemented immediately.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 7.html"},{"id":335,"question":"A security awareness program wants to measure improvement in phishing detection. Which metric is MOST direct?","options":["Phishing simulation click and credential submission rates over time","Total number of emails received by the organization each calendar month","Average laptop battery health across the endpoint fleet over quarters","Number of employee badges issued and replaced due to normal wear"],"correctIndex":0,"explanation":"Simulated phishing outcomes directly measure susceptibility and trends in user behavior.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Day 7.html"},{"id":336,"question":"Which approach BEST improves awareness training effectiveness across different employee roles?","options":["Role-based training tailored to job functions and likely threat scenarios","One annual generic video for everyone regardless of duties or exposure","Training only new hires and skipping refresher training for all others","Using posters only without interaction, testing, or follow-up evaluation"],"correctIndex":0,"explanation":"Role-based training increases relevance and retention for groups like devs, finance, and executives.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":337,"question":"When preparing for a compliance audit, which action BEST supports audit readiness?","options":["Maintain a mapped repository of control evidence aligned to requirements","Recreate evidence only after auditors arrive and request documentation","Disable logging to reduce the volume of evidence auditors can review","Provide only policy documents and avoid operational evidence collection"],"correctIndex":0,"explanation":"Readiness is improved when evidence is organized, current, and mapped to control requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":338,"question":"Which item is MOST associated with SOC 2 Type II compared to Type I?","options":["Testing operating effectiveness of controls over a defined time period","A point-in-time description of controls without effectiveness testing","A quarterly network penetration test across the public address space","A one-time vulnerability scan of perimeter systems and public services"],"correctIndex":0,"explanation":"Type I focuses on design at a point in time; Type II evaluates operating effectiveness over time.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":339,"question":"What is the BEST description of the outcome of a gap analysis against a security framework?","options":["A mapped comparison showing deficiencies and prioritized actions to close gaps","A list of discovered vulnerabilities produced only by scanning tools output","A record of incidents over the last year sorted by attack type categories","A diagram of VLANs and network segments showing routing and access paths"],"correctIndex":0,"explanation":"Gap analysis compares current state to target requirements and produces remediation actions.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 7.html"},{"id":340,"question":"Which concept BEST describes ensuring security policies are followed through monitoring and corrective actions?","options":["Compliance management with tracking, reporting, and corrective remediation","Threat hunting for hidden adversaries in internal telemetry and logs","Vulnerability chaining to demonstrate multi-step exploitation in networks","Packet capture analysis to troubleshoot latency and connection behavior"],"correctIndex":0,"explanation":"Compliance management ensures adherence to policies/standards via monitoring, reporting, and remediation.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":341,"question":"To reduce insider risk by minimizing unnecessary access, which governance practice BEST supports the goal?","options":["Least privilege with periodic access reviews and timely deprovisioning","Increasing Wi-Fi coverage to improve roaming and reduce dead zones","Allowing shared accounts for convenience when workloads become heavy","Disabling EDR alerts broadly to reduce notification fatigue in teams"],"correctIndex":0,"explanation":"Least privilege plus access reviews and deprovisioning reduces excess permissions and insider risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":342,"question":"Which role is MOST commonly responsible for setting strategic security direction aligned with business goals?","options":["CISO or equivalent executive leader accountable for security strategy","Help desk technician responsible for resolving end-user access issues","Junior system administrator managing day-to-day server configurations","Facilities supervisor coordinating building access and maintenance work"],"correctIndex":0,"explanation":"Strategic security direction and alignment are executive responsibilities typically led by the CISO.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":343,"question":"Which governance practice BEST ensures critical systems remain secure as changes occur?","options":["Formal change management with security review and documented approvals","Allowing direct production deployments without review to move quickly","Disabling version control to reduce complexity and simplify workflows","Relying on annual audits as the primary method to detect issues later"],"correctIndex":0,"explanation":"Change management enforces review, testing, approval, and logging to reduce change-related risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":344,"question":"A company needs to define how long records are kept and how they are disposed. Which policy area applies?","options":["Data retention and disposal policy covering lifecycle and secure destruction","Password complexity policy defining length, history, and rotation requirements","Wireless encryption policy defining supported protocols for Wi-Fi networks","Patch management policy defining timelines for updating OS and applications"],"correctIndex":0,"explanation":"Retention and disposal policies define how long to keep records and how to dispose of them securely.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":345,"question":"What is the PRIMARY purpose of a tabletop exercise (TTX) for security preparedness?","options":["Validate plans and decision-making using scenarios without live system changes","Perform live exploitation against production systems to test attacker success","Replace the need for documented incident response procedures entirely","Guarantee compliance automatically by simulating regulator expectations only"],"correctIndex":0,"explanation":"TTXs are discussion-based exercises used to validate roles, processes, and decisions without impacting systems.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 7.html"},{"id":346,"question":"Which audit approach is MOST accurately described as risk-based?","options":["Prioritizing testing for controls that mitigate the highest business risks","Testing every control equally regardless of criticality or impact levels","Auditing only controls with evidence that is easy to gather quickly","Auditing primarily after a breach occurs to document what happened"],"correctIndex":0,"explanation":"Risk-based auditing focuses coverage on areas with the highest likelihood and impact to the business.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":347,"question":"Which item MOST indicates readiness for a formal certification-style audit with respect to documentation?","options":["Documented policies and standards with evidence of use and periodic review","One policy PDF that has never been communicated or reviewed since creation","Verbal procedures known to a few employees without any recorded evidence","A backlog of untracked security issues without owners or due date fields"],"correctIndex":0,"explanation":"Readiness requires documented requirements, proof of implementation, and governance processes like reviews.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":348,"question":"Which item is the MOST appropriate evidence that quarterly access reviews occurred?","options":["Dated review records showing reviewer identity, outcomes, and approvals","A policy statement requiring quarterly reviews for privileged user access","A manager email stating that access reviews are important for security","An IAM architecture diagram showing where access review features reside"],"correctIndex":0,"explanation":"Evidence must show the control operated: dates, reviewer identity, results, approvals, and follow-up.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":349,"question":"A security awareness team wants to reduce risky behavior quickly. Which method is MOST effective?","options":["Just-in-time micro-training delivered immediately after risky user actions","Posting long policy documents and assuming employees read them closely","Training only the IT department because they are the most technical users","Sending generic emails monthly without measuring behavior change outcomes"],"correctIndex":0,"explanation":"Just-in-time training is timely and relevant, making it more effective than generic messaging alone.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Day 7.html"},{"id":350,"question":"Which assessment is BEST suited to identify weaknesses in overall security program maturity?","options":["A maturity assessment mapped to a framework with capability levels defined","A malware scan of a single host to confirm detection capability status","A printer inventory review that validates asset counts and locations only","A password reset campaign that focuses only on credential hygiene changes"],"correctIndex":0,"explanation":"Maturity assessments evaluate program capabilities across people, process, and measurement over time.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 7.html"},{"id":351,"question":"Which outcome BEST reflects successful remediation verification after fixing an audit finding?","options":["Re-test the control and retain evidence showing the issue is resolved and sustained","Close the ticket as soon as the change request is submitted to an engineering queue","Wait for users to report problems if the issue returns during daily operations","Assume the fix worked because the vendor claimed the feature is enabled now"],"correctIndex":0,"explanation":"Verification requires re-testing and evidence that the corrected control is operating effectively.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":352,"question":"Which statement BEST describes 'risk appetite'?","options":["The level and type of risk leadership is willing to accept to meet goals","A list of vulnerabilities ranked by CVSS scores for technical prioritization","The number of incidents the SOC can handle per day based on staffing","The encryption algorithm selected for data at rest across all systems"],"correctIndex":0,"explanation":"Risk appetite expresses how much risk the organization is willing to accept in pursuit of objectives.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":353,"question":"Which governance control BEST ensures policies remain current as technology and threats change?","options":["Defined review cadence with version control and stakeholder approval workflow","One-time approval at creation with no scheduled updates or periodic checks","Allowing each team to interpret policy requirements without documentation","Storing policies on a shared drive without any change tracking enabled"],"correctIndex":0,"explanation":"Formal review cycles and version control keep policies accurate and aligned with the environment.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":354,"question":"An organization wants critical processes to continue during disruptions. Which activity is MOST relevant?","options":["Business impact analysis to prioritize services and set recovery objectives","Replacing endpoints with new hardware to reduce the chance of device failure","Blocking all internet traffic except email to reduce the external attack surface","Increasing password complexity to 40 characters for all users without exceptions"],"correctIndex":0,"explanation":"A BIA identifies critical services and informs RTO/RPO and recovery planning priorities.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":355,"question":"Why is security sign-off in the SDLC considered an important governance control?","options":["It ensures security requirements are addressed before release to reduce rework","It guarantees software will have zero vulnerabilities in all environments","It eliminates the need for unit testing because security covers all defects","It replaces change management by allowing direct releases once approved"],"correctIndex":0,"explanation":"Security gates help address requirements and risks early, reducing exposure and costly last-minute fixes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":356,"question":"A financial services firm is updating its risk register after a series of phishing-related near misses. Leadership wants a numeric estimate to justify a new control, but historical incident frequency is limited. Which approach best aligns with quantitative analysis while acknowledging data constraints?","options":["Use SLE and ALE estimates with documented assumptions, then sensitivity-test ARO ranges for variance.","Use a heat map with High/Medium/Low labels and convene SMEs to vote on overall risk severity.","Use a qualitative narrative of potential impacts and prioritize risks based on stakeholder perception alone.","Use only vulnerability scan scores as a proxy for business impact and treat CVSS as financial loss."],"correctIndex":0,"explanation":"Quantitative analysis uses numeric loss models (SLE/ALE). When ARO is uncertain, you document assumptions and run sensitivity analysis rather than switching to purely qualitative methods.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":357,"question":"During a BIA review, an online retailer states the maximum downtime for the order processing system is 6 hours, but the target recovery objective is 2 hours. What is the relationship being described?","options":["MTD is the absolute limit, and RTO is the target time that must be less than or equal to the MTD value.","RPO is the absolute limit, and MTD is the target time that must be less than or equal to the RPO value.","WRT is the absolute limit, and RPO is the target time that must be less than or equal to the WRT value.","SLE is the absolute limit, and ALE is the target time that must be less than or equal to the SLE value."],"correctIndex":0,"explanation":"MTD (maximum tolerable downtime) is the hard ceiling. RTO is the targeted recovery time and should be shorter than (or at most equal to) the MTD.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":358,"question":"A security manager selects a mitigation strategy that transfers a portion of financial impact to a third party without reducing the probability of a cyber event. Which option best fits this strategy?","options":["Purchase cyber insurance and align coverage limits to modeled ALE and contractual exposure thresholds.","Deploy EDR with behavioral rules and tune detections to reduce dwell time and lateral movement paths.","Implement secure baselines and disable legacy protocols to reduce attack surface and exploit likelihood.","Accept the risk by documenting residual exposure and scheduling review at the next governance cycle."],"correctIndex":0,"explanation":"Risk transference shifts financial impact to another party (e.g., insurance), but does not inherently reduce likelihood. Controls like EDR/baselines are risk reduction.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":359,"question":"A hospital is implementing compensating controls because a legacy imaging device cannot support modern encryption. Which mitigation technique best addresses confidentiality risk without replacing the device immediately?","options":["Segment the device on an isolated VLAN with strict ACLs and a monitored jump host for administration only.","Enable full-disk encryption on the device and require TPM-backed keys for all imaging data at rest.","Deploy client-side certificates directly on the device and enforce mutual TLS across all communications.","Recompile the device firmware to support modern cipher suites and apply vendor patches weekly."],"correctIndex":0,"explanation":"When the asset cannot support strong crypto, compensating controls like segmentation, ACLs, and controlled administration reduce exposure and limit lateral movement.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 8.html"},{"id":360,"question":"A company identifies that its biggest business risk is prolonged outage from a regional disaster. They decide to maintain a secondary site with hardware installed but requiring configuration and data restoration before use. Which site type is being described?","options":["Warm site with partial readiness, requiring some restoration and configuration before full production service.","Cold site with no equipment, requiring procurement and installation prior to any operational capability.","Hot site with full synchronization, enabling near-immediate failover with minimal manual intervention steps.","Mobile site with temporary facilities, requiring shipping containers and satellite communications on demand."],"correctIndex":0,"explanation":"Warm sites have equipment but are not fully current or instantly available like hot sites; they require configuration/restoration. Cold sites are largely empty facilities.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + Day 8.html"},{"id":361,"question":"A risk owner wants to ensure that control selection is traceable to business goals and regulatory requirements. Which documentation set most directly supports this alignment?","options":["Policies, standards, and a control framework mapping that ties requirements to implemented controls and owners.","Packet captures and IDS signatures showing exploitation attempts against externally facing perimeter services.","A list of discovered vulnerabilities ranked only by CVSS base score and scanner plugin criticality levels.","An inventory of employee training completions and phishing click rates without linkage to risk statements."],"correctIndex":0,"explanation":"Governance alignment comes from policy/standards and framework mappings (e.g., NIST/ISO) that trace requirements to controls, owners, and evidence.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"Sec + Day 8.html"},{"id":362,"question":"A CISO is prioritizing mitigations using a risk matrix. Multiple risks are rated 'High' because likelihood is high, but impact differs significantly between systems. What is the most appropriate next step to improve prioritization accuracy?","options":["Refine impact criteria with business owners and incorporate asset criticality so impact levels differentiate meaningfully.","Treat all High likelihood risks as equal priority and remediate them strictly in alphabetical order by system name.","Ignore impact criteria and prioritize only by likelihood because impact is subjective and difficult to validate.","Convert the matrix into CVSS-only scoring and remove business context to improve technical objectivity."],"correctIndex":0,"explanation":"When impact is not discriminating well, you tune impact criteria and include asset criticality/business context so the matrix produces more useful prioritization.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":363,"question":"A team is selecting controls to reduce ransomware blast radius. Which mitigation technique most directly limits lateral movement inside the enterprise network?","options":["Network segmentation with least privilege ACLs and restricted east-west traffic between critical subnets.","Full-disk encryption on endpoints to prevent unauthorized read access when devices are physically stolen.","A data retention policy that deletes older files to reduce storage costs and improve archival governance.","A public key infrastructure rollout intended to standardize identity issuance for external partner access."],"correctIndex":0,"explanation":"Segmentation and restrictive east-west controls reduce lateral movement and contain ransomware spread. The other options address different risk dimensions.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":364,"question":"A risk assessment identifies a control gap for privileged account monitoring. Which mitigation best supports detection and response while maintaining auditability?","options":["Implement PAM with session recording, just-in-time elevation, and centralized logging to a SIEM for review.","Disable all administrative accounts permanently and require standard users to perform all server maintenance.","Use a shared administrator password in a vault to simplify access and reduce time spent on account requests.","Allow privileged access only from unmanaged personal devices to reduce load on corporate endpoint controls."],"correctIndex":0,"explanation":"PAM with JIT and session recording improves visibility, reduces standing privilege, and creates auditable evidence. Shared passwords and unmanaged devices increase risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":365,"question":"An organization calculates SLE for a database breach as $250,000. The event is expected to occur once every five years. What is the ALE?","options":["ALE equals $50,000 per year because ARO is 0.2 and ALE is SLE multiplied by ARO for expected annual loss.","ALE equals $1,250,000 per year because ARO is 5 and ALE is SLE multiplied by ARO for expected annual loss.","ALE equals $250,000 per year because ARO is not used when the event frequency is less than one per year.","ALE equals $0 per year because events that occur every five years are excluded from annualized modeling."],"correctIndex":0,"explanation":"ARO is 1/5 = 0.2. ALE = SLE × ARO = 250,000 × 0.2 = 50,000.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":366,"question":"A vendor hosts an application for your company and commits to uptime, response times, and penalties if targets are not met. Which agreement type is most applicable?","options":["SLA that defines measurable service targets, reporting cadence, and remedies when the service level is missed.","MOU that documents shared intentions without enforceable metrics or operational penalties for missed targets.","NDA that prevents disclosure of confidential information but does not specify availability or response metrics.","ISA that defines encryption and authentication for network interconnection, not service availability measures."],"correctIndex":0,"explanation":"An SLA specifies service metrics like uptime and response times plus penalties/remedies. MOU/NDA/ISA do not primarily define service performance metrics.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":367,"question":"A security analyst proposes replacing annual tabletop exercises with a single incident response policy document to reduce costs. From a risk management perspective, what is the most accurate concern?","options":["Removing exercises reduces preparedness evidence and increases residual risk because plans must be validated and improved.","Removing exercises improves security because fewer staff learn the plan and therefore attackers gain less knowledge.","Replacing exercises with a policy increases control effectiveness because documentation always prevents operational errors.","Eliminating exercises decreases risk because it reduces audit scope and therefore reduces findings and compliance effort."],"correctIndex":0,"explanation":"Exercises test assumptions, reveal gaps, and improve response readiness. Eliminating them often increases residual risk and reduces evidence of control effectiveness.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":368,"question":"A company wants to mitigate the risk of credential stuffing on a customer portal. Which control most directly reduces the likelihood of automated login abuse?","options":["Implement MFA with rate limiting and bot detection controls to degrade automated attempts and enforce strong auth.","Add full-disk encryption to the web server to protect data at rest from local administrator access threats.","Move the portal to a different DNS provider to reduce network latency and improve customer page load times.","Deploy a new SIEM dashboard to visualize authentication logs without changing authentication control behavior."],"correctIndex":0,"explanation":"MFA, rate limiting, and bot detection directly reduce credential stuffing success. Encryption, DNS changes, and dashboards do not directly prevent automated login abuse.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":369,"question":"A risk committee approves acceptance of a low-impact, low-likelihood risk. What is the BEST supporting governance action to keep acceptance defensible over time?","options":["Document the risk owner, rationale, residual risk, and review date in the risk register with sign-off evidence.","Ignore the risk entirely because accepted risks do not require monitoring or periodic reassessment activities.","Delete the risk from the register to prevent auditors from discovering it during future compliance checks.","Mitigate the risk immediately anyway so acceptance never appears in documentation or management reporting."],"correctIndex":0,"explanation":"Risk acceptance should be explicit, documented, owned, and reviewed. This preserves accountability and supports audit defensibility as conditions change.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":370,"question":"A software team must deploy quickly but wants mitigation that reduces the probability of vulnerabilities reaching production. Which control is most appropriate?","options":["Integrate SAST/DAST into CI/CD with gating thresholds and peer code review to catch defects before release.","Rely solely on a quarterly penetration test and defer remediation until the next annual budgeting cycle.","Disable logging in production to reduce storage costs and limit sensitive data exposure in log aggregation.","Allow developers to bypass change control for emergency releases and document fixes after customer complaints."],"correctIndex":0,"explanation":"Shift-left controls like SAST/DAST, gated pipelines, and peer review reduce the likelihood of shipping vulnerabilities, supporting proactive mitigation.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 8.html"},{"id":371,"question":"An organization wants mitigation that primarily reduces impact, not likelihood, for a data loss scenario. Which control best fits that objective?","options":["Implement immutable backups with offline copies and tested restore procedures to limit operational impact of loss.","Deploy web application firewalls with tuned signatures to block malicious payloads and reduce exploit attempts.","Enforce strict password complexity rules to increase brute-force cost and reduce authentication attack success.","Conduct security awareness training to reduce phishing susceptibility and reduce probability of credential compromise."],"correctIndex":0,"explanation":"Backups and tested restores reduce impact by improving recovery capability. WAF, passwords, and training primarily reduce likelihood.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Day 8.html"},{"id":372,"question":"A security architect recommends a risk mitigation plan but must ensure controls are cost-effective. Which concept best supports comparing control cost to expected loss reduction?","options":["Cost-benefit analysis using ALE reduction versus control implementation and operational costs for a rational decision.","Threat modeling using only STRIDE categories to label issues without financial context or control cost comparisons.","Vulnerability prioritization using only CVSS temporal metrics to avoid business impact and cost considerations.","Compliance mapping that checks boxes for frameworks without evaluating measurable reduction in expected losses."],"correctIndex":0,"explanation":"Cost-benefit analysis compares expected annual loss reduction (e.g., ALE delta) against control cost, supporting defensible mitigation decisions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":373,"question":"A company mitigates a high-risk finding by outsourcing a function to a managed service provider. However, regulatory accountability remains with the company. What is the BEST mitigation add-on?","options":["Establish SLA/contract clauses, audit rights, and continuous vendor risk monitoring to manage third-party exposure.","Assume the provider now owns all compliance requirements and remove the service from internal control testing.","Stop collecting logs from the outsourced function to reduce data handling risk and simplify operational overhead.","Disable incident response playbooks for the function because the provider will always handle all incidents alone."],"correctIndex":0,"explanation":"Outsourcing introduces third-party risk. Strong contracts, audit rights, and ongoing monitoring are key to mitigating residual and compliance risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":374,"question":"A SOC receives frequent false positives from a detection rule, causing analyst fatigue and slower response. Which mitigation best reduces operational risk while preserving detection value?","options":["Tune the rule with better thresholds and context enrichment, then validate changes with purple-team testing.","Disable the rule permanently and ignore related alerts to reduce workload regardless of threat exposure changes.","Route all alerts to a single analyst mailbox without triage so that accountability is centralized and consistent.","Increase alert severity for all events so fewer items appear on dashboards and analysts focus only on criticals."],"correctIndex":0,"explanation":"Tuning and validation reduce false positives while keeping detection coverage. Disabling blindly or manipulating severity increases risk and reduces response effectiveness.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 8.html"},{"id":375,"question":"A company wants to mitigate risk from unauthorized USB usage on sensitive workstations. Which control set is most appropriate?","options":["Apply device control policies with allowlists, endpoint DLP, and least privilege to restrict removable media access.","Install a second antivirus product to increase signature coverage and allow all removable media for productivity.","Disable screen locking to avoid disrupting workflows and require users to self-report suspicious USB devices.","Move user profiles to local storage only and remove centralized logging to reduce sensitive data in transit."],"correctIndex":0,"explanation":"Device control allowlists plus DLP and least privilege address the threat path (removable media exfil/malware). Extra AV or reduced controls are not targeted mitigation.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 8.html"},{"id":376,"question":"A risk analysis identifies that the probability of a rare event is low, but the financial impact is catastrophic. Which prioritization outcome is most appropriate?","options":["Treat it as high priority due to extreme impact and consider resilience controls that reduce consequence severity.","Treat it as low priority because likelihood is low and only likely risks should receive mitigation funding now.","Ignore it because catastrophic events cannot be modeled and therefore cannot be mitigated effectively in practice.","Accept it without documentation because discussing catastrophic risk increases stakeholder anxiety and audit scrutiny."],"correctIndex":0,"explanation":"Low likelihood but catastrophic impact can still be high risk, especially with business-critical services. Resilience controls can reduce impact even if likelihood remains low.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":377,"question":"A company is using qualitative risk assessment. Which output is MOST consistent with qualitative analysis?","options":["A risk heat map with likelihood and impact labeled as High/Medium/Low and supported by SME rationale notes.","An ALE table that calculates annualized losses for each risk using SLE and ARO with currency-based results.","A Monte Carlo simulation showing probabilistic distributions for annual losses based on event frequency ranges.","A depreciation schedule that amortizes security tooling purchases over time for financial accounting and taxation."],"correctIndex":0,"explanation":"Qualitative analysis commonly uses ordinal ratings (High/Medium/Low) and risk matrices/heat maps, often based on SME input rather than monetary calculations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":378,"question":"A security team must mitigate risk from outdated TLS configurations on public web services. Which mitigation is MOST appropriate?","options":["Disable weak protocols and ciphers, enforce modern TLS, and validate via scanning and change control evidence.","Increase password complexity for all users because authentication strength automatically fixes transport weaknesses.","Move the web server to a private subnet with no public access and keep the same TLS to avoid disruption.","Enable WEP on internal Wi-Fi to standardize encryption across networks and simplify security configuration."],"correctIndex":0,"explanation":"Transport security is addressed by disabling weak TLS versions/ciphers and enforcing modern configurations, validated by scanning and controlled change management.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":379,"question":"An organization wants to reduce data exfiltration risk from cloud object storage that is frequently misconfigured. Which mitigation technique best addresses the root cause?","options":["Implement CSPM with policy-as-code guardrails, least privilege IAM, and continuous misconfiguration monitoring.","Disable cloud logging to reduce the volume of security events and rely on quarterly manual checks for access.","Allow public read access by default and ask teams to self-audit periodically to avoid delays in development.","Replace object storage with email attachments so data remains within familiar workflows and user interfaces."],"correctIndex":0,"explanation":"CSPM plus guardrails and least privilege IAM reduces misconfigurations and detects drift continuously, directly targeting the root cause.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":380,"question":"A risk register shows 'Residual Risk' remains medium after a control is implemented. What does residual risk represent?","options":["The remaining exposure after controls are applied, acknowledging that mitigations reduce but rarely eliminate risk.","The total inherent exposure before any control is applied, representing the raw baseline risk state of the asset.","A risk that has been transferred completely to a third party and therefore no longer requires internal oversight.","A risk that has been accepted permanently and therefore cannot be revisited during future governance reviews."],"correctIndex":0,"explanation":"Residual risk is what remains after applying controls. Inherent risk is the pre-control baseline. Transference and acceptance do not remove oversight requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":381,"question":"A company is selecting mitigation for insider threats where users have legitimate access but misuse it. Which control combination is MOST effective?","options":["Apply least privilege, UEBA monitoring, and separation of duties to reduce misuse opportunity and increase detection.","Increase perimeter firewall rules and block inbound traffic because insiders primarily attack from external networks.","Disable MFA and rely on password length alone so that authentication remains simple and consistent for users.","Encrypt all email subject lines only and ignore attachments so that data exfiltration attempts are harder to see."],"correctIndex":0,"explanation":"Insider threat mitigation often combines least privilege, separation of duties, and behavioral analytics (UEBA) to limit misuse and increase detection visibility.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":382,"question":"A risk owner wants to reduce the likelihood of successful social engineering attacks. Which mitigation is MOST directly aligned?","options":["Run targeted security awareness with phishing simulations and reinforce reporting workflows with measurable metrics.","Implement tape backups and offsite storage to ensure data can be recovered regardless of how compromise occurs.","Deploy RAID for storage redundancy to reduce disk failure probability and increase system availability levels.","Purchase additional cyber insurance to transfer financial impact if attackers successfully compromise user accounts."],"correctIndex":0,"explanation":"Awareness training with simulations directly targets user susceptibility and reduces likelihood. Backups reduce impact; RAID is availability; insurance transfers impact.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 8.html"},{"id":383,"question":"A company identifies that a legacy business process cannot be redesigned quickly, so it chooses to reduce exposure by limiting when and where the process is executed. What mitigation approach is being applied?","options":["Risk reduction via administrative controls that constrain operating conditions and reduce the attack surface window.","Risk avoidance via elimination of the process entirely so the exposure category is removed from the environment.","Risk transference via a contract that shifts all operational responsibility and liabilities to an external party.","Risk acceptance via explicit sign-off to do nothing, with no change to operations or monitoring requirements."],"correctIndex":0,"explanation":"Constraining when/where an activity happens is administrative risk reduction (reducing exposure). Avoidance would eliminate the activity entirely.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":384,"question":"A company is validating that mitigations are actually effective. Which activity provides the BEST evidence of control effectiveness over time?","options":["Continuous monitoring with metrics, control testing results, and periodic audits mapped to control objectives.","A one-time screenshot of a configuration page showing the setting was enabled at an unknown prior date.","A verbal statement from a system owner that controls are working, without logs, metrics, or test artifacts.","An unsigned spreadsheet that lists controls but does not show implementation status or validation outcomes."],"correctIndex":0,"explanation":"Ongoing metrics, testing, and audit evidence demonstrate sustained effectiveness. One-time screenshots or verbal statements are weak evidence in governance.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":385,"question":"A company needs a mitigation technique to prevent configuration drift on hardened servers. Which option is MOST appropriate?","options":["Use configuration management with desired-state enforcement and continuous compliance scanning against baselines.","Allow local admins to customize settings to improve flexibility and track changes only when incidents occur.","Disable patch management to prevent unexpected changes and rely solely on network controls for protection.","Move all server configuration steps to ad-hoc runbooks and prohibit automated tooling to reduce complexity."],"correctIndex":0,"explanation":"Desired-state configuration management and baseline scanning prevent drift and quickly detect deviations, supporting consistent hardening and risk reduction.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 8.html"},{"id":386,"question":"A risk team is asked to recommend a mitigation for web-based attacks that can be deployed quickly while longer-term application fixes are scheduled. What is the BEST short-term compensating control?","options":["Deploy a WAF with tuned rules and monitoring to reduce exploit success while developers remediate root causes.","Disable TLS entirely so payload inspection is easier and remove encryption barriers for network monitoring tools.","Move the application to an unmanaged hosting provider to avoid internal change control and accelerate releases.","Require users to change passwords weekly because frequent changes directly prevent SQL injection and XSS attacks."],"correctIndex":0,"explanation":"A WAF is a common compensating control for web apps, reducing likelihood/impact of attacks while permanent fixes are implemented. Password changes do not stop injection/XSS.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 8.html"},{"id":387,"question":"A company wants to mitigate risk by removing a risky service entirely from its environment. Which risk response does this represent?","options":["Risk avoidance by eliminating the exposure source and removing the associated threat surface from operations.","Risk acceptance by documenting the risk and proceeding with operations without deploying additional controls.","Risk transference by purchasing insurance and continuing the service with no operational or technical changes.","Risk reduction by deploying controls that lower likelihood or impact while keeping the service operational."],"correctIndex":0,"explanation":"Avoidance means removing the activity/system/service that creates the risk. Reduction keeps it but controls it; acceptance tolerates; transference shifts impact.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":388,"question":"Your policy says, “Encrypt sensitive data in transit.” During a readiness audit, a team asks what proves compliance. Which artifact BEST makes the policy testable?","options":["A standard specifying TLS versions, cipher suites, and certificate requirements","A guideline suggesting encryption when practical based on team preferences","A diagram showing where sensitive data flows between apps and databases","A procedure describing how to request an exception for urgent deployments"],"correctIndex":0,"explanation":"Standards create measurable requirements that can be validated (TLS version/ciphers/certs), unlike guidelines or diagrams.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":389,"question":"An auditor rejects your access review evidence because it is only screenshots with no ownership or dates. You need a durable fix that will pass future audits. What is BEST?","options":["Use a system-of-record workflow with approvers, timestamps, and immutable logs","Collect more screenshots quarterly and save them to a shared drive folder","Ask managers to verbally attest reviews occurred and document it in meeting notes","Pause access reviews until a new GRC tool is purchased and fully configured"],"correctIndex":0,"explanation":"Evidence must be attributable and time-bound; a tracked workflow with approvals and logs provides audit-quality proof.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Full Review.html"},{"id":390,"question":"A vendor must administer only one cloud app for 30 days. The vendor requests tenant-wide admin to avoid delays. Which solution BEST meets least privilege and reduces standing access?","options":["Scoped RBAC for the app plus time-bound elevation through PAM/JIT approval","A shared admin account with a long password rotated monthly by the help desk","Grant Global Admin, then review their activity logs at the end of the month","Allow access from any IP if they use CAPTCHA and a strong password policy"],"correctIndex":0,"explanation":"Least privilege is achieved with scoped roles and short-lived elevation; PAM/JIT reduces standing privileges and exposure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":391,"question":"The SOC sees a workstation making HTTPS requests every 60 seconds to a brand-new domain with low reputation. You suspect C2 but must minimize disruption. What control MOST directly limits impact right now?","options":["Enforce egress allow-listing and DNS security to block rare outbound destinations","Disable TLS inspection so analysts cannot see encrypted traffic and reduce alerts","Increase internet bandwidth to reduce latency and shorten investigation timelines","Move the workstation into the same VLAN as servers to simplify monitoring paths"],"correctIndex":0,"explanation":"Egress/DNS controls disrupt C2 and exfil routes quickly, with less broad disruption than blanket port blocks.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":392,"question":"A critical VM is suspected compromised but must remain online for billing. Your IR plan requires preserving volatile evidence. What is the BEST first step?","options":["Capture volatile data and snapshot memory before containment actions change state","Power off the VM to preserve the disk image and stop attacker processes quickly","Rebuild the VM from gold image immediately to restore trust and reduce downtime","Enable additional logging now and rely on future events to reconstruct activity"],"correctIndex":0,"explanation":"Volatile evidence (memory, connections, processes) disappears quickly; capture it first before actions that alter state.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Full Review.html"},{"id":393,"question":"A DevOps team wants mutual authentication for internal APIs without shared secrets and with automated rotation. Which option BEST fits?","options":["mTLS using internal CA-issued certificates with short lifetimes and automation","A single PSK shared across all services and rotated annually through tickets","HTTP Basic authentication over TLS using long-lived service passwords only","Kerberos without managing SPNs, ticket lifetimes, or service key rotation steps"],"correctIndex":0,"explanation":"mTLS provides mutual authentication with asymmetric keys and supports automation with short-lived certificates.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":394,"question":"A customer portal returns “syntax error near SELECT” when special characters are entered. The team proposes a WAF rule to block apostrophes. What is the BEST remediation?","options":["Use parameterized queries and proper server-side input handling for database calls","Block special characters at the WAF and disable detailed error messages in prod","Move the database into a private subnet and keep the application logic unchanged","Add a warning banner telling users not to enter certain characters in the form"],"correctIndex":0,"explanation":"Parameterized queries address the root cause by separating code from data; WAF-only controls are incomplete and bypassable.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":395,"question":"EDR shows a process creating scheduled tasks, disabling AV updates, and modifying registry run keys. No ransomware encryption is observed yet. Which technique is MOST likely?","options":["Persistence and defense evasion through tampering with security control settings","Credential stuffing against VPN portals using breached username/password pairs","Bluejacking over Bluetooth to push unsolicited messages to nearby devices","Watering-hole compromise of a website that employees frequently visit at lunch"],"correctIndex":0,"explanation":"Scheduled tasks + AV tampering + run keys strongly indicate persistence and defense evasion behaviors.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Full Review.html"},{"id":396,"question":"Two internal zones must communicate, but only one application flow is permitted. The business wants the smallest blast radius if a workstation is compromised. What is the BEST design?","options":["Microsegmentation with default-deny rules and only the required service path allowed","A flat network with host firewalls and broad routing to simplify connectivity needs","A site-to-site VPN between the zones so all traffic is encrypted across segments","NAT both zones into one subnet so tools see all hosts as a single address range"],"correctIndex":0,"explanation":"Microsegmentation enforces least privilege for east-west traffic and limits lateral movement to the single required flow.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":397,"question":"Your SIEM alerts heavily on normal admin actions, causing alert fatigue. You must reduce noise without losing detection coverage. What is the BEST approach?","options":["Tune rules using baselines, allow-lists for expected behavior, and log enrichment","Disable detections for admin actions since privileged activity is always expected","Stop ingesting authentication logs so there are fewer events to correlate daily","Replace the SIEM vendor and import the same ruleset without any customization"],"correctIndex":0,"explanation":"Baselining, allow-lists, and enrichment reduce false positives while retaining meaningful detection and correlation.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Full Review.html"},{"id":398,"question":"A vendor claims compliance but refuses to share evidence due to confidentiality. You need a contractual control that enables verification. What clause is BEST?","options":["Right-to-audit and evidence-sharing language with confidentiality and scoping terms","A clause requiring encryption at rest for vendor-managed storage and databases only","A clause requiring quarterly feature roadmaps to be shared with your IT department","A clause requiring vendor staff to use corporate email accounts while on projects"],"correctIndex":0,"explanation":"Right-to-audit and evidence-sharing clauses enable independent verification while preserving confidentiality through scoped terms.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":399,"question":"A company wants per-user authentication on Wi-Fi, strong encryption, and no shared password. The environment supports certificate issuance. What is BEST?","options":["WPA3-Enterprise with 802.1X using EAP-TLS backed by a RADIUS service","WPA2-Personal with a long passphrase rotated quarterly and posted in the office","WEP with MAC filtering and hidden SSID to reduce unauthorized device access","Open Wi-Fi with captive portal and SMS verification for each daily connection"],"correctIndex":0,"explanation":"WPA3-Enterprise + EAP-TLS provides strong per-user auth and avoids shared secrets; certificates are highly resistant to phishing.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":400,"question":"A storage bucket with regulated data was accidentally made public through a console change. You must prevent recurrence and detect drift quickly. What is BEST?","options":["Policy-as-code guardrails blocking public access plus continuous configuration monitoring","A quarterly manual checklist review of permissions performed by one cloud admin","An awareness email reminding engineers to never change permissions on buckets","Disabling cloud storage entirely and moving all files back to on-prem servers"],"correctIndex":0,"explanation":"Guardrails (prevent) plus continuous monitoring (detect drift) is the strongest control for fast-moving cloud environments.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":401,"question":"Analytics teams need to work with large datasets containing PII, but privacy risk must be reduced and re-identification tightly controlled. What is BEST?","options":["Tokenize or anonymize data and restrict re-identification through controlled processes","Store datasets unencrypted to maximize performance and rely on network controls only","Use only full-disk encryption and share raw datasets broadly within the department","Compress datasets before sharing to reduce size and limit content visibility slightly"],"correctIndex":0,"explanation":"Tokenization/anonymization reduces exposure while enabling analytics; re-identification should be gated and audited.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":402,"question":"A data center has repeated tailgating during shift changes. Security needs a control that prevents piggybacking while maintaining throughput. What is BEST?","options":["Mantrap with badge plus biometric verification and anti-passback enforcement rules","A single door with a camera for after-the-fact review and a sign to deter entry","A visitor sign-in sheet and a printed badge that employees can pick up anytime","Rack locks only, while leaving facility entrances unmanaged to avoid bottlenecks"],"correctIndex":0,"explanation":"Mantraps and anti-passback enforce single-person entry while still allowing controlled flow during high traffic periods.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":403,"question":"After collecting a disk image, legal asks whether evidence handling will stand up in court. What practice BEST supports chain of custody?","options":["Record collection, transfers, storage conditions, and handler signatures for each step","Encrypt the evidence with a password known only to the incident commander on call","Copy the evidence to several USB drives so analysts can work in parallel quickly","Upload the evidence to a shared drive so the whole team can access it freely"],"correctIndex":0,"explanation":"Chain of custody is maintained by documented handling and integrity across time and personnel, not by encryption alone.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":404,"question":"Your org wants to stop unknown executables while allowing approved apps. You must reduce malware execution even if signatures lag. What control is BEST?","options":["Application allow-listing with code signing enforcement and a staged approval process","Antivirus only with weekly full scans and daily signature updates on endpoints","Disable UAC prompts to reduce friction during installs and improve user experience","Grant users local admin rights so they can install tools without help desk delays"],"correctIndex":0,"explanation":"Allow-listing with signing is preventive and blocks unknown code, reducing reliance on detection-only security.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Full Review.html"},{"id":405,"question":"Two sites need a secure tunnel for internal subnets with encryption and integrity. The team suggests AH to save overhead. What configuration BEST meets requirements?","options":["IPsec ESP in tunnel mode using strong encryption and modern DH key exchange groups","IPsec AH in transport mode using MD5 integrity for compatibility with older devices","Telnet over restricted firewall rules since source IPs are controlled and trusted","FTP with complex passwords and account lockout since files are internal and small"],"correctIndex":0,"explanation":"ESP provides confidentiality + integrity; tunnel mode is typical for site-to-site; AH does not encrypt.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":406,"question":"After quarterly phishing training, leadership wants proof that risk is decreasing—not just that people attended. Which metric BEST demonstrates improvement?","options":["Phishing simulation click and credential rates trended over time with consistent campaigns","Total count of emails received monthly across the organization and all business units","Number of employees who completed training modules with no behavioral measurement","Quantity of posters placed in hallways and break rooms during each awareness push"],"correctIndex":0,"explanation":"Behavioral outcomes from controlled simulations best show whether user susceptibility is decreasing.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Full Review.html"},{"id":407,"question":"A scanner flags a critical CVE on a server, but inventory shows the vulnerable service is not installed. Your team still wants to patch immediately. What is BEST?","options":["Validate exposure, document evidence, and mark as false positive with tracked rationale","Patch every host in the subnet to be safe because scanning is usually accurate enough","Ignore the result entirely because scanners often report issues that do not exist here","Disable scanning on that asset so it stops generating confusing vulnerability tickets"],"correctIndex":0,"explanation":"Validate findings against inventory/exposure; document decisions with evidence so remediation is risk-based and auditable.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Full Review.html"},{"id":408,"question":"A project proposes removing internal segmentation because all users authenticate once at VPN login. Security recommends a Zero Trust approach instead. Which statement BEST reflects Zero Trust?","options":["Continuously evaluate access using identity, device posture, and context for each request","Treat internal traffic as trusted by default once the user has logged in successfully","Allow broad access within subnets to reduce complexity and improve performance quickly","Rely on perimeter controls only because threats are assumed to be external attackers"],"correctIndex":0,"explanation":"Zero Trust avoids implicit trust based on location; it continuously evaluates and enforces least privilege per request.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Full Review.html"},{"id":409,"question":"Your domain is being spoofed in phishing campaigns. You want to reduce spoofing and improve validation for recipients. Which configuration BEST addresses this?","options":["Deploy SPF, DKIM, and DMARC with enforcement and reporting for aligned authentication","Enable TLS for email transport only so messages are encrypted in transit across hops","Use S/MIME for internal mail only and skip domain alignment controls for external mail","Add a disclaimer banner to external mail advising users to verify senders carefully"],"correctIndex":0,"explanation":"SPF/DKIM validate sender and content; DMARC enforces alignment with policy and provides reporting to reduce spoofing.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":410,"question":"A business unit requests broad access to a confidential dataset “for future projects.” There is no current use case and the data contains PII. What is BEST?","options":["Require documented need-to-know, grant least-privilege access, and time-bound approvals","Grant access now but log usage so any misuse can be investigated after the fact later","Grant access if they agree to use stronger passwords and complete annual training first","Move the dataset to a new share and email a link so the team can access it easily"],"correctIndex":0,"explanation":"Need-to-know and least privilege are primary controls; time-bound approvals reduce standing access and insider risk.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Full Review.html"},{"id":411,"question":"Threat intel says a ransomware group targets your industry using stolen VPN creds and living-off-the-land tools. You want meaningful action, not fear-driven changes. What is BEST FIRST step?","options":["Map reported TTPs to detections and controls, then validate coverage with testing exercises","Block the entire country where the group is believed to operate to reduce exposure","Buy a new endpoint product immediately to ensure ransomware cannot execute anywhere","Wait for a confirmed incident before changing monitoring or adjusting defensive posture"],"correctIndex":0,"explanation":"Operationalize intel by translating TTPs into detections/control improvements and validating coverage via tests.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + Full Review.html"},{"id":412,"question":"A finance team is repeatedly targeted by credential phishing. You want passwordless authentication with strong phishing resistance. Which option is BEST?","options":["FIDO2/WebAuthn with hardware-backed credentials or platform authenticators for users","SMS one-time codes for logins because the phone carrier is trusted and available always","Security questions stored as hashed answers so attackers cannot easily read them back","Email-delivered TOTP codes required only for admins since finance is not privileged"],"correctIndex":0,"explanation":"FIDO2/WebAuthn is phishing-resistant by design (origin binding + asymmetric keys), unlike SMS or knowledge-based factors.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":413,"question":"You suspect lateral movement via Windows administrative shares (SMB). You want detection that correlates authentication and SMB sessions. Which logs are MOST important?","options":["Windows security authentication events plus SMB session/audit logs from endpoints and servers","DNS query logs only, because all lateral movement begins with name resolution activity","Web proxy logs only, because SMB traffic is typically routed through HTTP proxy services","Printer spooler logs only, because admin shares rely on print services for access"],"correctIndex":0,"explanation":"Lateral movement via SMB involves authentication and SMB sessions; security logs plus SMB auditing provide the best signal.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Full Review.html"},{"id":414,"question":"A workstation is compromised in the user VLAN. You must reduce blast radius so it cannot reach the database subnet. What control MOST directly accomplishes this?","options":["Default-deny east-west rules with segmentation and explicit allow paths to critical services","Centralized DHCP reservations for all workstations to simplify IP-based monitoring at scale","A faster internet circuit to reduce attacker dwell time and shorten exfiltration windows","Shared local admin passwords to speed up IT support and reduce credential management work"],"correctIndex":0,"explanation":"Segmentation with default-deny limits lateral movement and enforces explicit access paths to crown-jewel systems.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":415,"question":"A baseline requires disabling legacy SMB versions. Leadership asks how you will prove compliance continuously, not just once. What is BEST?","options":["Continuous configuration assessment with drift detection and compliance reporting dashboards","An email asking users to confirm they changed settings manually on their own machines","Assume compliance since the baseline document was published on the intranet for teams","Spot-check a few endpoints yearly without tracking changes after patch cycles occur"],"correctIndex":0,"explanation":"Continuous assessment detects drift as systems change, providing strong ongoing assurance beyond a one-time check.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"Sec + Full Review.html"},{"id":416,"question":"A service outage occurred because a TLS certificate expired. You need to prevent repeats while supporting short certificate lifetimes. What is BEST?","options":["Automate certificate lifecycle management with monitoring, alerting, and staged renewal","Increase certificate validity to ten years so renewal rarely needs to happen at all","Disable certificate validation on clients so expired certificates do not break sessions","Remove TLS and use plaintext internally because the network is already considered trusted"],"correctIndex":0,"explanation":"Automation + monitoring prevents outages and supports safer short-lived certificates without manual failures.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + Full Review.html"},{"id":417,"question":"A mobile app stores an API token in plaintext local storage. The token grants access to customer data. What remediation BEST reduces risk?","options":["Store the token in the platform keystore/secure enclave and rotate tokens routinely","Base64-encode the token so it is not readable at a glance in local storage files","Move the token into a config file protected only by standard file permissions on disk","Hardcode multiple backup tokens in the app so users never lose connectivity access"],"correctIndex":0,"explanation":"Encoding is not protection. Use secure storage and rotate tokens to reduce exposure if a device or app storage is compromised.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":418,"question":"A host is suspected infected and communicating over 443. Business wants minimal disruption and no broad firewall changes. What containment action is BEST?","options":["Isolate the host using EDR/network quarantine while preserving evidence for analysis","Block all outbound TCP 443 across the organization until investigation is completed","Reboot the host to clear memory and remove attacker tools from active processes","Disable the SIEM rule so the incident stops generating alerts during triage work"],"correctIndex":0,"explanation":"Targeted isolation contains the incident with minimal blast radius and retains forensic opportunity.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Full Review.html"},{"id":419,"question":"A popular open-source library is reported compromised upstream. Your CI/CD pulls dependencies automatically. What immediate control BEST reduces exposure?","options":["Pin versions, verify artifacts by signature/hash, and restrict repositories to trusted sources","Disable code review so developers can push quick changes to production without delay","Allow downloads from any mirror so builds are fast even if sources change often","Stop using version control so attackers cannot learn which dependencies you rely upon"],"correctIndex":0,"explanation":"Pinning and verifying artifacts prevents malicious upstream changes from silently entering builds; repository controls reduce risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":420,"question":"A terminated employee can still access a cloud resource because their role assignment remains active. Passwords were reset but access persists. What failed MOST likely?","options":["Offboarding deprovisioning tied to HR events and identity source-of-truth synchronization","Password complexity policy missing history requirements and minimum length enforcement","Firewall rules too permissive for inbound internet traffic to cloud management portals","Full-disk encryption not enabled on the user’s previous laptop used during employment"],"correctIndex":0,"explanation":"Role assignments are authorization artifacts; offboarding must revoke access/roles based on HR lifecycle events and IAM processes.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":421,"question":"A manager asks whether a new detection rule counts as a detective technical control. Which example BEST fits that classification?","options":["A SIEM correlation rule alerting on impossible travel sign-ins using multiple data points","A policy requiring annual awareness training and signed acknowledgment by all staff members","A mantrap preventing two people from entering a secure area at the same time each entry","A secure coding standard requiring parameterized queries for all database interactions"],"correctIndex":0,"explanation":"SIEM correlation is a detective technical control; policy is administrative, mantrap is physical preventive, coding standard is preventive.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Full Review.html"},{"id":422,"question":"Regulated data must not be emailed externally, but internal collaboration should remain smooth. Security wants to reduce accidental leaks without blocking normal internal sharing. What is BEST?","options":["DLP with content inspection, internal allow rules, and user coaching for risky actions","Disable email entirely and require all communication through phone calls and meetings","Encrypt all outbound email automatically without inspecting content or recipient context","Require users to rename sensitive files before sending them outside to reduce mistakes"],"correctIndex":0,"explanation":"DLP can enforce internal vs external handling based on content/labels and provide coaching or blocking for risky behavior.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":423,"question":"A payment platform has RTO 2 hours and RPO 15 minutes. Leadership wants a realistic design that meets these objectives. What is BEST?","options":["Warm/hot design with frequent replication and tested failover procedures for the service","Cold site with weekly tape backups stored offsite and manual rebuild documentation steps","No redundancy but a detailed runbook to rebuild the environment in another region later","Monthly full backups with encryption and a plan to restore whenever time permits later"],"correctIndex":0,"explanation":"Tight RTO/RPO requires near-real-time replication and practiced failover—typically warm/hot, not cold/manual restore.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":424,"question":"UEBA flags a user downloading 20x their baseline data volume, then authenticating from a new geography. The user claims they are traveling. What is BEST immediate action?","options":["Validate context, enforce step-up auth, and restrict session/data access pending review","Disable UEBA alerts because behavior analytics frequently generates false positives anyway","Block all downloads for every user until the manager approves global policy changes soon","Assume malicious intent and wipe the device immediately without collecting any evidence"],"correctIndex":0,"explanation":"Use context to validate and apply conditional access controls (step-up auth/session limits) while investigating, minimizing disruption.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":425,"question":"Secrets are occasionally committed to source control during urgent fixes. You need prevention that works even under pressure. What is BEST?","options":["Pre-commit secret scanning plus centralized secret management and short-lived credentials","A policy telling developers to be careful and avoid committing secrets during emergencies","Storing secrets in comments so they are easy to find later and rotate after releases","Using longer passwords so accidentally committed secrets are harder to guess by attackers"],"correctIndex":0,"explanation":"Tooling and architecture prevent mistakes: pre-commit scanning blocks commits; secret managers and short-lived creds reduce blast radius.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":426,"question":"After containing a malware outbreak, IT wants to reconnect systems quickly. Security must ensure eradication and reduce recurrence. What is BEST next step?","options":["Remove persistence, fix root cause, patch weaknesses, and validate with re-scans before return","Restore from backup immediately without checking whether backups contain the same malware","Reconnect systems and rely on monitoring to catch any remaining activity after users return","Lower alert thresholds so the SOC receives fewer notifications while operations stabilize"],"correctIndex":0,"explanation":"Eradication means removing persistence, addressing root cause, patching exploited weaknesses, and validating clean state before recovery.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Full Review.html"},{"id":427,"question":"What does **BIA** stand for in business continuity planning?","options":["Business Impact Analysis","Baseline Integrity Assessment","Binary Incident Attribution","Bandwidth Inspection Authorization"],"correctIndex":0,"explanation":"BIA (Business Impact Analysis) identifies critical functions and the impact of disruptions to set recovery priorities (RTO/RPO/MTD).","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":428,"question":"In risk calculations, **SLE** most commonly means:","options":["Single Loss Expectancy","System Logging Endpoint","Security Level Estimate","Session Link Encryption"],"correctIndex":0,"explanation":"SLE (Single Loss Expectancy) is the expected loss from a single occurrence of a risk event.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":429,"question":"In quantitative risk, **ALE** is:","options":["Annual Loss Expectancy","Asset Loss Evaluation","Authorized Log Export","Applied Layer Encryption"],"correctIndex":0,"explanation":"ALE (Annual Loss Expectancy) is the expected annualized loss, typically SLE × ARO.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":430,"question":"In risk frequency modeling, **ARO** stands for:","options":["Annual Rate of Occurrence","Authorized Response Option","Aggregate Risk Objective","Applied Routing Overlay"],"correctIndex":0,"explanation":"ARO (Annual Rate of Occurrence) estimates how often a risk event occurs per year.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + acronyms.html"},{"id":431,"question":"In recovery planning, **RTO** means:","options":["Recovery Time Objective","Remote Transfer Operation","Risk Tolerance Output","Routing Table Optimization"],"correctIndex":0,"explanation":"RTO (Recovery Time Objective) is the target time to restore a system or process after a disruption.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + acronyms.html"},{"id":432,"question":"In recovery planning, **RPO** means:","options":["Recovery Point Objective","Remote Packet Output","Risk Priority Order","Routing Path Override"],"correctIndex":0,"explanation":"RPO (Recovery Point Objective) is the acceptable data loss measured in time (how far back you can restore).","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + acronyms.html"},{"id":433,"question":"In BCP/DR, **MTD** stands for:","options":["Maximum Tolerable Downtime","Managed Threat Detection","Minimum Transfer Delay","Maximum Ticket Duration"],"correctIndex":0,"explanation":"MTD (Maximum Tolerable Downtime) is the absolute limit for how long a process can be down.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + acronyms.html"},{"id":434,"question":"In recovery discussions, **WRT** means:","options":["Work Recovery Time","Wireless Routing Table","Web Response Threshold","Write Retention Time"],"correctIndex":0,"explanation":"WRT (Work Recovery Time) is the time to restore business operations to normal productivity after systems are back.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":435,"question":"A control mapping to security requirements often references **CIA** meaning:","options":["Confidentiality, Integrity, Availability","Control, Inspection, Authorization","Cryptography, Identity, Auditing","Compliance, Investigation, Assurance"],"correctIndex":0,"explanation":"CIA is the security triad: confidentiality, integrity, and availability.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":436,"question":"For access control, **RBAC** stands for:","options":["Role-Based Access Control","Risk-Based Authorization Control","Rule-Based Account Configuration","Resource Baseline Access Catalog"],"correctIndex":0,"explanation":"RBAC assigns permissions to roles, then users inherit privileges through role membership.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + acronyms.html"},{"id":437,"question":"For access control, **ABAC** stands for:","options":["Attribute-Based Access Control","Application-Based Account Control","Audit-Based Access Calculation","Adaptive Baseline Authorization Criteria"],"correctIndex":0,"explanation":"ABAC evaluates attributes (user, resource, environment) to make authorization decisions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + acronyms.html"},{"id":438,"question":"In identity systems, **MFA** stands for:","options":["Multi-Factor Authentication","Managed Firewall Appliance","Modular Forensic Analysis","Mandatory File Authorization"],"correctIndex":0,"explanation":"MFA uses two or more factors (know/have/are) to strengthen authentication.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + acronyms.html"},{"id":439,"question":"A trusted third party issuing certificates is a **CA**, which means:","options":["Certificate Authority","Control Auditor","Cryptographic Agent","Compliance Attestation"],"correctIndex":0,"explanation":"A Certificate Authority issues and signs digital certificates used in PKI.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":440,"question":"A policy defining expected uptime and response times is an **SLA**, meaning:","options":["Service-Level Agreement","Security Logging Addendum","System Lifecycle Authorization","Software License Amendment"],"correctIndex":0,"explanation":"SLA specifies service performance metrics and remedies/penalties for failure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"Sec + acronyms.html"},{"id":441,"question":"A confidential sharing contract is an **NDA**, meaning:","options":["Non-Disclosure Agreement","Network Data Authorization","Named Domain Allocation","New Device Attestation"],"correctIndex":0,"explanation":"NDA protects confidential information from unauthorized disclosure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + acronyms.html"},{"id":442,"question":"A secure hash used to ensure file integrity is commonly **SHA**, meaning:","options":["Secure Hash Algorithm","System Hardened Access","Session Header Authorization","Secure Host Allocation"],"correctIndex":0,"explanation":"SHA refers to hash functions (e.g., SHA-256) used for integrity verification.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":443,"question":"A symmetric encryption standard acronym **AES** stands for:","options":["Advanced Encryption Standard","Automated Endpoint Security","Authenticated Email Sender","Adaptive Encryption System"],"correctIndex":0,"explanation":"AES is a widely used symmetric block cipher used for data at rest and in transit.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":444,"question":"A widely used public-key algorithm acronym **RSA** stands for:","options":["Rivest–Shamir–Adleman","Random Session Algorithm","Remote Security Attestation","Rapid Stream Authentication"],"correctIndex":0,"explanation":"RSA is an asymmetric cryptosystem used for encryption and signatures.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":445,"question":"A common key exchange acronym **DH** stands for:","options":["Diffie–Hellman","Data Header","Domain Handoff","Dynamic Hashing"],"correctIndex":0,"explanation":"Diffie–Hellman enables key exchange over an untrusted network (often with ephemeral variants like DHE/ECDHE).","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":446,"question":"A security monitoring system acronym **SIEM** stands for:","options":["Security Information and Event Management","System Integrity and Endpoint Monitoring","Secure Identity and Email Management","Service Incident and Escalation Model"],"correctIndex":0,"explanation":"SIEM aggregates logs, correlates events, and supports alerting and investigations.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":447,"question":"An endpoint detection tool acronym **EDR** stands for:","options":["Endpoint Detection and Response","Encrypted Data Routing","Event-Driven Remediation","External Domain Resolution"],"correctIndex":0,"explanation":"EDR provides endpoint telemetry, detection, and response actions like isolation/quarantine.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":448,"question":"In cloud security posture tooling, **CSPM** stands for:","options":["Cloud Security Posture Management","Centralized Security Policy Module","Cloud Service Patch Mechanism","Configurable Security Proxy Model"],"correctIndex":0,"explanation":"CSPM detects cloud misconfigurations and policy drift across cloud resources.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + acronyms.html"},{"id":449,"question":"A common DLP acronym **DLP** stands for:","options":["Data Loss Prevention","Data Link Protocol","Dynamic Login Provisioning","Distributed Log Processing"],"correctIndex":0,"explanation":"DLP reduces unauthorized data exfiltration through monitoring and control policies.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + acronyms.html"},{"id":450,"question":"A network segmentation concept acronym **ACL** stands for:","options":["Access Control List","Automated Compliance Ledger","Application Control Layer","Authenticated Connection Link"],"correctIndex":0,"explanation":"ACLs define permit/deny rules for traffic or permissions for objects.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + acronyms.html"},{"id":451,"question":"A secure remote access acronym **VPN** stands for:","options":["Virtual Private Network","Verified Protocol Node","Virtual Packet Negotiation","Variable Path Networking"],"correctIndex":0,"explanation":"VPN provides encrypted tunnels for remote access or site-to-site connectivity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":452,"question":"A secure web transport acronym **TLS** stands for:","options":["Transport Layer Security","Trusted Link Service","Token Login Standard","Tunneled Local Session"],"correctIndex":0,"explanation":"TLS secures data in transit and replaces older SSL versions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + acronyms.html"},{"id":453,"question":"DNS encryption acronym **DoH** stands for:","options":["DNS over HTTPS","Domain over Host","Data on Hypertext","DNS over Handshake"],"correctIndex":0,"explanation":"DoH sends DNS queries over HTTPS (commonly port 443) for privacy and integrity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":454,"question":"DNS encryption acronym **DoT** stands for:","options":["DNS over TLS","Domain over Transport","Data over Token","DNS over Tunneling"],"correctIndex":0,"explanation":"DoT sends DNS queries over TLS (commonly port 853) to protect DNS traffic.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":455,"question":"For threat intel, **IOC** commonly stands for:","options":["Indicator of Compromise","Identity Operations Center","Internal Object Catalog","Incident Output Category"],"correctIndex":0,"explanation":"IOCs are observable artifacts like hashes, domains, IPs, and file paths linked to malicious activity.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + acronyms.html"},{"id":456,"question":"For adversary behavior, **TTPs** stands for:","options":["Tactics, Techniques, and Procedures","Tokens, Transfers, and Policies","Threat Tools and Platforms","Telemetry, Tuning, and Protection"],"correctIndex":0,"explanation":"TTPs describe how adversaries operate: their goals (tactics), methods (techniques), and playbooks (procedures).","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + acronyms.html"},{"id":457,"question":"A web protection control acronym **WAF** stands for:","options":["Web Application Firewall","Wide Area Forwarder","Web Access Framework","Wireless Authentication Filter"],"correctIndex":0,"explanation":"WAF filters HTTP/S traffic to mitigate common web attacks (e.g., injection, XSS) as a compensating control.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + acronyms.html"},{"id":458,"question":"A privilege management acronym **PAM** stands for:","options":["Privileged Access Management","Protected Account Mechanism","Policy Audit Module","Password Authorization Model"],"correctIndex":0,"explanation":"PAM manages privileged accounts with vaulting, JIT elevation, and session recording.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + acronyms.html"},{"id":459,"question":"In cryptography, **HMAC** stands for:","options":["Hash-based Message Authentication Code","Host-managed Access Control","High-memory Application Cache","Hardware Mode Authorization Check"],"correctIndex":0,"explanation":"HMAC uses a hash function with a secret key to provide integrity and authenticity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":460,"question":"A common wireless encryption acronym **WPA3** expands to:","options":["Wi-Fi Protected Access 3","Wireless Privacy Algorithm 3","Web Proxy Authorization 3","Wideband Protected Attachment 3"],"correctIndex":0,"explanation":"WPA3 is the modern Wi-Fi security standard that improves protection over WPA2.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":461,"question":"A formal agreement describing secure system interconnections is an **ISA**, meaning:","options":["Interconnection Security Agreement","Internal Security Assessment","Integrated Service Authorization","Incident Severity Assignment"],"correctIndex":0,"explanation":"ISA documents technical and security requirements when connecting systems between organizations.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":462,"question":"A common secure email protocol acronym **S/MIME** stands for:","options":["Secure/Multipurpose Internet Mail Extensions","System/Managed Identity Messaging Exchange","Secure/Modular Internet Message Encapsulation","Service/Multipoint Integrated Mail Encryption"],"correctIndex":0,"explanation":"S/MIME provides email signing and encryption using certificates.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":463,"question":"Which aspect of security assurance specifically relies on cryptographic digital signatures unique to each user to prove that a message or document was sent by the claimed sender?","options":["Confidentiality","Non-repudiation","Availability","Discretionary access model"],"correctIndex":1,"explanation":"Non-repudiation ensures that a person cannot deny the validity of their actions or communications. It uses cryptographic digital signatures unique to each user to provide proof of origin and integrity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec+Day1Quiz.html"},{"id":464,"question":"An organization is evaluating its current security posture against the National Institute of Standards and Technology (NIST) Cybersecurity Framework (CSF). What type of analysis are they performing?","options":["Risk assessment","Gap analysis","Vulnerability analysis","BIA (Business Impact Analysis)"],"correctIndex":1,"explanation":"A gap analysis checks how well an organization's security setup matches a cybersecurity framework like the NIST CSF (National Institute of Standards and Technology Cybersecurity Framework) to identify missing, incomplete, or poorly configured controls.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":465,"question":"Which function of the NIST Cybersecurity Framework (CSF) focuses on developing security policies, evaluating risks, threats, and vulnerabilities, and recommending controls to mitigate them?","options":["Protect","Detect","Identify","Respond"],"correctIndex":2,"explanation":"The 'Identify' function of the NIST CSF (National Institute of Standards and Technology Cybersecurity Framework) involves developing security policies and capabilities, as well as evaluating risks, threats, and vulnerabilities to recommend security controls.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":466,"question":"What unique phase distinguishes the modern Identity and Access Management (IAM) framework from the earlier AAA framework?","options":["Identification","Authentication","Authorization","Accounting"],"correctIndex":0,"explanation":"The modern IAM (Identity and Access Management) framework includes standard AAA (Authentication, Authorization, and Accounting) functions PLUS the Identification component, which was omitted in the earlier framework.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":467,"question":"A system enforces pre-determined security rules and labels (such as Secret or Top Secret) that cannot be altered by any individual user within the system. Which access control model is being utilized?","options":["DAC (Discretionary Access Control)","RBAC (Role-Based Access Control)","MAC (Mandatory Access Control)","ABAC (Attribute-Based Access Control)"],"correctIndex":2,"explanation":"In a MAC (Mandatory Access Control) model, access rights are predetermined by system-enforced rules and security labels; they cannot be modified by any standard user within the system.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec+Day1Quiz.html"},{"id":468,"question":"Security guards and user security awareness training programs fall under which control category?","options":["Technical controls","Managerial controls","Operational controls","Physical controls"],"correctIndex":2,"explanation":"Operational controls are security measures implemented primarily by people rather than automated systems. Examples include security guards and training programs.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":469,"question":"A network administrator configures an automated firewall rule and sets up permission policies to block an active security attack from succeeding. What functional control type is this?","options":["Detective control","Preventive control","Corrective control","Deterrent control"],"correctIndex":1,"explanation":"Preventive controls (such as firewall rules, encryption, and permission policies) actively attempt to keep an attack from succeeding. Users do not need to have explicit knowledge of the control for it to function.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":470,"question":"Which functional control type psychologically discourages an intrusion, reduces the motive of an attacker, and explicitly requires users to have knowledge of the control to work effectively?","options":["Deterrent control","Directive control","Compensating control","Technical control"],"correctIndex":0,"explanation":"Deterrent controls psychologically discourage intrusions (e.g., warning signs, login banners, good lighting) and require users to have knowledge of the control to change their motivation.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":471,"question":"Which corporate role is primarily responsible for overall technology strategy and ensuring IT systems align with organizational goals, while also overseeing security policy implementation?","options":["CSO (Chief Security Officer)","CIO (Chief Information Officer)","ISSO (Information Systems Security Officer)","Security Manager"],"correctIndex":1,"explanation":"The CIO (Chief Information Officer) is responsible for the overall technology strategy and aligning IT systems with organization goals, while overseeing the broad implementation of security policies.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec+Day1Quiz.html"},{"id":472,"question":"What security principle refers to an organization taking the necessary reasonable steps to protect its assets, data, and infrastructure to prevent harm or loss?","options":["Liability","Due Care","Non-repudiation","Auditing"],"correctIndex":1,"explanation":"Due Care refers to the baseline responsibility of an organization to actively take reasonable, protective steps to safeguard its assets and data from potential harm.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":473,"question":"A centralized unit within an enterprise continuously monitors network traffic, endpoints, and logs using tools to identify, investigate, contain, and mitigate active security events. What is this unit called?","options":["DevSecOps","CIRT (Cyber Incident Response Team)","SOC (Security Operations Center)","Change Control Board"],"correctIndex":2,"explanation":"The SOC (Security Operations Center) is a centralized organizational and technical unit that continuously monitors and analyzes an organization's security posture to capture alerts and mitigate risks.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec+Day1Quiz.html"},{"id":474,"question":"Which team is specifically tasked with integrating automated security testing into Continuous Integration/Continuous Development (CI/CD) pipelines so that security is a shared responsibility at every stage of software creation?","options":["SOC (Security Operations Center)","CIRT (Cyber Incident Response Team)","DevSecOps (Development, Security, and Operations)","M-of-N Recovery Team"],"correctIndex":2,"explanation":"DevSecOps (Development, Security, and Operations) integrates security directly into the development process, implementing secure coding practices and automated security testing in the CI/CD pipeline.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec+Day1Quiz.html"},{"id":475,"question":"How do modern cyber threats differ significantly from traditional threats of the early internet era?","options":["Modern threats rely purely on signature-based virus detection.","Modern threats have shifted from simple opportunistic vandalism toward structured, well-funded campaigns driven by financial, espionage, and political motives.","Modern threats are exclusively internal and do not attempt remote network infiltration.","Modern threats have lower technical sophistication and capabilities."],"correctIndex":1,"explanation":"Threats have evolved from early opportunistic vandalism and worms into structured, long-term campaigns funded by nation-states or organized crime (such as Advanced Persistent Threats), shifting motivations toward profit, espionage, and warfare.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Sec+Day1Quiz.html"},{"id":476,"question":"A threat actor who uses advanced techniques, holds military or political backing, and conducts prolonged, targeted campaigns while remaining undetected in a network for extended periods is classified as what?","options":["Unskilled attacker","Hacktivist","APT (Advanced Persistent Threat)","Internal unintentional insider"],"correctIndex":2,"explanation":"An APT (Advanced Persistent Threat) describes sophisticated, prolonged, and highly targeted cyberattacks often associated with nation-state actors due to the immense resources and long-term entry goals required.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Sec+Day1Quiz.html"},{"id":477,"question":"What type of attack vector involves leaving infected removable USB flash drives in public spaces, hoping a target will plug them into a corporate machine and execute malicious code?","options":["Watering hole attack","Drop attack","Pharming attack","Typosquatting"],"correctIndex":1,"explanation":"In a drop attack, an attacker leaves infected removable media (like USB drives) in public or workplace areas hoping an unsuspecting user will find it and plug it into a computer system.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec+Day1Quiz.html"},{"id":478,"question":"A user purchases a third-party cloud software application to help complete daily tasks without requesting or obtaining the permission and security analysis of the corporate IT department. What does this describe?","options":["External threat surface","Shadow IT","Baiting attack","Discretionary authorization"],"correctIndex":1,"explanation":"Shadow IT refers to computer hardware or software introduced to the workplace by users without the explicit sanction, procurement review, or security analysis of the IT department.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Sec+Day1Quiz.html"},{"id":479,"question":"What is the total sum of all points where an unauthorized user can try to enter data into or extract data from an environment?","options":["Attack vector","Attack surface","Vulnerability scanner","Trusted platform module"],"correctIndex":1,"explanation":"The attack surface is the total sum of all exposed points (hardware, software, network components) where an unauthorized attacker could try to exploit a vulnerability or interact with data.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec+Day1Quiz.html"},{"id":480,"question":"An automated vulnerability scanner requires a small software component to be explicitly installed on every endpoint device to collect internal data. What type of scanner is this?","options":["Agentless vulnerability scanner","Client-based vulnerability scanner","Passive network sniffer","Discretionary exploit engine"],"correctIndex":1,"explanation":"Client-based vulnerability scanners require an agent (a small software component) to be actively installed on each endpoint device to collect and report detailed system status.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec+Day1Quiz.html"},{"id":481,"question":"A threat actor compromises a local pizza delivery website commonly visited by staff members of a target financial firm to run exploit code on the visitors' systems. What social engineering/reconnaissance strategy is this?","options":["Business Email Compromise (BEC)","Watering hole attack","Pretexting impersonation","Typospoofing"],"correctIndex":1,"explanation":"A watering hole attack targets a specific group of users by identifying and compromising an unsecure third-party website that the targets frequently visit.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec+Day1Quiz.html"},{"id":482,"question":"An attacker registers the domain 'goggle.com' to catch traffic from users who make typographical mistakes while typing the address of a popular search engine. What is this practice called?","options":["Typosquatting","Typospoofing","Pharming","Email spoofing"],"correctIndex":0,"explanation":"Typosquatting involves specifically registering domain names that are slight misspellings or common typographical variations of popular websites to deceive users who make keyboard errors.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":483,"question":"A Cybersecurity Analyst (CySA+) reviews an Nmap result showing TCP 22 open on a Linux jump host used by administrators. Which protocol is most likely expected, and why is it preferred over the legacy alternative?","options":["Secure Shell (SSH); it provides encrypted remote administration instead of cleartext Telnet.","Telnet; it provides encrypted remote administration instead of Secure Shell (SSH).","Remote Desktop Protocol (RDP); it provides encrypted Linux shell access over TCP 22.","Simple Network Management Protocol (SNMP); it provides encrypted command-line administration."],"correctIndex":0,"explanation":"TCP 22 is associated with Secure Shell (SSH), Secure File Transfer Protocol (SFTP), and Secure Copy Protocol (SCP). Telnet commonly uses TCP 23 and is a poor administrative choice because credentials and session data are not protected by default.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":484,"question":"During a hunt, an analyst finds repeated successful logins to network devices over TCP 23. Which finding should be prioritized?","options":["Telnet is exposed, creating a cleartext administrative-access risk.","Secure Shell (SSH) is exposed, creating a certificate-validation risk.","Trivial File Transfer Protocol (TFTP) is exposed, creating a zone-transfer risk.","Lightweight Directory Access Protocol (LDAP) is exposed, creating a mail-relay risk."],"correctIndex":0,"explanation":"TCP 23 is Telnet. It is commonly flagged because remote administration over Telnet can expose credentials and session contents. SSH on TCP 22 is the safer replacement.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":485,"question":"A web app cannot resolve internal hostnames. Firewall logs show blocked outbound UDP 53 from the app subnet to the internal resolver. Which protocol is being blocked?","options":["Domain Name System (DNS) name resolution.","Dynamic Host Configuration Protocol (DHCP) address leasing.","Network Time Protocol (NTP) time synchronization.","Lightweight Directory Access Protocol (LDAP) directory queries."],"correctIndex":0,"explanation":"Domain Name System (DNS) typically uses UDP 53 for standard queries and TCP 53 for zone transfers or larger responses. Blocking DNS can break hostname resolution even when the destination service is healthy.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":486,"question":"A Security Information and Event Management (SIEM) alert shows unusually large outbound TCP 53 sessions to an external host. What should the analyst suspect first?","options":["Possible Domain Name System (DNS) tunneling or unauthorized zone-transfer-like behavior.","Normal Dynamic Host Configuration Protocol (DHCP) lease renewal traffic.","Expected Network Time Protocol (NTP) clock correction traffic.","Routine Simple Mail Transfer Protocol (SMTP) mail submission traffic."],"correctIndex":0,"explanation":"DNS typically uses UDP 53, but TCP 53 can be normal for large responses and zone transfers. Large or persistent external TCP 53 flows can also be suspicious and deserve investigation for tunneling or exfiltration.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":487,"question":"A mail server must send mail between mail transfer agents. Which default port and protocol should be allowed?","options":["TCP 25 for Simple Mail Transfer Protocol (SMTP).","TCP 110 for Post Office Protocol version 3 (POP3).","TCP 143 for Internet Message Access Protocol (IMAP).","TCP 587 for Lightweight Directory Access Protocol (LDAP)."],"correctIndex":0,"explanation":"Simple Mail Transfer Protocol (SMTP) uses TCP 25 for server-to-server mail transfer. TCP 587 is commonly used for authenticated mail submission by clients, not LDAP.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":488,"question":"A company wants users to retrieve mailbox contents securely while leaving messages synchronized on the server. Which protocol and port best fits?","options":["Internet Message Access Protocol over Secure Sockets Layer/Transport Layer Security (IMAPS) on TCP 993.","Post Office Protocol version 3 (POP3) on TCP 110.","Simple Mail Transfer Protocol (SMTP) on TCP 25.","Simple Network Management Protocol version 3 (SNMPv3) on UDP 161."],"correctIndex":0,"explanation":"Internet Message Access Protocol (IMAP) keeps mail synchronized with the server. The secure default is IMAPS on TCP 993. POP3S on TCP 995 is secure too, but POP3 is more download-oriented and less ideal for multi-device synchronization.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":489,"question":"A firewall administrator sees authentication requests from a Virtual Private Network (VPN) appliance to a server on UDP 1812. Which service is most likely in use?","options":["Remote Authentication Dial-In User Service (RADIUS) authentication.","Terminal Access Controller Access-Control System Plus (TACACS+) authentication.","Kerberos authentication service ticketing.","Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS) directory binding."],"correctIndex":0,"explanation":"RADIUS commonly uses UDP 1812 for authentication and UDP 1813 for accounting. TACACS+ uses TCP 49. Kerberos uses TCP/UDP 88. LDAPS uses TCP 636.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":490,"question":"A network team wants centralized device administration with separate authentication, authorization, and accounting controls over TCP 49. Which protocol should be configured?","options":["Terminal Access Controller Access-Control System Plus (TACACS+).","Remote Authentication Dial-In User Service (RADIUS).","Kerberos.","Network Basic Input/Output System (NetBIOS)."],"correctIndex":0,"explanation":"TACACS+ uses TCP 49 and is common for network-device administration. It separates authentication, authorization, and accounting functions, which is useful for administrative command control.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":491,"question":"A vulnerability scan flags cleartext directory binds on TCP 389. Which secure replacement should the administrator prefer?","options":["Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS) on TCP 636.","Kerberos over TCP/UDP 88.","Server Message Block (SMB) over TCP 445.","Remote Authentication Dial-In User Service (RADIUS) over UDP 1812."],"correctIndex":0,"explanation":"LDAP commonly uses TCP 389. LDAPS uses TCP 636 to protect directory traffic with encryption. Kerberos and RADIUS are authentication-related, but they are not direct LDAP replacements.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":492,"question":"An incident responder sees suspicious authentication attempts to TCP 445 across many Windows servers. Which protocol is most relevant?","options":["Server Message Block (SMB) for file sharing and administrative access.","Simple Network Management Protocol (SNMP) for device telemetry.","Secure Shell (SSH) for encrypted terminal sessions.","Internet Message Access Protocol (IMAP) for mailbox synchronization."],"correctIndex":0,"explanation":"TCP 445 is Server Message Block (SMB). It is heavily monitored because it is tied to Windows file sharing, administrative shares, and many lateral movement techniques.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":493,"question":"A scan finds UDP 137, UDP 138, and TCP 139 exposed from a legacy Windows subnet. Which protocol family should be investigated?","options":["Network Basic Input/Output System (NetBIOS).","Border Gateway Protocol (BGP).","Simple Object Access Protocol (SOAP).","Internet Key Exchange (IKE)."],"correctIndex":0,"explanation":"NetBIOS commonly uses UDP 137 for name service, UDP 138 for datagram service, and TCP 139 for session service. Modern Windows file sharing commonly relies on SMB over TCP 445 instead.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":494,"question":"A Security Operations Center (SOC) notices event timestamps differ by several minutes across servers, weakening timeline analysis. Which protocol should be checked first?","options":["Network Time Protocol (NTP) on UDP 123.","Domain Name System (DNS) on UDP 53.","Simple Network Management Protocol (SNMP) on UDP 161.","Kerberos on TCP/UDP 88."],"correctIndex":0,"explanation":"NTP uses UDP 123 and is critical for consistent logs, Kerberos ticketing, and incident timelines. Kerberos can also be affected by time drift, but NTP is the service used to synchronize clocks.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":495,"question":"A public web application is available over TCP 80 and TCP 443. Which port should be preferred for user traffic?","options":["TCP 443 using Hypertext Transfer Protocol Secure (HTTPS).","TCP 80 using Hypertext Transfer Protocol (HTTP).","TCP 8080 using Simple Mail Transfer Protocol (SMTP).","TCP 8443 using Dynamic Host Configuration Protocol (DHCP)."],"correctIndex":0,"explanation":"HTTPS uses TCP 443 and protects web traffic with Transport Layer Security (TLS). HTTP on TCP 80 is cleartext and should usually redirect to HTTPS for user-facing applications.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":496,"question":"A scanner finds an internal admin console listening on TCP 8080. What is the best interpretation?","options":["It may be an alternate web service or proxy port that still needs access control and Transport Layer Security (TLS) review.","It is always Secure Shell (SSH), so password authentication should be disabled.","It is always Kerberos, so time synchronization is the main exposure.","It is always Domain Name System (DNS), so recursion should be disabled."],"correctIndex":0,"explanation":"TCP 8080 is commonly used for alternate HTTP services, proxies, or admin consoles. Nonstandard ports do not make services safe; they still need authentication, authorization, encryption, and exposure review.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":497,"question":"A network monitoring platform polls routers over UDP 161 and receives trap messages on UDP 162. Which protocol is in use?","options":["Simple Network Management Protocol (SNMP).","Simple Mail Transfer Protocol (SMTP).","Server Message Block (SMB).","Secure File Transfer Protocol (SFTP)."],"correctIndex":0,"explanation":"SNMP commonly uses UDP 161 for polling and UDP 162 for traps. SNMP version 3 is preferred because it supports authentication and encryption.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":498,"question":"A scan identifies Simple Network Management Protocol version 2 community strings in use. Which remediation is best?","options":["Migrate to Simple Network Management Protocol version 3 (SNMPv3) with authentication and encryption.","Replace it with Trivial File Transfer Protocol (TFTP) because both use User Datagram Protocol (UDP).","Move polling from UDP 161 to TCP 25 to protect management traffic.","Disable Network Time Protocol (NTP) because time sync exposes community strings."],"correctIndex":0,"explanation":"SNMPv1 and SNMPv2c rely on community strings and are weaker than SNMPv3. SNMPv3 can provide message integrity, authentication, and confidentiality.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":499,"question":"A device downloads boot configuration files from UDP 69 without authentication. Which protocol is this?","options":["Trivial File Transfer Protocol (TFTP).","File Transfer Protocol (FTP) control channel.","Secure Copy Protocol (SCP).","Network File System (NFS)."],"correctIndex":0,"explanation":"TFTP uses UDP 69 and is simple, unauthenticated, and commonly seen in network boot or device configuration workflows. It should be tightly restricted.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":500,"question":"A data-loss review finds credentials sent over TCP 21 before files are transferred over a separate data connection. Which protocol caused the concern?","options":["File Transfer Protocol (FTP).","Secure File Transfer Protocol (SFTP).","Hypertext Transfer Protocol Secure (HTTPS).","Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS)."],"correctIndex":0,"explanation":"FTP uses TCP 21 for control and TCP 20 for active-mode data. It is not encrypted by default. SFTP rides over SSH on TCP 22 and is usually preferred.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":501,"question":"An external scan shows TCP 3389 open to the internet on a Windows host. Which service should be restricted immediately?","options":["Remote Desktop Protocol (RDP).","Kerberos.","Server Message Block (SMB).","Post Office Protocol version 3 Secure (POP3S)."],"correctIndex":0,"explanation":"RDP uses TCP 3389. Internet-exposed RDP is commonly targeted for brute force, credential stuffing, exploitation, and ransomware intrusion paths.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":502,"question":"A firewall change for an Internet Protocol Security (IPsec) VPN must allow Internet Key Exchange and Network Address Translation Traversal. Which ports should be included?","options":["UDP 500 and UDP 4500.","TCP 389 and TCP 636.","UDP 67 and UDP 68.","TCP 20 and TCP 21."],"correctIndex":0,"explanation":"IPsec commonly uses Internet Key Exchange (IKE) on UDP 500 and NAT Traversal on UDP 4500. ESP is protocol 50, but it is not a TCP or UDP port.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":503,"question":"A legacy remote-access profile uses TCP 1723 and Generic Routing Encapsulation (GRE). Which protocol is most likely configured?","options":["Point-to-Point Tunneling Protocol (PPTP).","Layer 2 Tunneling Protocol (L2TP).","Internet Key Exchange version 2 (IKEv2).","Secure Shell (SSH) tunneling."],"correctIndex":0,"explanation":"PPTP uses TCP 1723 and GRE. It is considered weak by modern standards and should generally be replaced with stronger VPN technologies.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":504,"question":"New endpoints on a subnet cannot obtain addresses. Packet captures show blocked broadcasts involving UDP 67 and UDP 68. Which process is failing?","options":["Dynamic Host Configuration Protocol (DHCP) leasing.","Domain Name System (DNS) recursive lookup.","Network Time Protocol (NTP) synchronization.","Kerberos ticket granting."],"correctIndex":0,"explanation":"DHCP commonly uses UDP 67 for the server and UDP 68 for the client. Blocking this exchange can prevent clients from receiving IP address configuration.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":505,"question":"An Active Directory environment has authentication failures after a firewall update. Which port should be checked for Kerberos authentication?","options":["TCP/UDP 88.","TCP 49.","UDP 1813.","TCP 995."],"correctIndex":0,"explanation":"Kerberos uses TCP and UDP 88. It is central to many Active Directory authentication flows and is sensitive to time synchronization issues.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":506,"question":"A Security Operations Center (SOC) wants network devices to forward logs confidentially instead of using default UDP 514. Which destination is the better choice?","options":["TCP 6514 for syslog over Transport Layer Security (TLS).","UDP 69 for syslog over Trivial File Transfer Protocol (TFTP).","TCP 23 for syslog over Telnet.","UDP 123 for syslog over Network Time Protocol (NTP)."],"correctIndex":0,"explanation":"Traditional syslog commonly uses UDP 514. Syslog over TLS commonly uses TCP 6514 and provides confidentiality and integrity protections for log transport.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":507,"question":"A cloud security review finds TCP 3306 open to the internet on a server that stores customer records. Which service is most likely exposed?","options":["MySQL database service.","Microsoft SQL Server database service.","PostgreSQL database service.","MongoDB database service."],"correctIndex":0,"explanation":"MySQL commonly uses TCP 3306. Database services should rarely be internet-exposed; use private networking, access controls, strong authentication, and logging.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":508,"question":"A vulnerability report lists TCP 1433 open on a production database host. Which technology is most likely being reported?","options":["Microsoft SQL Server.","MySQL.","PostgreSQL.","Lightweight Directory Access Protocol (LDAP)."],"correctIndex":0,"explanation":"Microsoft SQL Server commonly uses TCP 1433. MySQL commonly uses TCP 3306, and PostgreSQL commonly uses TCP 5432.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":509,"question":"An analyst detects an unauthorized remote-control tool listening on TCP 5900. Which protocol is most likely involved?","options":["Virtual Network Computing (VNC).","Remote Desktop Protocol (RDP).","Secure Shell (SSH).","Server Message Block (SMB)."],"correctIndex":0,"explanation":"VNC commonly uses TCP 5900. Like RDP, it should be tightly controlled and monitored because it enables interactive remote access.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":510,"question":"A phone system uses TCP/UDP 5060 for call setup and TCP 5061 when protected by Transport Layer Security (TLS). Which protocol is this?","options":["Session Initiation Protocol (SIP).","Simple Network Management Protocol (SNMP).","Server Message Block (SMB).","Secure Copy Protocol (SCP)."],"correctIndex":0,"explanation":"SIP commonly uses 5060 for signaling and 5061 for SIP over TLS. It is used for Voice over Internet Protocol (VoIP) call setup, not for media transport itself.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":511,"question":"An edge router unexpectedly begins session attempts to external peers on TCP 179. Which protocol should the network security team investigate?","options":["Border Gateway Protocol (BGP).","Dynamic Host Configuration Protocol (DHCP).","Domain Name System (DNS).","Lightweight Directory Access Protocol (LDAP)."],"correctIndex":0,"explanation":"BGP uses TCP 179 and is used for routing between autonomous systems. Unexpected BGP peering attempts can indicate misconfiguration or routing security concerns.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":512,"question":"A hardened Windows management subnet allows TCP 5986 but blocks TCP 5985. What administrative protocol is likely being secured?","options":["Windows Remote Management (WinRM) over Hypertext Transfer Protocol Secure (HTTPS).","Windows Remote Management (WinRM) over Hypertext Transfer Protocol (HTTP).","Server Message Block (SMB) over Transport Layer Security (TLS).","Remote Desktop Protocol (RDP) over Secure Shell (SSH)."],"correctIndex":0,"explanation":"WinRM commonly uses TCP 5985 for HTTP and TCP 5986 for HTTPS. The secure listener should be preferred when remote management is required.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":513,"question":"A load balancer terminates Transport Layer Security (TLS) for a customer portal. Which port should be expected for standard encrypted browser traffic?","options":["TCP 443 for Hypertext Transfer Protocol Secure (HTTPS).","TCP 80 for Hypertext Transfer Protocol Secure (HTTPS).","TCP 25 for Hypertext Transfer Protocol Secure (HTTPS).","UDP 443 for Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS)."],"correctIndex":0,"explanation":"HTTPS defaults to TCP 443. Some newer protocols may use UDP 443, but the standard Security+ and CySA+ baseline answer for encrypted web traffic is HTTPS on TCP 443.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":514,"question":"A host exposes TCP 21, TCP 22, and TCP 23. The security team can keep only one remote-administration option available. Which should remain?","options":["TCP 22 because Secure Shell (SSH) supports encrypted administration and secure file transfer options.","TCP 21 because File Transfer Protocol (FTP) encrypts command and data channels by default.","TCP 23 because Telnet encrypts administrator credentials by default.","TCP 21 because it is the only port that can transfer files securely."],"correctIndex":0,"explanation":"SSH on TCP 22 is the best administrative choice among these. FTP and Telnet are cleartext by default and should be replaced or tightly restricted.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"}];
